INSERT INTO `attraction` VALUES (4387, '天山天池', '瑶池仙境', '天山天池古称“瑶池”，是天山博格达峰北侧的一个半月形湖泊，以高山湖泊为中心的自然风景区，湖水清澈，四周群山环抱。', 1, 1682, '新疆昌吉州阜康市博格达峰下', 43.88000000, 88.15000000, 'https://dimg04.c-ctrip.com/images/100f0z000000mjejhB1BB.jpg', '[\"https://dimg04.c-ctrip.com/images/100f0z000000mjejhB1BB.jpg\", \"https://dimg04.c-ctrip.com/images/100f0z000000mjejhB1BB.jpg\", \"https://dimg04.c-ctrip.com/images/100f0z000000mjejhB1BB.jpg\", \"https://dimg04.c-ctrip.com/images/100f0z000000mjejhB1BB.jpg\"]', 4.80, 12500, 568003, 89000, 98, 12, 125.00, '门票包含景区区间车，学生半价，65岁以上老人免票', '09:00-19:00（夏季）；10:00-17:00（冬季）', '夏季（6-8月）、秋季（9-10月）', '天山天池是古代冰川泥石流堵塞河道形成的高山湖泊，历史上是西王母娘娘的瑶池，具有深厚的神话传说底蕴。', '山区气温较低，建议携带保暖衣物；景区内部分路段台阶较多，注意行走安全。', 'http://www.ts天池.com', '[\"手抓肉\",\"烤包子\",\"大盘鸡\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4388, '新疆国际大巴扎', '西域风情地标', '世界规模最大的大巴扎（集市），集伊斯兰文化、建筑、民族商贸、娱乐、餐饮于一体，是乌鲁木齐的城市名片。', 2, 1682, '新疆乌鲁木齐市天山区解放南路8号', 43.79000000, 87.62000000, 'https://dimg04.c-ctrip.com/images/10011f000001h37tn1715.jpg', '[\"https://dimg04.c-ctrip.com/images/10011f000001h37tn1715.jpg\", \"https://dimg04.c-ctrip.com/images/10011f000001h37tn1715.jpg\", \"https://dimg04.c-ctrip.com/images/10011f000001h37tn1715.jpg\", \"https://dimg04.c-ctrip.com/images/10011f000001h37tn1715.jpg\"]', 4.70, 9800, 785002, 76000, 95, 180, 0.00, '免费开放，内部消费自理', '10:00-22:00', '全年适宜，夏季夜晚更热闹', '新疆国际大巴扎建于2003年，融合了中亚、西亚的建筑风格，是丝绸之路文化的现代传承。', '人流量较大，注意保管个人财物；尊重少数民族宗教信仰和风俗习惯。', 'http://www.xjdbz.com', '[\"烤羊肉串\",\"馕坑肉\",\"手抓饭\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4389, '红山公园', '城市观景台', '红山公园因山体呈红褐色而得名，是乌鲁木齐的象征，可俯瞰整个城市风貌，拥有红山塔等历史建筑。', 1, 1682, '新疆乌鲁木齐市水磨沟区红山路北一巷40号', 43.80000000, 87.63000000, 'https://dimg04.c-ctrip.com/images/0106j120009zdcsde209F.jpg', '[\"https://dimg04.c-ctrip.com/images/0106j120009zdcsde209F.jpg\", \"https://dimg04.c-ctrip.com/images/0106j120009zdcsde209F.jpg\", \"https://dimg04.c-ctrip.com/images/0106j120009zdcsde209F.jpg\", \"https://dimg04.c-ctrip.com/images/0106j120009zdcsde209F.jpg\"]', 4.50, 6500, 320000, 45000, 85, 120, 0.00, '免费开放', '08:00-22:00', '春季（4-5月）、秋季（9-10月）', '红山塔建于清代乾隆年间，是为“镇山锁水”而建，具有200多年历史。', '登山台阶较多，建议穿舒适的鞋子；夏季注意防晒。', '', '[\"凉皮子\",\"黄面\",\"油塔子\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4390, '水磨沟公园', '城市休闲氧吧', '以水磨沟河为核心的城市公园，泉水清澈，植被茂密，是乌鲁木齐市民休闲度假的好去处。', 1, 1682, '新疆乌鲁木齐市水磨沟区水磨沟路472号', 43.82000000, 87.68000000, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://ts1.tc.mm.bing.net/th/id/R-C.eef2e7b7029fd493d0b39097440a19a8?rik=mOHjc9ZRwMFDOA&riu=http%3a%2f%2fimg.pconline.com.cn%2fimages%2fupload%2fupc%2ftx%2fitbbs%2f1510%2f15%2fc42%2f13996301_1444896934438.jpg&ehk=RfMvxJhfdkTazTovDfUtWqHi2mSrNFSdTP8pZyPReFM%3d&risl=&pid=ImgRaw&r=0\",\"https://www.ts.cn/xwzx/shxw/202212/W020221205807014532844.jpeg\"]', 4.60, 5200, 280000, 38000, 80, 150, 0.00, '免费开放', '08:00-20:00', '夏季（6-8月）、秋季（9-10月）', '水磨沟历史上是乌鲁木齐的水磨坊聚集地，清代就已是著名的游览胜地。', '公园内水域较多，注意看护老人和小孩；禁止在非指定区域戏水。', '', '[\"新疆拌面\",\"烤包子\",\"酸奶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:22:13');
INSERT INTO `attraction` VALUES (4391, '南山风景区', '草原避暑胜地', '乌鲁木齐南部的草原风景区，包含西白杨沟、东白杨沟等景点，可体验草原风光、骑马等活动。', 1, 1682, '新疆乌鲁木齐市乌鲁木齐县南山牧场', 43.48000000, 87.45000000, 'https://dimg04.c-ctrip.com/images/1me1p12000dv2p7raF8BD.jpg', '[\"https://dimg04.c-ctrip.com/images/1me1p12000dv2p7raF8BD.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4s12000c6nocv93B5E.jpg\", \"https://dimg04.c-ctrip.com/images/0105112000h15ynzjC22E.jpg\", \"https://dimg04.c-ctrip.com/images/0102b12000h15zn5aD55C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2o12000icl0t1l0387.jpg\", \"https://dimg04.c-ctrip.com/images/27c3j12000na9jmxj3516_R_180_180.jpg\"]', 4.75, 8600, 450000, 68000, 90, 300, 45.00, '门票含景区进入费，骑马等项目单独收费', '09:00-18:00', '夏季（6-8月）', '南山风景区是古丝绸之路的必经之地，也是哈萨克族牧民的传统游牧区。', '山区天气多变，建议携带雨具和保暖衣物；骑马需遵守景区安全规定。', '', '[\"哈萨克族手抓肉\",\"马奶酒\",\"包尔萨克\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4392, '新疆博物馆', '西域历史宝库', '收藏了大量新疆历史文物，包括干尸、纺织品、青铜器等，展现了新疆多民族的历史文化。', 2, 1682, '新疆乌鲁木齐市沙依巴克区西北路581号', 43.79000000, 87.58000000, 'https://dimg04.c-ctrip.com/images/0100k12000carhfpiFEA6.jpg', '[\"https://dimg04.c-ctrip.com/images/0100k12000carhfpiFEA6.jpg\", \"https://dimg04.c-ctrip.com/images/0100l12000cargqku53B3.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4q12000icygb8q10CF.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6i12000dfxtd5519D9.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5m12000rp3e3ws0093.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1112000cj0yn4r85A4.jpg\"]', 4.85, 7800, 360000, 52000, 88, 180, 0.00, '免费开放，需提前预约', '10:00-18:00（周一闭馆）', '全年适宜', '新疆博物馆成立于1953年，是新疆最大的综合性博物馆，馆藏文物超过6万件。', '展厅内禁止触摸文物；禁止使用闪光灯拍照；遵守场馆参观秩序。', 'http://www.xjmuseum.com', '[\"馕\",\"烤包子\",\"新疆奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4393, '达坂城古镇', '丝路古镇', '以“达坂城的姑娘”闻名，重现了古代丝路驿站的风貌，可体验民俗文化。', 2, 1682, '新疆乌鲁木齐市达坂城区达坂城镇', 43.32000000, 88.35000000, 'https://dimg04.c-ctrip.com/images/100k1f000001guem856AF.jpg', '[\"https://dimg04.c-ctrip.com/images/100k1f000001guem856AF.jpg\", \"https://dimg04.c-ctrip.com/images/100k1f000001guem856AF.jpg\", \"https://dimg04.c-ctrip.com/images/100k1f000001guem856AF.jpg\", \"https://dimg04.c-ctrip.com/images/100k1f000001guem856AF.jpg\"]', 4.40, 3800, 180000, 25000, 75, 120, 30.00, '门票含景区参观费，民俗体验项目单独收费', '09:00-18:00', '春季（4-5月）、秋季（9-10月）', '达坂城是古代丝绸之路的重要驿站，历史上是兵家必争之地，也是多民族融合的重要区域。', '景区内风沙较大，建议佩戴防晒帽和口罩；遵守景区民俗体验的相关规定。', '', '[\"达坂城凉皮\",\"烤羊肉串\",\"馕\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4394, '盐湖景区', '中国死海', '以盐湖漂浮、盐疗为特色的景区，湖水含盐量高，可体验“死海”漂浮的乐趣。', 3, 1682, '新疆乌鲁木齐市达坂城区盐湖街道', 43.28000000, 88.18000000, 'https://dimg04.c-ctrip.com/images/3505170000010viu477A6.jpg', '[\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6.jpg\", \"https://dimg04.c-ctrip.com/images/3505170000010viu477A6.jpg\", \"https://dimg04.c-ctrip.com/images/3505170000010viu477A6.jpg\", \"https://dimg04.c-ctrip.com/images/3505170000010viu477A6.jpg\"]', 4.55, 4500, 220000, 32000, 82, 180, 80.00, '门票含漂浮体验，盐疗项目单独收费', '10:00-19:00（夏季）；10:00-17:00（冬季）', '夏季（6-8月）', '盐湖已有数百年的开采历史，是新疆重要的盐资源产地，近年开发为旅游景区。', '漂浮时注意保护眼睛和口腔，避免盐水进入；患有高血压、心脏病等疾病者需谨慎体验。', '', '[\"新疆大盘鸡\",\"手抓饭\",\"酸奶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4395, '喀什古城', '活着的千年古城', '世界上现存规模最大的生土建筑群之一，保留了浓郁的维吾尔族风情，是国家5A级景区。', 2, 1683, '新疆喀什地区喀什市解放北路喀什古城景区', 39.47000000, 75.98000000, 'https://dimg04.c-ctrip.com/images/0104m12000o9o755010E2_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104y1200086wi2i1FC0E_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0101g120009egz5pd5DDE_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010281200086v4y395BA7_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0100n1200086v4y4rC5C6_W_1920_1080.jpg_.webp\"]', 4.90, 15800, 890006, 120000, 99, 360, 0.00, '免费开放，部分特色街区体验项目收费', '全天开放（核心区09:00-23:00）', '春季（4-5月）、秋季（9-10月）', '喀什古城已有2000多年历史，是古丝绸之路重镇，也是维吾尔族文化的核心发源地之一。', '古城内街巷复杂，建议跟随导览或使用导航；尊重当地居民的生活习惯，禁止随意进入民宅。', 'http://www.kashigucheng.com', '[\"烤包子\",\"馕坑肉\",\"鸽子汤\",\"木卡姆冰淇淋\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4396, '艾提尕尔清真寺', '西域第一清真寺', '中国规模最大的清真寺之一，是喀什维吾尔族穆斯林的主要宗教活动场所。', 2, 1683, '新疆喀什地区喀什市艾提尕尔广场西侧', 39.47000000, 75.97000000, 'https://dimg04.c-ctrip.com/images/0105712000lxl69bcDF9B_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0105812000lxl6qb78A9F_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0ww4i120009laucj04758_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0ww5z120009laujp59439_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/3C/4C/wKgBEFuCkDiAUtXpAAV7fVUJQ8s23.jpeg\"]', 4.85, 11200, 650000, 85000, 96, 120, 0.00, '免费开放，周五主麻日需注意宗教活动秩序', '08:00-20:00（宗教活动期间除外）', '全年适宜（避开宗教活动高峰）', '艾提尕尔清真寺始建于1442年，历经多次扩建，是新疆伊斯兰教的重要圣地。', '进入清真寺需穿戴整齐，禁止穿短裤、短裙；禁止在寺内大声喧哗、拍照（需征得同意）。', '', '[\"馕\",\"烤羊肉串\",\"新疆奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4397, '帕米尔高原', '世界屋脊', '中国最西端的高原，与塔吉克斯坦、阿富汗等国接壤，拥有慕士塔格峰、喀拉库勒湖等绝美风光。', 1, 1683, '新疆喀什地区塔什库尔干塔吉克自治县境内', 38.50000000, 75.20000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0.jpg', '[\"https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0.jpg\", \"https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0.jpg\", \"https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0.jpg\", \"https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0.jpg\"]', 4.95, 9800, 720000, 95000, 98, 480, 150.00, '门票含景区通行费，自驾需缴纳环保费', '全天开放（建议白天通行）', '夏季（6-8月）', '帕米尔高原是古丝绸之路的重要通道，也是塔吉克族的主要聚居区，拥有深厚的高原文化底蕴。', '高原海拔较高（平均4000米以上），注意预防高原反应；天气寒冷，需携带保暖衣物；部分区域需办理边防证。', '', '[\"塔吉克族手抓肉\",\"馕\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4398, '喀拉库勒湖', '高原明珠', '帕米尔高原上的高山湖泊，湖水颜色随天气变化，背靠慕士塔格峰，风光绝美。', 1, 1683, '新疆喀什地区阿克陶县布伦口乡', 38.30000000, 75.25000000, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\"]', 4.90, 8500, 580000, 78000, 97, 240, 50.00, '门票含景区参观费，骑马、露营单独收费', '08:00-20:00', '夏季（6-8月）', '喀拉库勒湖意为“黑湖”，是冰川融水形成的湖泊，历史上是玄奘西天取经的必经之地。', '湖边风大，注意保暖；禁止向湖中丢弃垃圾；露营需遵守景区规定。', '', '[\"高原羊肉汤\",\"馕\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4399, '香妃园', '西域风情园林', '纪念乾隆皇帝的香妃而建，融合了维吾尔族建筑和园林风格，展示了香妃的生平故事。', 2, 1683, '新疆喀什地区喀什市浩罕乡艾孜热特村', 39.45000000, 75.90000000, 'https://p1-q.mafengwo.net/s11/M00/9F/C1/wKgBEFtyhzKAPqw7AA32RCfq1CU19.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/98/9C/wKgED1uxFkyAEco7ADi62m7at0o60.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/91/FC/wKgED1vPNT2AcIyVAA-SbE-6yTc69.jpeg\",\"https://dimg04.c-ctrip.com/images/0104t120008npdguk479B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0103y12000e87chma0A7E_W_1920_1080.jpg_.webp\"]', 4.70, 7800, 420000, 65000, 92, 180, 40.00, '门票含景区参观费，演出项目单独收费', '09:00-20:00', '春季（4-5月）、秋季（9-10月）', '香妃园始建于1640年，是香妃的家族墓地，也是新疆规模最大的伊斯兰教陵墓群之一。', '景区内有演出活动，建议提前了解场次；尊重宗教习俗，禁止在陵墓区大声喧哗。', 'http://www.xiangfeiyuan.com', '[\"烤包子\",\"抓饭\",\"木卡姆糕点\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4400, '白沙湖（喀什）', '沙漠中的翡翠', '帕米尔高原上的白沙山和白沙湖，湖水清澈，白沙山洁白，构成绝美的自然画卷。', 1, 1683, '新疆喀什地区阿克陶县布伦口乡白沙湖景区', 38.40000000, 75.15000000, 'https://weng.mafengwo.net/img/b7/78/3b961d3646f1ed55b941819bd0abe8e3.jpeg', '[\"https://p1-q.mafengwo.net/s19/M00/13/B2/CoNGXmGvi1pyIgayAAtML-ZGbG4.jpg\",\"https://note.mafengwo.net/img/c9/17/dc329c5b47dfc3ca1a7e7adddb01b8a3.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/3F/32/wKgED1u8Yr2AA8CxAAWQ5dQC-4890.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/3E/3A/wKgED1u8Yr2AA8CxAAWQ5dQC-4890.jpeg\"]', 4.88, 7200, 450000, 72000, 94, 180, 30.00, '免费开放，停车费10元', '全天开放', '夏季（6-8月）、秋季（9-10月）', '白沙湖是因山体风化形成的白沙山和冰川融水形成的湖泊，是帕米尔高原的标志性景观之一。', '湖边无遮挡，注意防晒；风沙较大，建议佩戴墨镜和口罩；禁止攀爬白沙山。', '', '[\"烤羊肉串\",\"馕\",\"酸奶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4401, '塔什库尔干石头城', '千年石头城堡', '古丝绸之路的重要遗址，是古代西域三十六国之一的蒲犁国都城，保留了大量历史遗迹。', 2, 1683, '新疆喀什地区塔什库尔干塔吉克自治县县城北侧', 37.78000000, 75.22000000, 'https://p1-q.mafengwo.net/s16/M00/A7/C9/CoUBUmFddBuADZq_AAkbUv5aOf8773.jpg', '[\"https://note.mafengwo.net/img/e9/c0/b79a077a46ecd522790669752d9d2559.jpeg\",\"https://note.mafengwo.net/img/79/91/4bc5015d1dd32a7bfe8ed09a36c9bfc9.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 4.80, 6500, 380000, 58000, 91, 150, 20.00, '门票含景区参观费，讲解服务单独收费', '09:00-19:00', '春季（4-5月）、秋季（9-10月）', '石头城始建于汉代，历经魏晋、隋唐等朝代的修缮，是中国海拔最高的古城遗址之一。', '遗址内多碎石和陡坡，注意行走安全；高原地区注意保暖和防高原反应。', '', '[\"塔吉克族馕\",\"手抓肉\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4402, '金湖杨景区', '沙漠胡杨风光', '拥有大面积的胡杨林，秋季金黄一片，是喀什地区著名的自然景观。', 1, 1683, '新疆喀什地区泽普县奎依巴格镇', 38.20000000, 77.25000000, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\"]', 4.75, 5800, 320000, 48000, 89, 240, 40.00, '门票含景区参观费，区间车单独收费', '08:00-20:00', '秋季（10-11月）', '金湖杨景区的胡杨林已有上千年历史，是新疆南部最大的胡杨林景区之一。', '秋季游客较多，注意错峰出行；景区内蚊虫较多，建议携带驱蚊用品。', '', '[\"烤全羊\",\"抓饭\",\"烤包子\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4403, '慕士塔格峰', '冰山之父', '帕米尔高原的标志性山峰，海拔7546米，是登山爱好者的圣地，也是绝佳的观景地。', 1, 1683, '新疆喀什地区阿克陶县与塔什库尔干县交界处', 38.10000000, 75.10000000, 'https://p1-q.mafengwo.net/s13/M00/6C/28/wKgEaV0DLPaAfSMNAAiDk8Xc_ww87.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/6C/28/wKgEaV0DLPaAfSMNAAiDk8Xc_ww87.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/6C/28/wKgEaV0DLPeAdP7DAAcOqGk0Bsc97.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/6C/28/wKgEaV0DLPeAdP7DAAcOqGk0Bsc97.jpeg\",\"https://dimg04.c-ctrip.com/images/100w0g0000019et6yCC86_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0e0000019esyd0C72_W_1920_1080.jpg_.webp\"]', 4.92, 8200, 560000, 88000, 98, 360, 0.00, '免费开放，登山需办理专业登山许可证', '全天开放（建议白天观景）', '夏季（6-8月）', '慕士塔格峰是维吾尔族心中的神山，“慕士塔格”意为“冰山之父”，拥有丰富的冰川资源。', '登山需专业装备和向导，禁止无资质擅自攀登；山脚下气温低，需携带保暖衣物；预防高原反应。', '', '[\"高原羊肉\",\"馕\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4404, '高台民居', '空中村落', '喀什古城内的特色民居建筑群，依坡而建，房屋层层叠叠，是维吾尔族建筑的活化石。', 2, 1683, '新疆喀什地区喀什市老城东南端', 39.47000000, 75.98000000, 'https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\"]', 4.83, 7500, 400000, 62000, 93, 180, 0.00, '免费开放（部分区域修缮中）', '09:00-20:00', '全年适宜', '高台民居已有600多年历史，建筑多为土木结构，是喀什非物质文化遗产的重要载体。', '部分建筑年久失修，禁止进入未开放区域；尊重居民生活，禁止随意拍照。', '', '[\"烤羊肉串\",\"馕坑肉\",\"鸽子汤\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:45:54');
INSERT INTO `attraction` VALUES (4405, '那拉提草原', '空中草原', '国家5A级景区，世界四大草原之一的亚高山草甸植物区，以草原风光和哈萨克族风情为特色。', 1, 1684, '新疆伊犁哈萨克自治州新源县那拉提镇', 43.30000000, 84.15000000, 'https://dimg04.c-ctrip.com/images/0102p120008wtrwhb5133_C_1180_462.jpg', '[\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\"]', 4.90, 16500, 950002, 130000, 99, 480, 95.00, '门票含景区参观费，区间车分线路收费', '08:00-20:00', '夏季（6-8月）、秋季（9-10月）', '那拉提草原是古丝绸之路北道的必经之地，也是哈萨克族的传统游牧区，“那拉提”意为“最先见到太阳的地方”。', '草原天气多变，建议携带雨具和保暖衣物；骑马需遵守景区规定，注意安全。', 'http://www.narat.com', '[\"哈萨克族手抓肉\",\"马奶酒\",\"包尔萨克\",\"烤全羊\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:12:45');
INSERT INTO `attraction` VALUES (4406, '喀拉峻草原', '人体草原', '以“立体草原”和“人体草原”景观闻名，是世界自然遗产，拥有独特的高山草甸风光。', 1, 1684, '新疆伊犁哈萨克自治州特克斯县喀拉峻镇', 42.70000000, 81.60000000, 'https://dimg04.c-ctrip.com/images/0106v12000fajgkk311F7_W_1920_1080.jpg_.webp?_fr=wc', '[\"https://dimg04.c-ctrip.com/images/0102e120008a6v60y242A_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/100n0n000000e0qn09A2B_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0102v120008a6gqul35AB_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0106u120008a6utd98A72_W_1920_1080.jpg_.webp?_fr=wc\"]', 4.88, 12800, 780001, 98000, 97, 480, 80.00, '门票含景区参观费，区间车、索道单独收费', '08:00-20:00', '夏季（6-8月）', '喀拉峻草原是哈萨克族的传统游牧区，2013年被列入世界自然遗产名录，保留了原始的草原生态。', '景区面积大，建议乘坐区间车游览；部分区域无手机信号，注意结伴而行；防晒和保暖需兼顾。', 'http://www.kalajun.com', '[\"手抓肉\",\"烤包子\",\"哈萨克族奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:24:35');
INSERT INTO `attraction` VALUES (4407, '赛里木湖', '大西洋最后一滴眼泪', '新疆海拔最高、面积最大的高山湖泊，湖水清澈见底，环湖风光绝美。', 1, 1684, '新疆伊犁哈萨克自治州博乐市境内', 44.50000000, 81.20000000, 'https://dimg04.c-ctrip.com/images/0104112000a2cvs0dB260.jpg', '[\"https://dimg04.c-ctrip.com/images/0104112000a2cvs0dB260.jpg\", \"https://dimg04.c-ctrip.com/images/0104112000a2cvs0dB260.jpg\", \"https://dimg04.c-ctrip.com/images/0104112000a2cvs0dB260.jpg\", \"https://dimg04.c-ctrip.com/images/0104112000a2cvs0dB260.jpg\"]', 4.95, 18200, 1200001, 150000, 99, 360, 144.00, '门票含景区参观费，自驾车需缴纳环湖费', '全天开放（建议08:00-22:00游览）', '夏季（6-8月）、秋季（9-10月）', '赛里木湖是古丝绸之路北道的重要节点，湖水无任何污染，是新疆著名的净海。', '湖边风大，注意保暖；禁止向湖中丢弃垃圾；无人机航拍需遵守景区规定。', 'http://www.sailimu.com', '[\"冷水鱼宴\",\"烤羊肉串\",\"馕\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4408, '解忧公主薰衣草园', '中国普罗旺斯', '中国最大的薰衣草种植基地，夏季薰衣草花海盛开，是伊犁的标志性景观。', 1, 1684, '新疆伊犁哈萨克自治州霍城县清水河镇', 44.10000000, 80.80000000, 'https://dimg04.c-ctrip.com/images/01033120008gna6yh8456.jpg', '[\"https://dimg04.c-ctrip.com/images/01033120008gna6yh8456.jpg\", \"https://dimg04.c-ctrip.com/images/01033120008gna6yh8456.jpg\", \"https://dimg04.c-ctrip.com/images/01033120008gna6yh8456.jpg\", \"https://dimg04.c-ctrip.com/images/01033120008gna6yh8456.jpg\"]', 4.80, 10500, 650000, 85000, 95, 180, 35.00, '门票含景区参观费，薰衣草产品体验单独收费', '09:00-20:00', '夏季（6-7月）', '解忧公主薰衣草园以西汉解忧公主命名，是集种植、加工、旅游为一体的薰衣草主题景区。', '夏季紫外线强，注意防晒；采摘薰衣草需遵守景区规定；购买产品注意辨别真伪。', 'http://www.jieyougongzhu.com', '[\"烤包子\",\"抓饭\",\"薰衣草冰淇淋\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4409, '昭苏草原', '天马之乡', '以草原、油菜花、天马文化为特色，夏季万亩油菜花盛开，可体验赛马、赏马等活动。', 1, 1684, '新疆伊犁哈萨克自治州昭苏县境内', 43.10000000, 81.00000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\"]', 4.85, 9800, 580000, 78000, 93, 480, 0.00, '免费开放，部分景点（如夏塔）单独收费', '全天开放', '夏季（6-8月）', '昭苏草原是乌孙古国的所在地，也是中国著名的天马培育基地，拥有深厚的马文化底蕴。', '草原面积大，建议自驾或包车游览；油菜花季游客较多，注意错峰；早晚温差大，注意保暖。', '', '[\"手抓肉\",\"烤全羊\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:47:20');
INSERT INTO `attraction` VALUES (4410, '夏塔旅游区', '古道秘境', '以夏塔古道为核心，融合了雪山、冰川、森林、草原等景观，是徒步爱好者的圣地。', 1, 1684, '新疆伊犁哈萨克自治州昭苏县夏塔乡', 42.90000000, 80.80000000, 'https://dimg04.c-ctrip.com/images/100512000000roqqb19DE.jpg', '[\"https://dimg04.c-ctrip.com/images/100512000000roqqb19DE.jpg\", \"https://dimg04.c-ctrip.com/images/0105012000lien3guD73F.jpg\", \"https://dimg04.c-ctrip.com/images/0103d12000liemrp2D28F.jpg\", \"https://dimg04.c-ctrip.com/images/0104q12000lien1ag94BF.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5o12000ico04il728F.jpg\", \"https://dimg04.c-ctrip.com/images/Z80t0x000000kwzycD20A_R_180_180.jpg\"]', 4.92, 8500, 480000, 82000, 96, 360, 60.00, '门票含景区参观费，区间车、骑马单独收费', '08:00-20:00', '夏季（6-8月）', '夏塔古道是古丝绸之路的重要通道，也是玄奘西天取经的必经之路，拥有丰富的历史和自然景观。', '古道徒步需专业装备和向导，禁止擅自深入；山区天气多变，注意防雨保暖；保护野生动物，禁止捕猎。', '', '[\"烤羊肉串\",\"馕\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4411, '琼库什台', '原始村落', '保留了原始的哈萨克族村落风貌，拥有绝美的草原和森林景观，是小众秘境。', 1, 1684, '新疆伊犁哈萨克自治州特克斯县琼库什台村', 42.50000000, 81.40000000, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\"]', 4.90, 7800, 420000, 75000, 94, 480, 0.00, '免费开放，住宿和体验项目收费', '全天开放', '夏季（6-8月）、秋季（9-10月）', '琼库什台意为“大平台子”，是新疆保存最完整的哈萨克族游牧村落，2010年被列入中国历史文化名村。', '村落基础设施较简陋，建议提前准备物资；尊重哈萨克族习俗，禁止随意进入民宅；垃圾需自行带走。', '', '[\"手抓肉\",\"包尔萨克\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:47:20');
INSERT INTO `attraction` VALUES (4412, '果子沟大桥', '伊犁第一桥', '新疆第一座斜拉桥，也是果子沟的标志性景观，大桥横跨山谷，风光壮丽。', 1, 1684, '新疆伊犁哈萨克自治州霍城县果子沟景区', 44.30000000, 81.00000000, 'https://dimg04.c-ctrip.com/images/0103t12000o7r1wjuEEC2.jpg', '[\"https://dimg04.c-ctrip.com/images/0103t12000o7r1wjuEEC2.jpg\", \"https://dimg04.c-ctrip.com/images/0103t12000o7r1wjuEEC2.jpg\", \"https://dimg04.c-ctrip.com/images/0103t12000o7r1wjuEEC2.jpg\", \"https://dimg04.c-ctrip.com/images/0103t12000o7r1wjuEEC2.jpg\"]', 4.88, 9200, 550000, 80000, 95, 60, 0.00, '免费开放（观景台收费10元）', '全天开放（建议白天观景）', '全年适宜', '果子沟大桥建成于2011年，是连霍高速的重要组成部分，也是新疆的地标性建筑之一。', '观景台拍照注意安全，禁止翻越护栏；大桥为交通要道，禁止停留拍照；遵守交通规则。', '', '[\"烤包子\",\"抓饭\",\"羊肉串\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4413, '库尔德宁景区', '天山绿谷', '以原始森林、草原、雪山为特色，是国家级自然保护区，拥有丰富的动植物资源。', 1, 1684, '新疆伊犁哈萨克自治州巩留县库尔德宁镇', 43.00000000, 82.50000000, 'https://dimg04.c-ctrip.com/images/1lo5612000bkbj5j08B38.png', '[\"https://dimg04.c-ctrip.com/images/1lo5612000bkbj5j08B38.png\", \"https://dimg04.c-ctrip.com/images/1lo5612000bkbj5j08B38.png\", \"https://dimg04.c-ctrip.com/images/1lo5612000bkbj5j08B38.png\", \"https://dimg04.c-ctrip.com/images/1lo5612000bkbj5j08B38.png\"]', 4.85, 6500, 380000, 65000, 92, 360, 60.00, '门票含景区参观费，区间车单独收费', '08:00-19:00', '夏季（6-8月）、秋季（9-10月）', '库尔德宁是哈萨克语“横沟”的意思，是天山山脉最秀美的峡谷之一，也是雪岭云杉的重要分布区。', '景区内部分路段崎岖，建议穿舒适的鞋子；禁止采摘野生植物、捕猎野生动物；注意森林防火。', '', '[\"手抓肉\",\"烤全羊\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4414, '霍尔果斯口岸', '边境国门', '中国与哈萨克斯坦的边境口岸，可参观国门、界碑，体验边境贸易和异域风情。', 3, 1684, '新疆伊犁哈萨克自治州霍尔果斯市境内', 44.18000000, 80.42000000, 'https://static.jstv.com/img/2023/9/8/2023981694157476777_625.png', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0102b1200095zcu8wCBEA_W_1920_1080.jpg_.webp\"]', 4.70, 8800, 520000, 70000, 90, 180, 30.00, '门票含国门景区参观费，出境游需办理相关证件', '09:00-18:00', '全年适宜', '霍尔果斯口岸是古丝绸之路的重要驿站，也是中国西部重要的边境口岸，拥有百年通商历史。', '进入口岸需携带身份证；遵守边境管理规定，禁止跨越边界；购物时注意辨别商品真伪。', 'http://www.hoergos.gov.cn', '[\"哈萨克斯坦巧克力\",\"烤包子\",\"抓饭\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:07:43');
INSERT INTO `attraction` VALUES (4415, '伊帕尔汗薰衣草园', '薰衣草之乡', '集薰衣草种植、加工、旅游为一体的景区，可参观薰衣草加工过程，购买薰衣草产品。', 1, 1684, '新疆伊犁哈萨克自治州霍城县芦草沟镇', 44.15000000, 80.75000000, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 4.75, 7200, 450000, 68000, 88, 120, 20.00, '免费开放，产品体验和讲解单独收费', '09:00-19:00', '夏季（6-7月）', '伊帕尔汗薰衣草园是新疆知名的薰衣草品牌基地，“伊帕尔汗”意为香妃，传承了西域香料文化。', '夏季防晒，建议携带遮阳帽；采摘薰衣草需付费；购买产品可索要发票。', 'http://www.yipaerhan.com', '[\"薰衣草饼干\",\"烤包子\",\"酸奶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:47:20');
INSERT INTO `attraction` VALUES (4416, '唐布拉草原', '百里画廊', '以草原、溪流、森林为特色，绵延百里，被誉为“百里画廊”，是伊犁的小众美景。', 1, 1684, '新疆伊犁哈萨克自治州尼勒克县境内', 43.60000000, 82.80000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 4.88, 7500, 400000, 72000, 93, 480, 0.00, '免费开放，部分景点收费', '全天开放', '夏季（6-8月）', '唐布拉草原因唐布拉大峡谷而得名，“唐布拉”意为“印章”，拥有113条沟，每条沟都有独特的风光。', '草原内无固定游览路线，建议自驾或包车；部分区域手机信号弱，注意结伴；早晚温差大，带保暖衣物。', '', '[\"手抓肉\",\"马奶酒\",\"包尔萨克\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:47:20');
INSERT INTO `attraction` VALUES (4417, '葡萄沟', '火洲凉荫', '国家5A级景区，以葡萄种植和维吾尔族风情为特色，是吐鲁番的标志性景点。', 1, 1685, '新疆吐鲁番市高昌区葡萄沟镇', 42.90000000, 89.18000000, 'https://dimg04.c-ctrip.com/images/0102t120009ed1msl8AD9.jpg', '[\"https://dimg04.c-ctrip.com/images/0102t120009ed1msl8AD9.jpg\", \"https://dimg04.c-ctrip.com/images/0102t120009ed1msl8AD9.jpg\", \"https://dimg04.c-ctrip.com/images/0102t120009ed1msl8AD9.jpg\", \"https://dimg04.c-ctrip.com/images/0102t120009ed1msl8AD9.jpg\"]', 4.80, 12500, 780000, 95000, 96, 180, 75.00, '门票含景区参观费，区间车单独收费', '08:00-21:00（夏季）；09:00-19:00（冬季）', '夏季（6-9月）', '葡萄沟是火焰山峡谷中最凉爽的地段，种植了上百种葡萄，是吐鲁番葡萄文化的核心区。', '夏季气温极高（40℃以上），注意防暑降温；景区内蚊虫较多，携带驱蚊用品；品尝葡萄需按价付费。', 'http://www.putaogou.com', '[\"葡萄沟葡萄\",\"烤全羊\",\"手抓饭\",\"凉皮子\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4418, '火焰山', '中国热极', '《西游记》中的火焰山原型，夏季地表温度可达80℃以上，以独特的丹霞地貌和高温气候为特色。', 1, 1685, '新疆吐鲁番市高昌区火焰山镇', 42.80000000, 89.50000000, 'https://dimg04.c-ctrip.com/images/0103y120009egtfms1453_W_1920_1080.jpg_.webp?_fr=wc', '[\"https://dimg04.c-ctrip.com/images/0102e120009egt6la1B6B_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0101m120009ec76j34656_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/100e12000000sk4yl811A_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0106q120008ab97ov5E3A_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0100w120008ab8vxv24D9_W_1920_1080.jpg_.webp?_fr=wc\"]', 4.70, 11800, 850000, 88000, 95, 120, 40.00, '门票含景区参观费，电瓶车单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '秋季（9-10月）（夏季需注意防暑）', '火焰山是由红色砂岩构成的山脉，因夏季炎热似火而得名，是古丝绸之路的重要地标。', '夏季游览需避开中午高温时段，携带足量饮用水和防晒用品；景区内无遮挡，注意防晒；禁止攀爬山体。', '', '[\"烤包子\",\"凉皮子\",\"西瓜\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:23:06');
INSERT INTO `attraction` VALUES (4419, '坎儿井民俗园', '地下长城', '展示了吐鲁番的坎儿井水利工程，是古代劳动人民的智慧结晶，可了解坎儿井的历史和运作原理。', 2, 1685, '新疆吐鲁番市高昌区亚尔镇西门村', 42.90000000, 89.15000000, 'https://dimg04.c-ctrip.com/images/1lo0312000eanwm435655.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0312000eanwm435655.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000eanwm435655.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000eanwm435655.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000eanwm435655.jpg\"]', 4.85, 8500, 450000, 65000, 92, 120, 40.00, '门票含景区参观费，讲解服务单独收费', '09:00-19:00', '全年适宜（夏季凉爽）', '坎儿井是吐鲁番的生命之泉，与长城、京杭大运河并称为中国古代三大工程，已有2000多年历史。', '景区内地下通道凉爽，注意增减衣物；禁止触摸水利设施；尊重讲解员的讲解，保持安静。', '', '[\"手抓饭\",\"烤包子\",\"葡萄\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4420, '交河故城', '世界最大生土建筑', '世界上最大最古老、保存最完好的生土建筑城市，是西域三十六国之一的车师前国都城。', 2, 1685, '新疆吐鲁番市高昌区交河故城景区', 42.95000000, 89.30000000, 'https://dimg04.c-ctrip.com/images/100t0n000000e0wfjF88B.jpg', '[\"https://dimg04.c-ctrip.com/images/100t0n000000e0wfjF88B.jpg\", \"https://dimg04.c-ctrip.com/images/100t0n000000e0wfjF88B.jpg\", \"https://dimg04.c-ctrip.com/images/100t0n000000e0wfjF88B.jpg\", \"https://dimg04.c-ctrip.com/images/100t0n000000e0wfjF88B.jpg\"]', 4.90, 9800, 620000, 82000, 97, 180, 70.00, '门票含景区参观费，讲解服务单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '春季（4-5月）、秋季（9-10月）', '交河故城始建于公元前2世纪，历经汉唐等朝代，是丝绸之路的重要交通枢纽，14世纪毁于战火。', '夏季气温极高，注意防暑和防晒；故城内地表无遮挡，建议携带遮阳帽和饮用水；禁止攀爬和破坏遗址。', '', '[\"烤羊肉串\",\"馕\",\"西瓜\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4421, '高昌故城', '西域古都', '古代高昌王国的都城，保留了大量的历史遗迹，是研究西域历史的重要遗址。', 2, 1685, '新疆吐鲁番市高昌区三堡乡', 42.80000000, 89.60000000, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 4.85, 7800, 480000, 70000, 94, 150, 70.00, '门票含景区参观费，讲解服务单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '春季（4-5月）、秋季（9-10月）', '高昌故城始建于公元前1世纪，是西域政治、经济、文化中心，玄奘西天取经曾在此讲经。', '景区内风沙较大，建议佩戴口罩和墨镜；夏季防暑，携带饮用水；禁止在遗址上刻画。', '', '[\"手抓肉\",\"烤包子\",\"葡萄\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:47:55');
INSERT INTO `attraction` VALUES (4422, '库木塔格沙漠', '城市沙漠', '世界上唯一与城市相连的沙漠，可体验沙漠越野、滑沙、骑骆驼等项目。', 1, 1685, '新疆吐鲁番市鄯善县库木塔格沙漠景区', 42.80000000, 90.20000000, 'https://dimg04.c-ctrip.com/images/1lo1p12000bit2e4w3912.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1p12000bit2e4w3912.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1p12000bit2e4w3912.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1p12000bit2e4w3912.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1p12000bit2e4w3912.jpg\"]', 4.88, 10500, 720000, 85000, 96, 240, 60.00, '门票含景区参观费，沙漠越野、骆驼等项目单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '秋季（9-11月）', '库木塔格沙漠形成于汉代，是新疆第三大沙漠，“库木塔格”意为“沙山”，拥有独特的沙漠地貌。', '沙漠内紫外线强，注意防晒；沙漠越野需选择正规商家，遵守安全规定；滑沙注意保护眼睛。', 'http://www.kumutage.com', '[\"烤全羊\",\"手抓饭\",\"西瓜\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4423, '喀纳斯湖', '人间净土', '国家5A级景区，以神秘的湖怪、变换颜色的湖水和原始的森林风光为特色，是新疆的标志性景点。', 1, 1686, '新疆阿勒泰地区布尔津县喀纳斯景区', 48.80000000, 87.00000000, 'https://dimg04.c-ctrip.com/images/0103x12000nutx9rw6716.jpg', '[\"https://dimg04.c-ctrip.com/images/0103x12000nutx9rw6716.jpg\", \"https://dimg04.c-ctrip.com/images/0103x12000nutx9rw6716.jpg\", \"https://dimg04.c-ctrip.com/images/0103x12000nutx9rw6716.jpg\", \"https://dimg04.c-ctrip.com/images/0103x12000nutx9rw6716.jpg\"]', 4.95, 25800, 1500004, 200000, 99, 480, 160.00, '门票含景区参观费，区间车分线路收费，自驾需缴纳通行费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '秋季（9-10月）、夏季（6-8月）', '喀纳斯湖是由冰川融水形成的高山湖泊，“喀纳斯”意为“美丽而神秘的地方”，是图瓦人的主要聚居区。', '景区内温差大，需携带保暖衣物；秋季游客较多，建议提前预订住宿；尊重图瓦人习俗，禁止随意进入民宅。', 'http://www.kanas.gov.cn', '[\"烤冷水鱼\",\"手抓肉\",\"奶茶\",\"馕\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4424, '禾木村', '神的自留地', '图瓦人聚居的村落，以木屋、炊烟、雪山、白桦林为特色，秋季金黄一片，是摄影爱好者的天堂。', 1, 1686, '新疆阿勒泰地区布尔津县禾木哈纳斯蒙古乡', 48.60000000, 87.30000000, 'https://ts1.tc.mm.bing.net/th/id/R-C.75ca742ed4ee7f437c664ccd47ae6142?rik=UKoOyw3TiNW8%2fQ&riu=http%3a%2f%2fup.cntgol.com%2f2022%2f0914%2f1663156487897.jpg&ehk=g7xpv%2fJIWeTPkbnNk7py2amLVVTACfbc1yCGNFGY4TM%3d&risl=&pid=ImgRaw&r=0', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 4.92, 18500, 980001, 150000, 98, 480, 50.00, '门票含景区参观费，区间车单独收费，冬季需乘坐马拉爬犁', '全天开放（核心区08:00-22:00）', '秋季（9-10月）、冬季（12-2月）', '禾木村是中国保留最完整的图瓦人村落，木屋建筑风格独特，被誉为“中国最美的六大乡村古镇”之一。', '村内道路多为木栈道，建议穿舒适的鞋子；秋季早晚温差大，注意保暖；摄影时尊重当地居民。', '', '[\"图瓦人手抓肉\",\"烤饼\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:06:59');
INSERT INTO `attraction` VALUES (4425, '白哈巴村', '西北第一村', '中国最西北的村落，与哈萨克斯坦接壤，以边境风光、图瓦人风情和原始的自然景观为特色。', 1, 1686, '新疆阿勒泰地区哈巴河县铁热克提乡', 48.70000000, 86.80000000, 'https://dimg04.c-ctrip.com/images/0102512000rw5341cEB50_W_1920_1080.jpg_.webp?_fr=wc', '[\"https://dimg04.c-ctrip.com/images/0102r12000rw517zcAD7B_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0105p12000rw51uvh9AF0_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0101z12000rw52rtc28F6_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/0101s12000pvjnnkq64D9_W_1920_1080.jpg_.webp?_fr=wc\",\"https://dimg04.c-ctrip.com/images/01038120009nojaau6F7F_W_1920_1080.jpg_.webp?_fr=wc\"]', 4.90, 12800, 750000, 98000, 97, 360, 30.00, '门票含景区参观费，需办理边防证，区间车单独收费', '08:00-20:00', '秋季（9-10月）、夏季（6-8月）', '白哈巴村被誉为“西北第一村”，是图瓦人和哈萨克族的聚居区，拥有浓厚的边境文化氛围。', '进入景区需携带身份证办理边防证；尊重边境管理规定，禁止跨越边界；村内无信号，注意提前沟通。', '', '[\"手抓肉\",\"烤包子\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:26:03');
INSERT INTO `attraction` VALUES (4426, '五彩滩', '天下第一滩', '以雅丹地貌和额尔齐斯河两岸的五彩岩石为特色，日落时分风光绝美。', 1, 1686, '新疆阿勒泰地区布尔津县五彩滩景区', 47.80000000, 86.80000000, 'https://dimg04.c-ctrip.com/images/1lo2h12000dq5ul31839E_W_228_10000.jpg', '[\"https://dimg04.c-ctrip.com/images/0105412000f6qvbw65FB9_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1lo6r12000dq5v4j31610_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1lo4l12000dq5v68i27DF_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1lo7212000dq5vbo68AB4_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1lo2812000dq5uwbg8BB5_W_228_10000.jpg\"]', 4.85, 15800, 850000, 120000, 96, 120, 50.00, '门票含景区参观费，摄影需遵守景区规定', '08:00-21:00（夏季）；10:00-19:00（冬季）', '日落时分（夏季20:00-22:00）', '五彩滩是由流水侵蚀和风力磨蚀形成的雅丹地貌，岩石因矿物质含量不同呈现出五彩斑斓的颜色。', '景区内风大，注意保暖和防风；日落时游客较多，注意拍照安全；禁止攀爬岩石。', '', '[\"烤冷水鱼\",\"手抓肉\",\"馕\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:18:21');
INSERT INTO `attraction` VALUES (4427, '可可托海景区', '宝石之乡', '以峡谷、湖泊、森林、矿产资源为特色，是国家5A级景区，拥有丰富的地质和人文景观。', 1, 1686, '新疆阿勒泰地区富蕴县可可托海镇', 47.20000000, 89.80000000, 'https://dimg04.c-ctrip.com/images/010281200087dc2p6AB55.jpg', '[\"https://dimg04.c-ctrip.com/images/010281200087dc2p6AB55.jpg\", \"https://dimg04.c-ctrip.com/images/010281200087dc2p6AB55.jpg\", \"https://dimg04.c-ctrip.com/images/010281200087dc2p6AB55.jpg\", \"https://dimg04.c-ctrip.com/images/010281200087dc2p6AB55.jpg\"]', 4.88, 10500, 650001, 85000, 95, 360, 90.00, '门票含景区参观费，区间车单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '夏季（6-8月）、秋季（9-10月）', '可可托海意为“绿色的丛林”，是中国重要的稀有金属产地，也是额尔齐斯河的发源地之一。', '景区内峡谷路段注意行走安全；禁止采集矿石和野生植物；冬季气温极低（-30℃以下），注意保暖。', 'http://www.keketuohai.com', '[\"烤羊肉\",\"手抓饭\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4428, '白沙湖（阿勒泰）', '沙漠圣湖', '位于沙漠中的淡水湖，湖水清澈，周边白沙环绕，是阿勒泰地区的小众秘境。', 1, 1686, '新疆阿勒泰地区哈巴河县185团境内', 48.50000000, 86.30000000, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\"]', 4.85, 7800, 480000, 72000, 93, 180, 40.00, '门票含景区参观费，需办理边防证', '08:00-20:00', '夏季（6-8月）、秋季（9-10月）', '白沙湖是由地下水和冰川融水补给形成的湖泊，是边境地区的重要生态屏障，也是军垦文化的重要象征。', '进入景区需携带身份证；遵守边境管理规定；禁止向湖中丢弃垃圾；保护湖区生态。', '', '[\"手抓肉\",\"烤包子\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4430, '乌伦古湖', '福海', '新疆第二大内陆湖，以渔业、海滨风光为特色，可体验捕鱼、品鱼、沙滩休闲等活动。', 1, 1686, '新疆阿勒泰地区福海县乌伦古湖景区', 47.10000000, 87.60000000, 'https://dimg04.c-ctrip.com/images/0105w120009cehaav1157.jpg', '[\"https://dimg04.c-ctrip.com/images/0105w120009cehaav1157.jpg\", \"https://dimg04.c-ctrip.com/images/0105w120009cehaav1157.jpg\", \"https://dimg04.c-ctrip.com/images/0105w120009cehaav1157.jpg\", \"https://dimg04.c-ctrip.com/images/0105w120009cehaav1157.jpg\"]', 4.75, 8200, 520000, 70000, 92, 240, 30.00, '门票含景区参观费，捕鱼、品鱼单独收费', '08:00-20:00', '夏季（6-8月）、秋季（9-10月）', '乌伦古湖是乌伦古河的尾闾湖，分为大海子和小海子，是新疆重要的渔业基地，“福海鱼”闻名全疆。', '湖边风大，注意保暖；品尝鱼鲜选择正规餐厅；禁止在非指定区域游泳。', '', '[\"乌伦古湖烤鱼\",\"手抓肉\",\"抓饭\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4431, '巴音布鲁克草原', '天鹅之乡', '中国第二大草原，以草原、天鹅湖、九曲十八弯为特色，是国家5A级景区。', 1, 1687, '新疆巴音郭楞蒙古自治州和静县巴音布鲁克镇', 42.70000000, 84.00000000, 'https://dimg04.c-ctrip.com/images/01052120008a6gf1416D6_C_1180_462.jpg', '[\"https://dimg04.c-ctrip.com/images/0102r120008if1sp17371_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/01052120008a6gf1416D6_W_228_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1lo0412000b8jhv4pDE48_W_228_10000.png\",\"https://dimg04.c-ctrip.com/images/1lo3l12000b8jhw5k5634_W_228_10000.png\"]', 4.90, 15800, 850002, 120000, 98, 480, 65.00, '门票含景区参观费，区间车单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '夏季（6-8月）、秋季（9-10月）', '巴音布鲁克草原是蒙古语“富饶的泉水”的意思，是天鹅的重要栖息地，九曲十八弯日落时分可看到九个太阳。', '草原海拔较高（平均2500米），注意预防高原反应；天气寒冷，需携带保暖衣物；天鹅湖禁止投喂和惊扰天鹅。', 'http://www.bayanbulak.com', '[\"手抓肉\",\"烤全羊\",\"奶茶\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:17:32');
INSERT INTO `attraction` VALUES (4432, '博斯腾湖', '西海', '中国最大的内陆淡水湖，以湖泊、芦苇、荷花、渔业为特色，是国家5A级景区。', 1, 1687, '新疆巴音郭楞蒙古自治州博湖县境内', 41.90000000, 86.60000000, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\"]', 4.85, 12500, 720001, 95000, 96, 240, 45.00, '门票含景区参观费，游船、捕鱼体验单独收费', '08:00-20:00', '夏季（6-8月）、秋季（9-10月）', '博斯腾湖意为“绿洲”，是开都河的尾闾湖，也是新疆重要的渔业和旅游基地，拥有“西塞明珠”的美誉。', '湖区风大，注意防晒和防风；乘船需穿救生衣，遵守安全规定；禁止采摘芦苇和荷花。', 'http://www.bostenhu.com', '[\"博斯腾湖烤鱼\",\"手抓饭\",\"烤包子\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4433, '楼兰古城', '沙漠秘境', '古楼兰王国的都城，是丝绸之路的重要节点，保留了大量的历史遗迹，极具神秘色彩。', 2, 1687, '新疆巴音郭楞蒙古自治州若羌县罗布泊境内', 40.40000000, 89.50000000, 'https://dimg04.c-ctrip.com/images/0101912000lqihupn6287.jpg', '[\"https://dimg04.c-ctrip.com/images/0101912000lqihupn6287.jpg\", \"https://dimg04.c-ctrip.com/images/0101912000lqihupn6287.jpg\", \"https://dimg04.c-ctrip.com/images/0101912000lqihupn6287.jpg\", \"https://dimg04.c-ctrip.com/images/0101912000lqihupn6287.jpg\"]', 4.95, 5800, 450001, 88000, 99, 360, 3000.00, '需办理文物保护通行证，仅限科考和特许游客进入，需专业向导陪同', '仅限白天进入（需提前报备）', '秋季（9-10月）', '楼兰古城始建于公元前3世纪，公元4世纪突然消失，是世界著名的未解之谜，拥有极高的历史价值。', '进入罗布泊需专业装备和向导，禁止单独进入；保护文物，禁止触摸和带走任何物品；遵守文物保护规定。', '', '[\"风干肉\",\"馕\",\"饮用水（自备）\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4434, '塔克拉玛干沙漠（巴州段）', '死亡之海', '中国最大的沙漠，巴州段可体验沙漠越野、露营、观星等活动，感受大漠风光。', 1, 1687, '新疆巴音郭楞蒙古自治州轮台县境内', 41.70000000, 84.20000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 4.88, 8500, 580000, 78000, 97, 480, 150.00, '门票含景区参观费，沙漠越野需专业车队陪同', '全天开放（建议白天进入）', '秋季（9-11月）', '塔克拉玛干沙漠意为“进去出不来的地方”，是世界第二大流动沙漠，拥有独特的沙漠地貌和胡杨林景观。', '沙漠内无固定路线，需专业向导和越野车；携带足量饮用水和食物；注意防晒和防沙。', '', '[\"烤全羊\",\"馕\",\"马奶酒\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4435, '轮台胡杨林', '沙漠英雄树', '世界上面积最大的胡杨林，秋季金黄一片，是新疆最著名的胡杨林景区。', 1, 1687, '新疆巴音郭楞蒙古自治州轮台县轮南镇', 41.70000000, 84.30000000, 'https://youimg1.c-ctrip.com/target/100v0z000000o428vDBC3.jpg', '[\"https://ts1.tc.mm.bing.net/th/id/R-C.df9f188c4c2b51a8c58870ecad9961cd?rik=LAecDScJEk9m7Q&riu=http%3a%2f%2fimg.pconline.com.cn%2fimages%2fupload%2fupc%2ftx%2fphotoblog%2f1412%2f30%2fc1%2f1278377_1278377_1419904207876.jpg&ehk=ju%2f7jsZT%2bWBEmUkyjeSycW0Ojv1W%2bfYvdNF4GsFchP8%3d&risl=&pid=ImgRaw&r=0\",\"https://www.bijingdi.com/uploadfile/2023/1121/20231121200342120.jpg\",\"https://ts1.tc.mm.bing.net/th/id/R-C.756377dd496e0127e315f7eb8db98df2?rik=e6CqTbPaTlXqZA&riu=http%3a%2f%2fimg.pconline.com.cn%2fimages%2fupload%2fupc%2ftx%2fphotoblog%2f1412%2f30%2fc1%2f1278804_1278804_1419904477069.jpg&ehk=SXfr%2ft5XfmZ2yuS%2b8VldwK3rKu9naaKyHULXI%2bgAL2w%3d&risl=&pid=ImgRaw&r=0\",\"https://youimg1.c-ctrip.com/target/100w10000000onrnpF9A4.jpg\",\"https://youimg1.c-ctrip.com/target/100v0z000000o428vDBC3.jpg\"]', 4.90, 12800, 820000, 110000, 98, 240, 45.00, '门票含景区参观费，小火车单独收费', '08:00-20:00（秋季延长至22:00）', '秋季（10-11月）', '轮台胡杨林是世界上最大的原始胡杨林，胡杨“生而不死一千年，死而不倒一千年，倒而不朽一千年”，极具生命力。', '秋季游客较多，建议错峰出行；景区内蚊虫较多，携带驱蚊用品；禁止采摘胡杨叶片和破坏树木。', '', '[\"烤全羊\",\"手抓饭\",\"烤包子\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-23 13:20:22');
INSERT INTO `attraction` VALUES (4436, '巩乃斯森林公园', '雪山森林', '以雪山、森林、草原、河流为特色，是巴州著名的避暑和休闲胜地。', 1, 1687, '新疆巴音郭楞蒙古自治州和静县巩乃斯镇', 43.00000000, 84.30000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\"]', 4.85, 6500, 420000, 68000, 94, 360, 30.00, '门票含景区参观费，区间车单独收费', '08:00-19:00', '夏季（6-8月）、秋季（9-10月）', '巩乃斯蒙古语意为“绿色的谷地”，是天山山脉的重要林区，也是巴音布鲁克草原的重要组成部分。', '林区注意森林防火；禁止采摘野生蘑菇和植物；山区天气多变，携带雨具和保暖衣物。', '', '[\"手抓肉\",\"烤包子\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4437, '铁门关', '西域铁门', '古代丝绸之路的重要关隘，是南北疆的分界线，拥有深厚的历史文化底蕴。', 2, 1687, '新疆巴音郭楞蒙古自治州库尔勒市铁门关镇', 41.70000000, 86.10000000, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 4.75, 5800, 380000, 55000, 90, 120, 20.00, '门票含景区参观费，讲解服务单独收费', '09:00-19:00', '全年适宜', '铁门关始建于晋代，是古代兵家必争之地，唐代诗人岑参曾在此留下著名诗篇，拥有2000多年历史。', '景区内台阶较多，注意行走安全；尊重历史遗迹，禁止刻画；遵守景区参观秩序。', '', '[\"库尔勒香梨\",\"烤包子\",\"手抓饭\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4438, '天山神秘大峡谷', '红色峡谷', '以红色砂岩构成的峡谷地貌为特色，峡谷内奇峰异石，风光壮丽。', 1, 1688, '新疆阿克苏地区库车市阿艾乡', 41.80000000, 83.00000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 4.85, 9800, 650000, 85000, 96, 240, 40.00, '门票含景区参观费，讲解服务单独收费', '08:00-20:00（夏季）；10:00-18:00（冬季）', '春季（4-5月）、秋季（9-10月）', '天山神秘大峡谷又称库车大峡谷，是由流水侵蚀和风力作用形成的雅丹地貌，拥有“中国最美峡谷”的美誉。', '峡谷内部分路段狭窄，注意单行线秩序；夏季多雨，注意防范洪水；禁止攀爬峡谷岩壁。', '', '[\"库车大馕\",\"烤包子\",\"手抓肉\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4439, '温宿大峡谷', '地质奇观', '以丹霞、雅丹、喀斯特等多种地貌为特色，是新疆最大的地质公园之一。', 1, 1688, '新疆阿克苏地区温宿县博孜墩乡', 41.20000000, 80.40000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\"]', 4.80, 7500, 480000, 72000, 94, 360, 30.00, '门票含景区参观费，越野车单独收费', '08:00-20:00', '春季（4-5月）、秋季（9-10月）', '温宿大峡谷是天山山脉南麓的重要地质遗迹，拥有距今2.6亿年的地质历史，是研究天山演化的重要区域。', '景区内无信号，注意结伴而行；越野车需选择正规商家；禁止采集矿石和化石。', '', '[\"烤羊肉串\",\"馕\",\"奶茶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4440, '库车王府', '西域王府', '清代库车王的府邸，融合了中原和维吾尔族建筑风格，展示了库车王的历史和文化。', 2, 1688, '新疆阿克苏地区库车市林基路街', 41.70000000, 82.90000000, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 4.75, 6500, 420000, 65000, 92, 120, 45.00, '门票含景区参观费，讲解服务单独收费', '09:00-19:00', '全年适宜', '库车王府始建于1759年，是清代乾隆皇帝册封的库车王的府邸，2004年重建，是库车历史文化的重要载体。', '参观时尊重王府的历史和文化；禁止触摸文物；遵守景区参观秩序，禁止大声喧哗。', '', '[\"库车烤包子\",\"手抓饭\",\"酸奶\"]', 1, 2, 1, '2026-03-19 17:18:07', '2026-03-20 22:49:39');
INSERT INTO `attraction` VALUES (4456, '塔尔寺', '藏传佛教格鲁派六大寺院之一', '塔尔寺是中国藏传佛教格鲁派（黄教）六大寺院之一，创建于明洪武十二年（1379年），是为纪念藏传佛教格鲁派创始人宗喀巴大师而建。寺院依山而建，由众多殿宇、经堂、佛塔、僧舍组成，占地面积约600余亩。寺内的酥油花、壁画和堆绣被誉为“塔尔寺三绝”，具有极高的艺术价值。[citation:4][citation:7]', 2, 1780, '青海省西宁市湟中区金塔路56号', 36.48333333, 101.56666667, 'https://dimg04.c-ctrip.com/images/0105e120007zf4uth8064.jpg', '[\"https://dimg04.c-ctrip.com/images/0105e120007zf4uth8064.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g1/M02/7B/30/CghzfVWwvEuAXNVYAA9qKeDCFXc998.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g1/M05/CE/54/CghzflWxFR-AG2wYAASteNIese0205.jpg\", \"https://dimg04.c-ctrip.com/images/010141200087d1ea2AEBF.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2g12000ickl9k23912.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M0A/8F/25/CghzgFWxFSGASNmMAAVDqkv3a20979.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '07:30-18:30', '6-8月', '塔尔寺始建于1379年，距今已有600多年历史，是宗喀巴大师的诞生地。', '尊重宗教信仰，遵守寺院规定，殿内禁止拍照。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4457, '青海藏文化博物院', '全球唯一全面收藏藏文化的博物馆', '青海藏文化博物院是国家一级博物馆、国家4A级景区，被誉为“藏文化百科全书”。馆内珍藏着载入吉尼斯纪录的618米巨幅唐卡《中国藏族文化艺术彩绘大观》，由400位画师耗时4年完成，涵盖藏族宇宙观、历史、宗教等内容。[citation:4]', 2, 1779, '青海省西宁市生物科技产业园区经二路36号', 36.68333333, 101.73333333, 'https://dimg04.c-ctrip.com/images/100q1f000001grjalD0E5.jpg', '[\"https://dimg04.c-ctrip.com/images/100q1f000001grjalD0E5.jpg\", \"https://dimg04.c-ctrip.com/images/01069120008vur45q56D5.jpg\", \"https://dimg04.c-ctrip.com/images/0102h120008vurmwr5A71.jpg\", \"https://dimg04.c-ctrip.com/images/0105w120008vuputr4964.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1312000ickvy3v727D.jpg\", \"https://dimg04.c-ctrip.com/images/zc0e170000011go8z7956_R_180_180.jpg\"]', 0.00, 0, 1, 0, 0, NULL, 60.00, NULL, '09:00-17:00', '全年', '博物院系统展示了藏文化的博大精深，是了解藏族历史、宗教、艺术的最佳场所。', '文明参观，请勿触摸展品。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4458, '东关清真大寺', '中国四大清真寺之一', '西宁东关清真大寺是青海省最大的清真寺，始建于明洪武年间，具有中国古典建筑与伊斯兰教特色相融合的风格，可同时容纳3000多人进行礼拜。[citation:7]', 2, 1779, '青海省西宁市城东区东关大街31号', 36.61666667, 101.78333333, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\"]', 0.00, 0, 1, 0, 0, NULL, 0.00, NULL, '08:00-18:00', '全年', '寺院始建于1380年，历经多次扩建，是西北地区伊斯兰教重要活动场所。', '参观时请尊重宗教信仰，穿着得体。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4459, '青藏高原野生动物园', '高原特色野生动物园', '青藏高原野生动物园是青海省唯一的大型动物园，以展示青藏高原特有野生动物为主，包括雪豹、藏羚羊、黑颈鹤、普氏原羚等珍稀动物。[citation:1]', 3, 1779, '青海省西宁市城西区行知路9号', 36.61666667, 101.73333333, 'https://www.bijingdi.com/uploadfile/2023/1023/20231023223401913.jpg', '[\"https://p1-q.mafengwo.net/s12/M00/EE/48/wKgED1vmOgqAWnQdABNSw2hPcWA12.jpeg\",\"https://youimg1.c-ctrip.com/target/100l0h0000008tkbi9765.jpg\",\"https://p1-q.mafengwo.net/s11/M00/F4/F7/wKgBEFtHUFKAN6P2AAqPTQr9ZP493.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\"]', 0.00, 0, 2, 0, 0, NULL, 30.00, NULL, '08:30-18:00', '5-10月', '园区依托青藏高原独特的自然环境，致力于高原珍稀动物的保护和繁育。', '请勿投喂动物，遵守园区规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-23 13:09:20');
INSERT INTO `attraction` VALUES (4460, '青海省博物馆', '青海历史文化的窗口', '青海省博物馆是展示青海历史文化和民族风情的重要窗口，馆藏文物3万余件，包括彩陶、青铜器、唐卡、民族服饰等，其中国家一级文物近百件。[citation:1]', 2, 1779, '青海省西宁市城西区西关大街58号', 36.63333333, 101.76666667, 'https://dimg04.c-ctrip.com/images/0102z12000id9z6y8B857.jpg', '[\"https://dimg04.c-ctrip.com/images/0102z12000id9z6y8B857.jpg\", \"https://dimg04.c-ctrip.com/images/0102r12000ida4u6c7E27.jpg\", \"https://dimg04.c-ctrip.com/images/0101h12000ida461w287C.jpg\", \"https://dimg04.c-ctrip.com/images/0102212000b8cfyf6295C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2512000icm55xgCD96.jpg\", \"https://dimg04.c-ctrip.com/images/Z80w0d0000006wzz87D82_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00（周一闭馆）', '全年', '博物馆系统展示了青海从史前到近现代的历史发展脉络。', '文明参观，请勿触摸展品。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4461, '西宁浦宁之珠', '西宁电视塔', '浦宁之珠是西宁市的标志性建筑之一，是一座集广播电视发射、旅游观光、餐饮娱乐于一体的多功能电视塔，塔高188米，可俯瞰西宁全景。[citation:1]', 3, 1779, '青海省西宁市城西区西山一巷', 36.63333333, 101.73333333, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '09:00-21:00', '全年', '由上海市浦东新区援建，体现了东西部协作的情谊。', '注意安全，勿倚靠玻璃围栏。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4462, '力盟步行街', '西宁城市休闲文化中心', '力盟商业巷步行街是西宁市集购物、餐饮、娱乐、休闲于一体的城市综合体，融合了现代商业与河湟文化元素，是市民和游客休闲娱乐的热门场所。[citation:1]', 4, 1779, '青海省西宁市城西区五四大街', 36.63333333, 101.76666667, 'https://dimg04.c-ctrip.com/images/100a12000000sz9oq2FE7_W_1920_1080.jpg_.webp?_fr=wc', '[\"https://dimg04.c-ctrip.com/images/1mh6n12000j616e8n98E5_W_640_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1mh7112000j610sw3407A_W_640_10000.jpg\",\"https://p1-q.mafengwo.net/s12/M00/DB/2E/wKgED1uZOz6AQJqGAAdUM2iciRI05.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/15/B0/wKgED1vSyqCALRiyAAzAhsZugRE62.jpeg\"]', 0.00, 0, 2, 0, 0, NULL, 0.00, NULL, '全天', '全年', '步行街以“一街八巷”的格局，展现河湟地区传统商业文化。', '保管好个人财物，注意人身安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-23 13:11:45');
INSERT INTO `attraction` VALUES (4463, '丹噶尔古城', '高原古商贸城', '丹噶尔古城始建于明洪武年间，是古丝绸之路和唐蕃古道的重要驿站，素有“海藏咽喉”、“茶马商都”之称。古城内保存有文庙、城隍庙、丹噶尔厅署等古建筑。[citation:1][citation:6]', 2, 1781, '青海省西宁市湟源县城关镇', 36.68333333, 101.26666667, 'https://dimg04.c-ctrip.com/images/100r1a0000019o4nb2BEF.jpg', '[\"https://dimg04.c-ctrip.com/images/100r1a0000019o4nb2BEF.jpg\", \"https://dimg04.c-ctrip.com/images/0106n12000mofj3774568.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0u12000qz89u3a60DD.jpg\", \"https://dimg04.c-ctrip.com/images/100f1a0000019pq6oD0FC.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6512000icns60u571A.jpg\", \"https://dimg04.c-ctrip.com/images/1h64b120008kjcheq9FA8_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-18:00', '5-10月', '明清时期青藏高原重要的商贸集散地，见证了茶马互市的繁荣。', '古城内巷道较多，注意游览路线。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4464, '互助土族故土园', '国家5A级旅游景区', '互助土族故土园是青海省首个国家5A级旅游景区，以展示土族民俗文化为核心，包含彩虹部落土族园、纳顿庄园、西部土族民俗文化村等景点。游客可体验土族轮子秋、安召舞，品尝青稞酒。[citation:1]', 2, 1786, '青海省海东市互助土族自治县威远镇', 36.83333333, 101.95000000, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/93/2F/wKgED1uo6VqAVlQBABc3oZhyNpo76.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-18:00', '5-10月', '土族是青海世居民族之一，互助县是全国唯一的土族自治县。', '尊重土族风俗习惯。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4465, '瞿昙寺', '西北地区保存最完整的明代建筑群', '瞿昙寺是一座藏传佛教格鲁派寺院，始建于明洪武二十五年（1392年），因明太祖朱元璋赐名“瞿昙寺”而得名。寺院仿照北京故宫布局建造，被誉为“小故宫”，寺内保存有大量明代壁画和石雕。[citation:6]', 2, 1784, '青海省海东市乐都区瞿昙镇', 36.45000000, 102.40000000, 'https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:30-17:30', '5-10月', '明代皇家寺院，由朱元璋赐名，是西北地区保存最完整的明代官式建筑群。', '尊重宗教信仰，保护文物古迹。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4466, '平安驿·河湟民俗文化体验地', '河湟文化体验地', '平安驿是集河湟民俗文化展示、传统手工艺制作、特色美食品鉴于一体的文化旅游体验地，还原了古代驿站的风貌，游客可品尝青海特色小吃，体验民俗文化。[citation:6]', 2, 1785, '青海省海东市平安区平安驿', 36.50000000, 102.11666667, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '平安驿是古代“平安驿站”所在地，是唐蕃古道重要节点。', '保管好个人财物。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4467, '孟达天池', '高原上的西双版纳', '孟达天池位于循化县孟达国家级自然保护区，是青藏高原少有的原始森林和高原湖泊景观，海拔2504米，池水清澈，四周森林茂密，动植物资源丰富，被誉为“高原西双版纳”。[citation:2]', 1, 1789, '青海省海东市循化撒拉族自治县孟达乡', 35.83333333, 102.71666667, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/E0/2C/wKgED1uOr1OAYEkgABLdm0wqGxo46.jpeg\"]', 0.00, 0, 2, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '6-9月', '孟达自然保护区是青海省第一个自然保护区，保存有完整的森林生态系统。', '山路较陡，注意安全，保护生态环境。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4468, '门源百里油菜花海', '中国最美花海', '门源油菜花海是世界上最壮观的花海之一，每年7月，50万亩油菜花同时盛开，绵延上百公里，宛如金色海洋。圆山观花台是观赏花海全景的最佳位置。[citation:1]', 1, 1791, '青海省海北州门源县青石嘴镇', 37.36666667, 101.61666667, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '全天', '7月', '门源种植油菜已有1800多年历史，是中国北方小油菜基地。', '花海游览请勿踩踏油菜花。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4469, '阿咪东索景区', '天境祁连核心景区', '阿咪东索意为“千兵哨卡”，俗称牛心山，是祁连县的标志性景点。景区集雪山、峡谷、丹霞、森林、草原等多种地貌于一体，四季景色各异，被誉为“东方瑞士”。[citation:1]', 1, 1792, '青海省海北州祁连县八宝镇', 38.18333333, 100.25000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '6-9月', '阿咪东索是祁连山支脉，是当地藏族群众心中的神山。', '高海拔地区，注意防寒和高原反应。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4470, '卓尔山', '东方瑞士的观景台', '卓尔山属于丹霞地貌，由红色砂岩、砾岩组成，藏语称为“宗穆玛釉玛”，意为美丽的红润皇后。站在卓尔山顶可俯瞰祁连县城、牛心山和八宝河，是摄影爱好者的天堂。[citation:1]', 1, 1792, '青海省海北州祁连县八宝镇', 38.20000000, 100.26666667, 'https://dimg04.c-ctrip.com/images/0103l120008376a9x1B12.jpg', '[\"https://dimg04.c-ctrip.com/images/0103l120008376a9x1B12.jpg\", \"https://dimg04.c-ctrip.com/images/0103l120008376a9x1B12.jpg\", \"https://dimg04.c-ctrip.com/images/0103l120008376a9x1B12.jpg\", \"https://dimg04.c-ctrip.com/images/0103l120008376a9x1B12.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '07:00-20:00', '6-9月', '卓尔山是祁连山国家公园的重要组成部分。', '栈道较陡，注意安全，预防高原反应。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4471, '金银滩草原', '西部歌王王洛宾创作之地', '金银滩草原是世界名曲《在那遥远的地方》的诞生地，西部歌王王洛宾曾在此创作。草原地势平坦，水草丰美，夏季野花盛开，金色的金露梅和银色的银露梅遍布草原，故名金银滩。[citation:1][citation:5]', 1, 1794, '青海省海北州海晏县西北', 36.95000000, 100.90000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '全天', '6-8月', '1939年，王洛宾在此创作了传世名曲《在那遥远的地方》。', '草原昼夜温差大，注意保暖。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4472, '原子城景区', '中国第一颗原子弹研制基地', '原子城是中国第一个核武器研制基地，现为国家级爱国主义教育示范基地。景区包括原子城纪念馆、纪念碑、爆轰试验场等景点，展示了中国核工业发展的光辉历程。[citation:1][citation:5]', 5, 1794, '青海省海北州海晏县西海镇', 36.95000000, 100.90000000, 'https://dimg04.c-ctrip.com/images/0HJ1v12000rqyoaju3A61_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '09:00-17:00（周一闭馆）', '全年', '1964年10月16日，中国第一颗原子弹在这里研制成功。', '文明参观，遵守场馆规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4473, '岗什卡雪峰', '祁连山东段最高峰', '岗什卡雪峰海拔5254.5米，是祁连山东段最高峰，也是门源境内群山之首。夏季山顶积雪终年不化，山下油菜花海金黄一片，形成“雪山花海”的奇观。冬季是登山滑雪的理想之地。[citation:1][citation:6]', 1, 1791, '青海省海北州门源县西北部', 37.70000000, 101.45000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '7-9月（登山最佳为7-8月）', '岗什卡是藏区十三大神山之一，传说为阿尼玛卿山神的妻子。', '高海拔登山需专业装备和向导，量力而行。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4474, '青海湖二郎剑景区', '青海湖主景区', '青海湖是中国最大的内陆咸水湖，二郎剑景区是青海湖主景区之一，因湖岸形似一把长剑而得名。景区可乘船游湖、观鸟、欣赏湖光山色。[citation:1][citation:4]', 1, 1796, '青海省海南州共和县109国道旁', 36.58333333, 100.50000000, 'https://dimg04.c-ctrip.com/images/1lo4r12000rhjanaiD648.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo4r12000rhjanaiD648.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4r12000rhjanaiD648.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4r12000rhjanaiD648.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4r12000rhjanaiD648.jpg\"]', 0.00, 0, 1, 0, 0, NULL, 90.00, NULL, '08:30-18:00', '5-10月', '青海湖古称“西海”，是藏族群众心中的圣湖。', '高海拔地区，注意防晒、防寒、预防高原反应。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4475, '黑马河', '青海湖最美日出观赏地', '黑马河是青海湖环湖西路的起点，也是观赏青海湖日出的最佳地点。每年夏季，众多游客在此露营，等待清晨第一缕阳光照亮湖面和雪山。[citation:6]', 1, 1796, '青海省海南州共和县黑马河镇', 36.71666667, 99.78333333, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '5-10月', '黑马河是青海湖重要的观景点，也是藏族群众转湖的必经之地。', '早晚温差大，注意保暖；露营注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4476, '龙羊峡景区', '黄河第一峡', '龙羊峡是黄河上游第一座大型水电站——龙羊峡水电站所在地，峡谷两岸峭壁林立，黄河水在此清澈碧绿。景区可乘船游览峡谷，欣赏丹霞地貌和高原平湖风光。[citation:1]', 1, 1796, '青海省海南州共和县龙羊峡镇', 36.16666667, 100.95000000, 'https://dimg04.c-ctrip.com/images/1me7212000lqlenaqE9CD.jpg', '[\"https://dimg04.c-ctrip.com/images/1me7212000lqlenaqE9CD.jpg\", \"https://dimg04.c-ctrip.com/images/1me7212000lqlenaqE9CD.jpg\", \"https://dimg04.c-ctrip.com/images/1me7212000lqlenaqE9CD.jpg\", \"https://dimg04.c-ctrip.com/images/1me7212000lqlenaqE9CD.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-17:30', '5-10月', '龙羊峡水电站是黄河上游“龙头”电站，被誉为“万里黄河第一坝”。', '峡谷风大，注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4477, '贵德国家地质公园', '七彩丹霞地貌', '贵德国家地质公园以七彩丹霞地貌著称，山峰色彩斑斓，形态奇特，有“天下丹霞第一奇”的美誉。景区内的阿什贡峡是观赏丹霞地貌的最佳地点。[citation:6]', 1, 1797, '青海省海南州贵德县尕让乡', 36.03333333, 101.43333333, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/93/2F/wKgED1uo6VqAVlQBABc3oZhyNpo76.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '5-10月', '贵德丹霞形成于1.2亿年前的白垩纪。', '游览时注意防晒，不要攀爬岩体。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4478, '清清黄河景区', '天下黄河贵德清', '贵德段的黄河水清澈见底，颠覆了人们对黄河“浑浊”的刻板印象。景区内可近距离接触黄河，欣赏黄河两岸的丹霞地貌和湿地风光。[citation:6]', 1, 1797, '青海省海南州贵德县河滨公园', 36.03333333, 101.43333333, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '5-10月', '黄河在贵德段因水流平缓、泥沙沉淀，呈现碧绿清澈的景象。', '注意安全，请勿下水游泳。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4479, '茶卡盐湖', '中国的天空之镜', '茶卡盐湖是柴达木盆地四大盐湖之一，湖面如镜，倒映着蓝天白云和远处的雪山，被誉为“中国的天空之镜”。游客可乘坐小火车深入盐湖，体验踩盐、摄影的乐趣。[citation:4][citation:6]', 1, 1805, '青海省海西州乌兰县茶卡镇', 36.71666667, 99.06666667, 'https://dimg04.c-ctrip.com/images/1lo2e12000iry3bbf0353.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2e12000iry3bbf0353.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2e12000iry3bbf0353.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2e12000iry3bbf0353.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2e12000iry3bbf0353.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '06:00-20:00', '6-9月', '茶卡盐湖已有3000多年开采历史，是古丝绸之路的重要站点。', '盐湖卤水有腐蚀性，注意保护皮肤和相机；穿防水鞋套。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4480, '察尔汗盐湖', '中国最大的盐湖', '察尔汗盐湖是中国最大的盐湖，也是世界第二大盐湖，总面积5856平方公里。湖面覆盖着厚厚的盐盖，青藏铁路和公路直接建在盐盖上，被誉为“万丈盐桥”。[citation:4]', 1, 1802, '青海省海西州格尔木市北60公里', 36.91666667, 95.26666667, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/93/2F/wKgED1uo6VqAVlQBABc3oZhyNpo76.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:30-18:00', '6-9月', '察尔汗盐湖蕴藏着丰富的钾、镁、锂等矿产资源，是青海盐湖工业的基地。', '盐湖卤水有腐蚀性，注意保护皮肤。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4481, '乌素特水上雅丹地质公园', '世界唯一的水上雅丹', '乌素特水上雅丹是世界上唯一的水上雅丹地貌景观。雅丹群分布在湖泊之中，形态各异，被誉为“水上魔鬼城”。春秋时节，成群的水鸟在此栖息，又称“百鸟千岛湖”。[citation:4][citation:6]', 1, 1802, '青海省海西州大柴旦行委西台地区', 37.51666667, 93.70000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-20:00', '5-10月', '乌素特雅丹形成于亿万年的地质变迁，因昆仑山冰川融水形成湖泊，形成了独特的水上雅丹景观。', '景区风大，注意防晒保暖；保护生态环境。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4482, '大柴旦翡翠湖', '上帝的眼泪', '大柴旦翡翠湖原是大柴旦化工厂盐湖采矿队采矿区，因湖水含矿量不同，呈现出淡青、翠绿、深蓝等绚丽色彩，宛如一块块翡翠散落人间，被誉为“上帝的眼泪”。[citation:6]', 1, 1808, '青海省海西州大柴旦镇西北', 37.88333333, 95.31666667, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-20:00', '6-9月', '翡翠湖原为采矿留下的卤水坑，因矿物成分不同形成色彩斑斓的湖泊。', '湖岸盐壳较硬，行走注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4483, '茫崖翡翠湖', '瀚海中的绿宝石', '茫崖翡翠湖位于柴达木盆地最西缘，湖水碧绿如玉，与远处的昆仑山、阿尔金山相映成趣。景区目前免费开放，是摄影爱好者的新晋打卡地。[citation:6]', 1, 1804, '青海省海西州茫崖市花土沟镇', 38.23333333, 90.80000000, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', '茫崖翡翠湖是盐湖开采留下的独特景观。', '路况较差，自驾注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4484, '艾肯泉', '恶魔之眼', '艾肯泉是茫崖市的一处奇特泉水，泉眼终年喷涌，因泉水含硫磺等矿物质，周围土地呈红褐色、黄色，从空中俯瞰形似一只眼睛，被称为“恶魔之眼”或“大地之眼”。[citation:6]', 1, 1804, '青海省海西州茫崖市花土沟镇', 38.03333333, 90.83333333, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\"]', 0.00, 0, 1, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', '艾肯泉的成因与地下深部热液活动有关，泉水含多种矿物质。', '泉水有腐蚀性，请勿接触。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4485, '黑独山', '水墨丹青画卷', '黑独山因其山体呈黑色，岩石历经风化形成独特的雅丹地貌，远望如同一幅幅水墨丹青画卷，近年来成为青海旅游的新晋网红打卡地。[citation:3][citation:6]', 1, 1804, '青海省海西州茫崖市冷湖镇', 38.73333333, 93.38333333, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '5-10月', '黑独山是典型的雅丹地貌，因其独特的黑色岩体备受摄影爱好者青睐。', '地处无人区，注意安全，备足物资。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4486, '可鲁克湖-托素湖', '情人湖', '可鲁克湖和托素湖一咸一淡，由一条小河相连，被称为“情人湖”。可鲁克湖是淡水湖，水草丰美，候鸟成群；托素湖是咸水湖，湖面辽阔，周围是茫茫戈壁。[citation:2]', 1, 1803, '青海省海西州德令哈市西南', 37.16666667, 96.96666667, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 20.00, NULL, '08:30-18:00', '5-10月', '可鲁克湖和托素湖是柴达木盆地重要的湿地生态系统。', '保护湿地生态环境，请勿乱扔垃圾。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4487, '坎布拉国家森林公园', '世界地质公园', '坎布拉国家森林公园以丹霞地貌、原始森林、宗教文化著称，2025年荣获世界地质公园称号。景区内山峰形态奇特，李家峡水库镶嵌其中，形成“碧水丹山”的壮丽景观。[citation:3][citation:5]', 1, 1811, '青海省黄南州尖扎县西北部', 36.03333333, 101.75000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '5-10月', '坎布拉是藏传佛教后弘期的发祥地之一，景区内有阿琼南宗寺等古迹。', '部分路段陡峭，注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4488, '隆务寺', '安多地区格鲁派大寺', '隆务寺是藏传佛教格鲁派在安多地区的重要寺院，始建于元代，距今已有700多年历史。寺院依山而建，规模宏大，珍藏有大量佛像、壁画、唐卡等珍贵文物。[citation:2][citation:6]', 2, 1810, '青海省黄南州同仁市隆务镇', 35.51666667, 102.01666667, 'https://dimg04.c-ctrip.com/images/1mh0r12000jjg5qqx16C2_W_640_10000.jpg', '[\"https://dimg04.c-ctrip.com/images/1mh6n12000j616e8n98E5_W_640_10000.jpg\",\"https://dimg04.c-ctrip.com/images/1mh7112000j610sw3407A_W_640_10000.jpg\",\"https://p1-q.mafengwo.net/s12/M00/DB/2E/wKgED1uZOz6AQJqGAAdUM2iciRI05.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/15/B0/wKgED1vSyqCALRiyAAzAhsZugRE62.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', '隆务寺是热贡艺术的发祥地之一，寺内保存有大量精美的壁画和堆绣。', '尊重宗教信仰，遵守寺院规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4489, '热贡历史文化名城', '国家级历史文化名城', '同仁市是国家级历史文化名城，是热贡艺术的发源地。热贡艺术包括唐卡、堆绣、雕塑、建筑彩绘等，被列入联合国教科文组织非物质文化遗产名录。[citation:6][citation:7]', 2, 1810, '青海省黄南州同仁市隆务镇', 35.51666667, 102.01666667, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '热贡艺术起源于元代，距今已有700多年历史，是藏传佛教艺术的重要流派。', '尊重当地文化，请勿随意拍摄。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4490, '年保玉则', '天神的后花园', '年保玉则是果洛神山之首，主峰海拔5369米，由无数海拔4000米以上的山峰组成，山间有360个冰川湖泊，景色原始壮丽。目前为保护生态环境，景区暂时关闭。[citation:2]', 1, 1819, '青海省果洛州久治县索呼日麻乡', 33.28333333, 101.10000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '暂时关闭', '7-8月', '年保玉则是藏区著名的神山，传说为果洛藏族的发祥地。', '景区已关闭，请勿擅自进入。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4491, '阿尼玛卿雪山', '藏区四大神山之一', '阿尼玛卿雪山是藏区四大神山之一，主峰玛卿岗日海拔6282米，终年积雪。这里是藏族群众转山朝圣的圣地，也是登山爱好者挑战的高峰。[citation:2]', 1, 1815, '青海省果洛州玛沁县西北部', 34.78333333, 99.41666667, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', '阿尼玛卿是藏传佛教的四大神山之一，每年都有大量信徒前来转山。', '高海拔地区，需专业装备和向导。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4492, '扎陵湖-鄂陵湖', '黄河源头姊妹湖', '扎陵湖和鄂陵湖是黄河源头最大的两个淡水湖，被称为“黄河源头姊妹湖”。两湖海拔4300多米，湖水清澈，水鸟成群，是黄河的发源地。[citation:2]', 1, 1820, '青海省果洛州玛多县西部', 34.91666667, 97.25000000, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '需特别许可', '7-8月', '黄河源头地区是藏族群众心中的圣地，有“黄河源”石碑。', '生态保护区，进入需办理手续，保护环境。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4493, '新寨玛尼堆', '世界最大的玛尼石堆', '新寨玛尼堆是世界上最大的玛尼石堆，由25亿块玛尼石组成，石刻经文数量之多、内容之丰富，堪称“世界第一石刻图书馆”。[citation:2]', 2, 1822, '青海省玉树州玉树市新寨村', 33.01666667, 97.01666667, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '新寨玛尼堆由第一世嘉那活佛创建于1715年，至今已有300多年历史。', '尊重信仰，请勿随意拿走玛尼石。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4494, '勒巴沟', '千年石刻艺术长廊', '勒巴沟是通天河南岸的一条峡谷，沟内分布着数千个唐代以来的摩崖石刻和岩画，内容包括佛像、经文、六字真言等，被誉为“石刻艺术博物馆”。[citation:2]', 2, 1822, '青海省玉树州玉树市巴塘乡', 32.98333333, 97.13333333, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', '勒巴沟岩画最早可追溯到唐代，是藏汉文化交融的见证。', '保护文物，请勿触摸石刻。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4495, '文成公主庙', '汉藏友谊的见证', '文成公主庙是一座藏式佛殿，供奉着大日如来佛及八大菩萨的巨型造像。相传唐贞观十五年（641年），文成公主进藏途经此地时，命人雕刻佛像，后建庙宇纪念。[citation:2]', 2, 1822, '青海省玉树州玉树市巴塘乡贝纳沟', 32.98333333, 97.13333333, 'https://dimg04.c-ctrip.com/images/0HJ1v12000rqyoaju3A61_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/EE/48/wKgED1vmOgqAWnQdABNSw2hPcWA12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-18:00', '全年', '文成公主庙始建于唐代，1300多年来香火不断，是汉藏民族团结的象征。', '尊重宗教信仰。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4496, '嘉那嘛呢经堂', '藏传佛教重要道场', '嘉那嘛呢经堂是玉树地震后重建的藏传佛教重要道场，与新寨玛尼堆相邻，供奉着第一世嘉那活佛的灵塔，是信众朝拜的圣地。[citation:2]', 2, 1822, '青海省玉树州玉树市新寨村', 33.01666667, 97.01666667, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-18:00', '全年', '嘉那活佛是藏传佛教近代史上的高僧，对新寨玛尼堆的扩建贡献巨大。', '尊重宗教信仰。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:39:21', '2026-03-20 22:59:48');
INSERT INTO `attraction` VALUES (4497, '嘉峪关关城', '天下第一雄关', '嘉峪关关城是明长城西端起点，始建于明洪武五年（1372年），由内城、外城、城壕三道防线组成，是长城沿线保存最完好、规模最壮观的古代军事关隘。', 2, 1828, '甘肃省嘉峪关市峪泉镇', 39.80166667, 98.21666667, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '08:30-18:00', '5-10月', '明代万里长城西端起点，古代“丝绸之路”交通要塞，距今600余年历史。', '城墙陡峭，游览时注意安全；防晒防暑。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4498, '麦积山石窟', '东方雕塑陈列馆', '麦积山石窟是中国四大石窟之一，始建于十六国后秦时期，现存洞窟221个，泥塑、石雕10632身，壁画1000余平方米，以其精美的泥塑艺术闻名世界。', 2, 1837, '甘肃省天水市麦积区麦积镇', 34.35000000, 106.00000000, 'https://dimg04.c-ctrip.com/images/0101z1200087du7dqD7C6.jpg', '[\"https://dimg04.c-ctrip.com/images/0101z1200087du7dqD7C6.jpg\", \"https://dimg04.c-ctrip.com/images/0102x1200087e6gy92DB3.jpg\", \"https://dimg04.c-ctrip.com/images/10061900000162e521475.jpg\", \"https://dimg04.c-ctrip.com/images/0104o12000ntad8h6C814.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4h12000ickppkd1D5D.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81s120008r5lmo14DAA_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:30-17:30', '4-10月', '麦积山石窟始凿于公元384年，跨越后秦至清代，是丝绸之路佛教艺术东传的见证。', '登窟需爬悬空栈道，恐高者量力而行；保护文物，请勿触摸。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4499, '张掖七彩丹霞旅游景区', '中国最美的丹霞地貌', '张掖七彩丹霞是中国北方干旱地区发育最典型的丹霞地貌，色彩斑斓、层理交错，被誉为“世界十大神奇地理奇观”之一。', 1, 1830, '甘肃省张掖市临泽县倪家营镇南台村', 38.91666667, 100.13333333, 'https://dimg04.c-ctrip.com/images/01062120008a8yvsk3FBE.jpg', '[\"https://dimg04.c-ctrip.com/images/01062120008a8yvsk3FBE.jpg\", \"https://dimg04.c-ctrip.com/images/01062120008a8yvsk3FBE.jpg\", \"https://dimg04.c-ctrip.com/images/01062120008a8yvsk3FBE.jpg\", \"https://dimg04.c-ctrip.com/images/01062120008a8yvsk3FBE.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '05:30-19:00', '6-9月', '丹霞地貌形成于600万年前，是红色砂岩经长期风化剥离和流水侵蚀形成的奇观。', '景区风大，注意防晒防风；保护地质遗迹，不得攀爬。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4500, '崆峒山风景名胜区', '道教第一山', '崆峒山是道教发源地之一，相传为黄帝问道广成子之处。景区集自然风光与宗教文化于一体，有“西来第一山”之誉。', 2, 1838, '甘肃省平凉市崆峒区崆峒镇', 35.55000000, 106.50000000, 'https://dimg04.c-ctrip.com/images/0103712000riawuksF0FF.jpg', '[\"https://dimg04.c-ctrip.com/images/0103712000riawuksF0FF.jpg\", \"https://dimg04.c-ctrip.com/images/0103712000riawuksF0FF.jpg\", \"https://dimg04.c-ctrip.com/images/0103712000riawuksF0FF.jpg\", \"https://dimg04.c-ctrip.com/images/0103712000riawuksF0FF.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '07:00-17:00', '4-10月', '轩辕黄帝曾登临崆峒山问道，秦皇汉武亦慕名登临，距今已有5000多年文化积淀。', '登山台阶较多，建议穿舒适运动鞋；雨天路滑注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4501, '鸣沙山·月牙泉', '沙漠第一泉', '鸣沙山因沙动成响而得名，月牙泉处于沙山环抱之中，形状酷似一弯新月，沙泉共生、泉不干涸的奇观被誉为“沙漠奇观”。', 1, 1829, '甘肃省酒泉市敦煌市月牙泉镇', 40.08333333, 94.66666667, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/93/2F/wKgED1uo6VqAVlQBABc3oZhyNpo76.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '05:00-20:30', '5-10月', '月牙泉已有2000多年历史，汉代即为游览胜地，是敦煌八景之一。', '沙漠地区紫外线强，注意防晒；骑骆驼时遵守安全规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4502, '官鹅沟旅游景区', '陇上江南第一沟', '官鹅沟集森林、草原、雪山、峡谷、湖泊于一体，有“小九寨”之称。景区由官珠沟、鹅嫚沟两大景区组成，瀑布飞泻、湖水碧绿。', 1, 1840, '甘肃省陇南市宕昌县官鹅沟', 34.05000000, 104.40000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:00', '6-10月', '官鹅沟曾是古氐羌民族的聚居地，沟内保留有羌寨建筑遗存。', '部分路段湿滑，注意防滑；海拔较高，注意高原反应。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4503, '炳灵寺世界文化遗产旅游区', '十万佛洲', '炳灵寺石窟始凿于西秦建弘元年（420年），现存窟龛216个，以第169窟的西秦壁画最为珍贵。景区还包括刘家峡水库和黄河三峡风光。', 2, 1841, '甘肃省临夏州永靖县刘家峡镇', 35.80000000, 103.25000000, 'https://dimg04.c-ctrip.com/images/0104412000h10nr295660.jpg', '[\"https://dimg04.c-ctrip.com/images/0104412000h10nr295660.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000h10nr295660.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000h10nr295660.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000h10nr295660.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:30-17:00', '4-10月', '炳灵寺藏语意为“十万佛洲”，是丝绸之路上的重要佛教石窟寺遗址。', '乘船游览注意安全；保护石窟文物，请勿拍照。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4504, '冶力关景区', '青藏之窗 甘南之眼', '冶力关以高山湖泊、原始森林、丹霞地貌、民俗风情著称，景区内有冶海、赤壁幽谷、亲昵沟等景点，是甘南生态旅游的标杆。', 1, 1842, '甘肃省甘南州临潭县冶力关镇', 34.95000000, 103.75000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '6-9月', '冶力关古为“茶马互市”的重要通道，历史上是藏汉文化交流的纽带。', '高原地区注意防晒防寒；游览时遵守景区规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4505, '兰州水墨丹霞旅游景区', '离城市最近的丹霞', '兰州水墨丹霞是中国距离城市主城区最近的丹霞地貌群，景区以红山湾地貌为主，兼有丹霞崖壁、孤峰、幽谷等奇特景观，色彩如泼墨山水画。', 1, 1833, '甘肃省兰州市永登县城关镇', 36.35000000, 103.35000000, 'https://dimg04.c-ctrip.com/images/0106i12000h1ae9qx8E3D.jpg', '[\"https://dimg04.c-ctrip.com/images/0106i12000h1ae9qx8E3D.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000h1ae9qx8E3D.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000h1ae9qx8E3D.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000h1ae9qx8E3D.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4506, '甘肃省博物馆', '丝路文明宝库', '甘肃省博物馆是国家一级博物馆，馆藏珍贵文物8万余件，尤以“铜奔马”、彩陶、丝绸之路文物著称，是了解甘肃历史文化的最佳窗口。', 2, 1833, '甘肃省兰州市七里河区西津西路3号', 36.06666667, 103.78333333, 'https://dimg04.c-ctrip.com/images/100r1f000001gopbzB1AD.jpg', '[\"https://dimg04.c-ctrip.com/images/100r1f000001gopbzB1AD.jpg\", \"https://dimg04.c-ctrip.com/images/100r1f000001gopbzB1AD.jpg\", \"https://dimg04.c-ctrip.com/images/100r1f000001gopbzB1AD.jpg\", \"https://dimg04.c-ctrip.com/images/100r1f000001gopbzB1AD.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00（周一闭馆）', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4507, '兴隆山自然保护区', '陇右第一名山', '兴隆山是国家自然保护区，分东、西两山，东山兴隆、西山栖云，森林覆盖率90%以上，是距离兰州最近的天然氧吧和避暑胜地。', 1, 1833, '甘肃省兰州市榆中县城关镇兴隆山村', 35.83333333, 104.06666667, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4508, '青城古镇', '黄河第一古镇', '青城古镇是甘肃省唯一的历史文化名镇，始建于宋代，现存明清古建筑群30余处，以高氏祠堂、青城书院最为著名。', 2, 1833, '甘肃省兰州市榆中县青城镇', 36.43333333, 104.35000000, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4509, '什川古梨园', '世界第一古梨园', '什川古梨园有近500年栽培历史，现存古梨树近万棵，树龄最长的达300年以上，春季梨花盛开时如雪似雾，被誉为“梨园之乡”。', 1, 1833, '甘肃省兰州市皋兰县什川镇', 36.20000000, 104.06666667, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '4月梨花季', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4510, '兰州水车博览园', '黄河水车文化', '兰州水车博览园复原了兰州古老的水车文化，园内水车轮转，展现“水车之都”的昔日风采，是了解黄河灌溉历史的窗口。', 2, 1833, '甘肃省兰州市城关区南滨河东路', 36.08333333, 103.83333333, 'https://youimg1.c-ctrip.com/target/1004190000015ov7r89FC.jpg', '[\"https://youimg1.c-ctrip.com/target/100w190000015vx3dD807.jpg\",\"https://youimg1.c-ctrip.com/target/100115000000yjrxoF755.jpg\",\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4511, '莫高窟', '人类艺术宝库', '莫高窟是世界文化遗产、世界艺术瑰宝，现存洞窟735个，壁画4.5万平方米，泥质彩塑2415尊，是世界上现存规模最大、内容最丰富的佛教艺术地。', 2, 1829, '甘肃省酒泉市敦煌市东南25公里处', 40.03333333, 94.80000000, 'https://dimg04.c-ctrip.com/images/100l1f000001gqg3sF82A.jpg', '[\"https://dimg04.c-ctrip.com/images/100l1f000001gqg3sF82A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1z12000icyhxm622F6.jpg\", \"https://dimg04.c-ctrip.com/images/27c6412000na9jnck75BB_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images//100e190000016o0ho6647.jpg\", \"https://dimg04.c-ctrip.com/images//1005190000016nrol7BE2.jpg\", \"https://dimg04.c-ctrip.com/images//1006190000016lvueC4AF.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 238.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4512, '敦煌雅丹国家地质公园', '魔鬼城', '敦煌雅丹地貌是典型的雅丹地貌群落，形态各异，夜晚风声呼啸如魔鬼怒吼，被誉为“魔鬼城”，是摄影爱好者的天堂。', 1, 1829, '甘肃省酒泉市敦煌市西北180公里处', 40.53333333, 93.00000000, 'https://p1-q.mafengwo.net/s12/M00/91/67/wKgED1uo6PSAWH2GABgrS3kcO1w55.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/65/D5/wKgED1umhteAYHXnABrdm6L1cvU87.jpeg\",\"https://dimg04.c-ctrip.com/images/3505170000010viu477A6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/350316000000yx8yp43CA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/92/5B/wKgED1uo6SmABbGIABgRlR7Opxs12.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/93/2F/wKgED1uo6VqAVlQBABc3oZhyNpo76.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '06:00-19:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4513, '阳关遗址', '西出阳关无故人', '阳关是中国古代陆路对外交通的咽喉之地，因王维“劝君更尽一杯酒，西出阳关无故人”而闻名于世，现存汉代烽燧遗址。', 2, 1829, '甘肃省酒泉市敦煌市阳关镇', 40.05000000, 94.00000000, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-19:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4514, '玉门关', '春风不度玉门关', '玉门关是汉代长城关隘，因西域输入玉石时取道于此而得名，现存小方盘城遗址，是丝绸之路的重要关隘。', 2, 1829, '甘肃省酒泉市敦煌市西北90公里处', 40.35000000, 93.86666667, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 1, 0, 0, NULL, 40.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4515, '金塔沙漠胡杨林', '金色童话世界', '金塔胡杨林是三北防护林体系的重要组成部分，每年10月胡杨树叶金黄，倒映在金波湖中，美不胜收。', 1, 1829, '甘肃省酒泉市金塔县城西', 39.98333333, 98.88333333, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-19:00', '10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4516, '酒泉卫星发射中心', '中国航天城', '酒泉卫星发射中心是中国创建最早、规模最大的综合性航天发射中心，成功发射了第一颗人造卫星、第一艘载人飞船等。', 5, 1829, '甘肃省酒泉市金塔县东北', 40.96666667, 100.28333333, 'https://dimg04.c-ctrip.com/images/0HJ1v12000rqyoaju3A61_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0102b1200095zcu8wCBEA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 1, 0, 0, NULL, 150.00, NULL, '预约参观', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4517, '张掖大佛寺', '西夏皇家寺院', '大佛寺始建于西夏永安元年（1098年），因寺内供奉一尊亚洲最大的室内泥塑卧佛而得名，是西夏佛教艺术的重要遗存。', 2, 1830, '甘肃省张掖市甘州区民主西街', 38.93333333, 100.45000000, 'https://dimg04.c-ctrip.com/images/010691200083dufi5DBF3.jpg', '[\"https://dimg04.c-ctrip.com/images/010691200083dufi5DBF3.jpg\", \"https://dimg04.c-ctrip.com/images/010691200083dufi5DBF3.jpg\", \"https://dimg04.c-ctrip.com/images/010691200083dufi5DBF3.jpg\", \"https://dimg04.c-ctrip.com/images/010691200083dufi5DBF3.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4518, '平山湖大峡谷', '比肩科罗拉多', '平山湖大峡谷是张掖丹霞地貌的重要组成部分，峡谷幽深、峰林奇特，集自然奇观与峡谷探险于一体，被誉为“活的地质演变教科书”。', 1, 1830, '甘肃省张掖市甘州区平山湖乡', 38.98333333, 100.80000000, 'https://dimg04.c-ctrip.com/images/1lo4m12000e1ekrutC4C5.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo4m12000e1ekrutC4C5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4m12000e1ekrutC4C5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4m12000e1ekrutC4C5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4m12000e1ekrutC4C5.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4519, '冰沟丹霞', '窗棂状宫殿式丹霞', '冰沟丹霞以“雄险神奇”著称，是窗棂状宫殿式丹霞地貌的命名地，景区内怪石嶙峋，形态万千，有“赤壁千仞”之称。', 1, 1830, '甘肃省张掖市肃南县康乐镇', 38.90000000, 100.13333333, 'https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg', '[\"https://p1-q.mafengwo.net/s12/M00/EE/48/wKgED1vmOgqAWnQdABNSw2hPcWA12.jpeg\",\"https://youimg1.c-ctrip.com/target/100l0h0000008tkbi9765.jpg\",\"https://p1-q.mafengwo.net/s11/M00/F4/F7/wKgBEFtHUFKAN6P2AAqPTQr9ZP493.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4520, '马蹄寺石窟群', '藏传佛教艺术宝库', '马蹄寺是集石窟艺术、祁连风光、裕固风情于一体的旅游区，始建于北凉，现存洞窟70余个，以“三十三天”石窟最为著名。', 2, 1830, '甘肃省张掖市肃南县马蹄藏族乡', 38.28333333, 100.51666667, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 74.00, NULL, '08:00-18:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4521, '山丹军马场', '亚洲最大军马场', '山丹军马场由霍去病始创于公元前121年，是世界上历史最悠久的军马场之一，祁连山冷龙岭北麓的大马营草原上，万马奔腾的场面震撼人心。', 3, 1830, '甘肃省张掖市山丹县大马营镇', 38.26666667, 101.06666667, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '7-8月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4522, '雷台汉墓', '铜奔马出土地', '雷台汉墓是东汉末年（公元186-219年）的大型砖室墓，1969年出土了举世闻名的铜奔马（马踏飞燕）和99件铜车马仪仗俑。', 2, 1832, '甘肃省武威市凉州区北关中路', 37.93333333, 102.63333333, 'https://dimg04.c-ctrip.com/images/0104m12000o9o755010E2_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104y1200086wi2i1FC0E_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0101g120009egz5pd5DDE_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010281200086v4y395BA7_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0100n1200086v4y4rC5C6_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104o12000ros9jny8D3C_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4523, '武威文庙', '陇右学宫之冠', '武威文庙始建于明正统二年（1437年），是西北地区规模最大、保存最完整的孔庙，被誉为“陇右学宫之冠”。', 2, 1832, '甘肃省武威市凉州区崇文街', 37.91666667, 102.63333333, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4524, '天梯山石窟', '石窟鼻祖', '天梯山石窟始建于东晋十六国北凉时期，被誉为“石窟鼻祖”，对云冈石窟、龙门石窟产生过重要影响。', 2, 1832, '甘肃省武威市凉州区张义镇', 37.65000000, 102.56666667, 'https://dimg04.c-ctrip.com/images/0101v120008grcfkl6268.jpg', '[\"https://dimg04.c-ctrip.com/images/0101v120008grcfkl6268.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ2j12000rvezc4h3302.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4v12000iclxcm63CD8.jpg\", \"https://dimg04.c-ctrip.com/images/0Z869120008r28pjnDCBB_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh4f12000gcgekhz6C7B.jpg\", \"https://dimg04.c-ctrip.com/images/1mh1v12000gcgnmnb1751.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4525, '冰沟河生态文化旅游区', '祁连秘境', '冰沟河是祁连山腹地的天然峡谷，集雪山、森林、草原、河流于一体，是休闲避暑、生态观光的理想之地。', 1, 1832, '甘肃省武威市天祝县祁连镇', 37.20000000, 102.41666667, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4526, '伏羲庙', '中华人文始祖祭祀地', '伏羲庙是中国规模最大、保存最完整的纪念伏羲氏的明代建筑群，每年夏至举办公祭伏羲大典。', 2, 1837, '甘肃省天水市秦州区伏羲路', 34.58333333, 105.71666667, 'https://dimg04.c-ctrip.com/images/10011f000001h38g6436B.jpg', '[\"https://dimg04.c-ctrip.com/images/10011f000001h38g6436B.jpg\", \"https://dimg04.c-ctrip.com/images/100w1900000167s6n6BD8.jpg\", \"https://dimg04.c-ctrip.com/images/100p1900000160vqgC6A1.jpg\", \"https://dimg04.c-ctrip.com/images/100g1900000162fvaCD8C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0912000icl7d1k41AA.jpg\", \"https://dimg04.c-ctrip.com/images/Z80u0v000000jkgog100C_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 20.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4527, '南郭寺', '杜甫寓居地', '南郭寺始建于南北朝时期，唐代诗人杜甫曾流寓于此，写下“山头南郭寺，水号北流泉”等诗篇。', 2, 1837, '甘肃省天水市秦州区南郭路', 34.56666667, 105.73333333, 'https://dimg04.c-ctrip.com/images/0105712000lxl69bcDF9B_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0105812000lxl6qb78A9F_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0ww4i120009laucj04758_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0ww5z120009laujp59439_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/3C/4C/wKgBEFuCkDiAUtXpAAV7fVUJQ8s23.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 20.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4528, '玉泉观', '陇上第一名观', '玉泉观始建于唐代，因观内有玉泉而得名，是道教全真派在西北的重要宫观，建筑依山而建，错落有致。', 2, 1837, '甘肃省天水市秦州区玉泉路', 34.58333333, 105.71666667, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 20.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4529, '大像山石窟', '甘谷大佛', '大像山石窟因山体雕刻的一尊高23.3米的唐代大佛而得名，是陇东南重要的佛教石窟寺。', 2, 1837, '甘肃省天水市甘谷县大像山镇', 34.73333333, 105.33333333, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4530, '扎尕那', '上帝的伊甸园', '扎尕那是一座天然石城，山峰、峡谷、森林、村寨、田园相映成趣，是甘南最著名的网红打卡地，被《国家地理》评为“十大非著名山峰”之一。', 1, 1842, '甘肃省甘南州迭部县益哇镇', 34.08333333, 103.23333333, 'https://dimg04.c-ctrip.com/images/0100i12000hr9pxo99A7F.jpg', '[\"https://dimg04.c-ctrip.com/images/0100i12000hr9pxo99A7F.jpg\", \"https://dimg04.c-ctrip.com/images/0102r12000ey3tq3h3453.jpg\", \"https://dimg04.c-ctrip.com/images/0100t12000h6u4frzDEFE.jpg\", \"https://dimg04.c-ctrip.com/images/0102312000iztdhnu2196.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5m12000ickhddm63F9.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M04/87/8D/CghzgVWwshKAZXy6AENz9miXm8I514.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4531, '拉卜楞寺', '世界藏学府', '拉卜楞寺是藏传佛教格鲁派六大宗主寺之一，保留有全国最好的藏传佛教教学体系，拥有六大扎仓（学院），被誉为“世界藏学府”。', 2, 1842, '甘肃省甘南州夏河县拉卜楞镇', 35.20000000, 102.51666667, 'https://dimg04.c-ctrip.com/images/010011200082mcq3z8777.jpg', '[\"https://dimg04.c-ctrip.com/images/010011200082mcq3z8777.jpg\", \"https://dimg04.c-ctrip.com/images/010011200082mcq3z8777.jpg\", \"https://dimg04.c-ctrip.com/images/010011200082mcq3z8777.jpg\", \"https://dimg04.c-ctrip.com/images/010011200082mcq3z8777.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4532, '郎木寺', '东方小瑞士', '郎木寺是甘、青、川三省交界处的著名寺院，实际上是一个镇名，寺院分为甘肃寺和四川寺两部分，白龙江穿镇而过，风光旖旎。', 2, 1842, '甘肃省甘南州碌曲县郎木寺镇', 34.08333333, 102.63333333, 'https://dimg04.c-ctrip.com/images/0100f12000myc7xp11ECB.jpg', '[\"https://dimg04.c-ctrip.com/images/0100f12000myc7xp11ECB.jpg\", \"https://dimg04.c-ctrip.com/images/0104t12000h0aj4bfBAEE.jpg\", \"https://dimg04.c-ctrip.com/images/0107312000myc7nv02D7B.jpg\", \"https://dimg04.c-ctrip.com/images/0102e12000myc7t0p0515.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1p12000icp97ejAA61.jpg\", \"https://dimg04.c-ctrip.com/images/1h64912000icaeujwA913_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4533, '尕海湖', '高原明珠', '尕海湖是甘南地区最大的淡水湖，是候鸟迁徙的重要栖息地，湖面如镜，倒映着蓝天白云和远山，被誉为“高原明珠”。', 1, 1842, '甘肃省甘南州碌曲县尕海镇', 34.25000000, 102.35000000, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/E0/2C/wKgED1uOr1OAYEkgABLdm0wqGxo46.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4534, '黄河第一弯', '九曲黄河', '黄河从巴颜喀拉山发源后，在甘南玛曲县形成了壮观的“天下黄河第一弯”，河道蜿蜒，水草丰美。', 1, 1842, '甘肃省甘南州玛曲县黄河大桥西侧', 33.98333333, 102.08333333, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4535, '万象洞', '地下艺术宫殿', '万象洞形成于2.5亿年前，是中国西北地区发现的最大溶洞，洞内钟乳石千姿百态，有“地下艺术宫殿”之称。', 1, 1840, '甘肃省陇南市武都区汉王镇', 33.31666667, 104.98333333, 'https://dimg04.c-ctrip.com/images/0100b12000md9aa1r2CBF.jpg', '[\"https://dimg04.c-ctrip.com/images/0100b12000md9aa1r2CBF.jpg\", \"https://dimg04.c-ctrip.com/images/0102412000md99z9zF152.jpg\", \"https://dimg04.c-ctrip.com/images/0100c12000md9a2w8A937.jpg\", \"https://dimg04.c-ctrip.com/images/0104612000md99s7kC688.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0z12000icph9gg1BF4.jpg\", \"https://dimg04.c-ctrip.com/images/1h63b120009ma94vc5C68_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4536, '阳坝梅园沟', '陇上江南', '阳坝是陇南康县的国家4A级景区，森林覆盖率高达70%以上，溪流潺潺，茶园青青，是甘肃唯一具有亚热带风光的景区。', 1, 1840, '甘肃省陇南市康县阳坝镇', 33.11666667, 105.60000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4537, '文县天池', '高山明珠', '文县天池是甘肃著名的高山湖泊，湖面海拔1728米，湖形似葫芦，四周群山环绕，景色秀丽。', 1, 1840, '甘肃省陇南市文县天池镇', 33.06666667, 104.81666667, 'https://dimg04.c-ctrip.com/images/100u1f000001gq8hkA627_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M0B/CB/8D/CghzflWw676AD_AGAA5GmjUJvLk510_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M09/7E/F5/CghzfFWw67aAdd_HABP_OnUCsmo760_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1g000001h76a6DB63_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/D9/E0/wKgED1uOrtSAdQEcABQTcZ_BGIM40.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/E0/2C/wKgED1uOr1OAYEkgABLdm0wqGxo46.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4538, '云屏三峡', '秦岭深处的秘境', '云屏三峡是秦岭山脉中的峡谷群，集险、奇、秀于一体，秋季层林尽染，如诗如画。', 1, 1840, '甘肃省陇南市两当县云屏镇', 34.03333333, 106.51666667, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4539, '云崖寺', '陇上明珠', '云崖寺是国家森林公园，以丹霞地貌、石窟艺术、森林生态著称，有“陇上明珠”之誉。', 2, 1838, '甘肃省平凉市庄浪县韩店镇', 35.16666667, 106.11666667, 'https://p1-q.mafengwo.net/s13/M00/25/C3/wKgEaVzPC1-AJj1NAAYw05Yc5KY00.jpeg', '[\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2GAU6IqAAj2Zep88Hc27.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAIIH7AAiBg8wDc5k62.jpeg\",\"https://p1-q.mafengwo.net/s13/M00/25/C4/wKgEaVzPC2KAC7L0AAoFNoSdeNo18.jpeg\",\"https://dimg04.c-ctrip.com/images/0103y12000ju4l86c5C31_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100w1f0000014qadgD62C_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4540, '龙泉寺', '古柏龙蟠', '龙泉寺始建于元代，寺内有一棵千年古柏，枝干如龙蟠，泉水淙淙，是平凉著名的佛教寺院。', 2, 1838, '甘肃省平凉市崇信县城北', 35.30000000, 107.03333333, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5n12000ier3zu69902.jpg\", \"https://dimg04.c-ctrip.com/images/010401200092mbd0zE91E.jpg\", \"https://dimg04.c-ctrip.com/images/0106612000j1z73xuE83E.jpg\", \"https://dimg04.c-ctrip.com/images/10071d000001f1xw9D9DE.png\", \"https://dimg04.c-ctrip.com/images/0102c12000f6ps299EB0F.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4541, '悬壁长城', '长城倒挂', '悬壁长城修筑于嘉峪关关城北面的黑山山腰，因长城依山势而建，如倒悬空中而得名，是嘉峪关防御体系的重要组成部分。', 2, 1828, '甘肃省嘉峪关市峪泉镇黄草营村', 39.85000000, 98.20000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 21.00, NULL, '08:30-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4542, '长城第一墩', '万里长城第一墩', '长城第一墩是明长城西端起点墩台，与山海关渤海入海石城“老龙头”遥相呼应，共同构筑万里长城的完整防御体系。', 2, 1828, '甘肃省嘉峪关市讨赖河畔', 39.78333333, 98.23333333, 'https://p1-q.mafengwo.net/s8/M00/0E/88/wKgBpVXBbt-AF71uAAuVfV52n0A745.png', '[\"https://p1-q.mafengwo.net/s12/M00/CB/79/wKgED1uTiayAU16wAD1ZAPq1Lj406.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/7F/9F/wKgBZ1kpq6mAfs20ABGbWGm4fQ495.jpeg\",\"https://dimg04.c-ctrip.com/images/100u12000000smt50FC14_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100y0q000000rxmdm6E97_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 21.00, NULL, '08:30-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4543, '嘉峪关方特欢乐世界', '丝路主题乐园', '嘉峪关方特是西北地区规模最大、科技含量最高的主题乐园，以丝路文化、神话传说为主题，是亲子游的热门选择。', 3, 1828, '甘肃省嘉峪关市南市区方特大道', 39.75000000, 98.26666667, 'https://dimg04.c-ctrip.com/images/0HJ1v12000rqyoaju3A61_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0102b1200095zcu8wCBEA_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s11/M00/0B/74/wKgBEFtcTvKAPs4bAECzTXp36e400.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 260.00, NULL, '10:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4544, '黄河石林', '中华自然奇观', '黄河石林生成于210万年前，石林与黄河相依，规模宏大，景象万千，是《神话》等影视剧取景地。', 1, 1835, '甘肃省白银市景泰县中泉镇龙湾村', 37.01666667, 104.03333333, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4545, '会宁会师旧址', '红军三大主力会师地', '会宁是红军长征胜利会师地，会师旧址包括会师楼、会师塔、纪念馆等，是全国重点文物保护单位、爱国主义教育基地。', 5, 1835, '甘肃省白银市会宁县会师镇', 35.68333333, 105.05000000, 'https://dimg04.c-ctrip.com/images/0HJ1v12000rqyoaju3A61_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0104k12000hxmfgw6C57B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010011200095zco2o35D3_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0104y1200095zcu8r3B9B_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/0102b1200095zcu8wCBEA_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4546, '八坊十三巷', '临夏城市名片', '八坊十三巷是临夏市的城市民俗街区，融合了回族砖雕、汉族木刻、藏族彩绘，被誉为“西北民族文化建筑活化石”。', 2, 1841, '甘肃省临夏州临夏市八坊街道', 35.60000000, 103.20000000, 'https://dimg04.c-ctrip.com/images/0106f12000reoiw9j8AB4.jpg', '[\"https://dimg04.c-ctrip.com/images/0106f12000reoiw9j8AB4.jpg\", \"https://dimg04.c-ctrip.com/images/0106f12000reoiw9j8AB4.jpg\", \"https://dimg04.c-ctrip.com/images/0106f12000reoiw9j8AB4.jpg\", \"https://dimg04.c-ctrip.com/images/0106f12000reoiw9j8AB4.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4547, '松鸣岩', '河州八景之一', '松鸣岩是国家级森林公园，因山风吹过松林发出声响而得名，是临夏地区著名的自然风景区。', 1, 1841, '甘肃省临夏州和政县松鸣镇', 35.35000000, 103.40000000, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4548, '渭河源景区', '渭河发源地', '渭河源是黄河最大支流渭河的发源地，景区内泉瀑众多，植被茂密，是寻根溯源、生态观光的好去处。', 1, 1836, '甘肃省定西市渭源县五竹镇', 35.10000000, 104.20000000, 'https://dimg04.c-ctrip.com/images/0104r1200086tuwsvB6D0_W_1920_1080.jpg_.webp', '[\"https://dimg04.c-ctrip.com/images/0100112000816i2bx2223_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/010691200080yktja5D21_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100a1e000001f69474C44_W_1920_1080.jpg_.webp\",\"https://p1-q.mafengwo.net/s12/M00/C0/73/wKgED1uvnnGAbeCYABLcDxs9rrw07.jpeg\",\"https://p1-q.mafengwo.net/s12/M00/A6/9C/wKgED1uL_MWABg9MABMv2kU96lU67.jpeg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4549, '贵清山/遮阳山', '陇中仙境', '贵清山、遮阳山是定西的两个国家森林公园，以奇峰、秀水、幽谷、古刹著称，有“陇中仙境”之誉。', 1, 1836, '甘肃省定西市漳县', 34.83333333, 104.46666667, 'https://p1-q.mafengwo.net/s10/M00/6C/A8/wKgBZ1m0xvCAE4OmADzzT2p3XCA78.jpeg', '[\"https://p1-q.mafengwo.net/s10/M00/45/A1/wKgBZ1jOJl2ATVViABPn_XOve3g34.jpeg\",\"https://p1-q.mafengwo.net/s10/M00/45/69/wKgBZ1jOJgyAEWXgABLbidwQjL877.jpeg\",\"https://dimg04.c-ctrip.com/images/0104o12000ja8cta1433A_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100j0u000000j2ke391F9_W_1920_1080.jpg_.webp\",\"https://dimg04.c-ctrip.com/images/100t0u000000j33m43C45_W_1920_1080.jpg_.webp\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-20 23:05:51');
INSERT INTO `attraction` VALUES (4550, '紫金花城', '戈壁花海', '紫金花城是金昌市的城市花园，种植有大面积的薰衣草、马鞭草等花卉，夏季花开时节，紫金花海如梦如幻。', 4, 1831, '甘肃省金昌市金川区', 38.51666667, 102.18333333, '/images/attractions/zijin.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-8月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-19 17:50:39');
INSERT INTO `attraction` VALUES (4551, '火星1号基地', '航天科普基地', '火星1号基地是中国首个火星模拟生存基地，依托金昌独特的地形地貌，打造航天科普、火星探索体验的主题景区。', 3, 1831, '甘肃省金昌市金川区宁远堡镇', 38.50000000, 102.20000000, '/images/attractions/mars-base.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-19 17:50:39');
INSERT INTO `attraction` VALUES (4552, '周祖陵景区', '农耕文化发源地', '周祖陵相传是周先祖不窋的陵寝，景区内周祖大殿、岐伯大殿等建筑群气势恢宏，是庆阳文化旅游的标志。', 2, 1839, '甘肃省庆阳市庆城县庆城镇', 36.01666667, 107.88333333, 'https://dimg04.c-ctrip.com/images/0100m12000niafkvfD626.jpg', '[\"https://dimg04.c-ctrip.com/images/0100m12000niafkvfD626.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000niafkvfD626.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000niafkvfD626.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000niafkvfD626.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4553, '南梁红色旅游景区', '红色南梁', '南梁是陕甘边革命根据地的中心，刘志丹、谢子长、习仲勋等在此创建了陕甘边区苏维埃政府，是红军长征的落脚点。', 5, 1839, '甘肃省庆阳市华池县南梁镇', 36.36666667, 108.06666667, 'https://dimg04.c-ctrip.com/images/0HJ2412000g920qz5C4C7.jpg', '[\"https://dimg04.c-ctrip.com/images/0HJ2412000g920qz5C4C7.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ2412000g920qz5C4C7.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ2412000g920qz5C4C7.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ2412000g920qz5C4C7.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:50:39', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4554, '秦始皇帝陵博物院', '世界第八大奇迹', '秦始皇兵马俑博物馆是中国最大的古代军事博物馆，已发现三个俑坑，总面积近2万平方米，出土陶俑、陶马8000余件。每个兵马俑面容、发髻、服饰各异，被誉为“世界第八大奇迹”。', 2, 1843, '陕西省西安市临潼区秦陵北路', 34.38527778, 109.27416667, 'https://dimg04.c-ctrip.com/images/0104012000f6rbl4996B9.jpg', '[\"https://dimg04.c-ctrip.com/images/0104012000f6rbl4996B9.jpg\", \"https://dimg04.c-ctrip.com/images/0104012000f6rbl4996B9.jpg\", \"https://dimg04.c-ctrip.com/images/0104012000f6rbl4996B9.jpg\", \"https://dimg04.c-ctrip.com/images/0104012000f6rbl4996B9.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:30-17:00', '全年', '1974年由当地农民打井时发现，1979年正式开放，1987年被列入世界文化遗产。', '景区面积大，建议乘坐电瓶车；注意防晒防暑。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4555, '华清宫文化旅游景区', '唐玄宗与杨贵妃爱情发生地', '华清宫是唐代帝王游幸的别宫，背山面渭，倚骊峰山势而筑。景区包括唐御汤遗址博物馆、西安事变旧址五间厅、九龙湖与芙蓉湖风景区等，是唐代皇家温泉沐浴文化的代表。', 2, 1843, '陕西省西安市临潼区华清路38号', 34.36527778, 109.20527778, '/images/attractions/huaqinggong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '07:30-18:00', '3-11月', '始建于西周，唐代达到鼎盛，唐玄宗每年携杨贵妃来此过冬沐浴。1936年西安事变发生于此。', '温泉泡池注意安全；登山注意台阶。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4556, '大雁塔·大唐芙蓉园景区', '盛唐文化象征', '大雁塔是唐代玄奘法师为保存佛经而建，现存七层，通高64.5米，是西安标志性建筑。大唐芙蓉园是中国第一个全方位展示盛唐风貌的大型皇家园林式文化主题公园。', 2, 1843, '陕西省西安市雁塔区芙蓉西路', 34.21972222, 108.95972222, '/images/attractions/dayanta.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '09:00-22:00', '全年', '大雁塔始建于唐永徽三年（652年），是玄奘法师译经藏经之地。大唐芙蓉园建在唐代芙蓉园遗址以北。', '登塔注意安全；节假日人流密集。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4557, '西安城墙·碑林历史文化景区', '中国现存最完整古城墙', '西安城墙是中国现存规模最大、保存最完整的古代城垣，周长13.74公里。碑林是收藏中国古代碑石时间最早、名碑最多的一座文化艺术宝库。', 2, 1843, '陕西省西安市碑林区南大街', 34.25527778, 108.94222222, '/images/attractions/chengqiang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 54.00, NULL, '08:00-22:00', '全年', '西安城墙始建于隋代，明代扩建。碑林始建于北宋，收藏汉代至清代碑石4000余方。', '骑自行车游览注意安全；保管好个人物品。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4558, '大明宫国家遗址公园', '千宫之宫', '大明宫是唐代的政治中心和国家象征，被誉为“千宫之宫”，其面积相当于3个凡尔赛宫、4.5个故宫。遗址公园展示了含元殿、麟德殿等遗址。', 2, 1843, '陕西省西安市新城区自强东路', 34.29555556, 108.95972222, '/images/attractions/daminggong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-18:00', '全年', '大明宫始建于唐贞观八年（634年），是唐太宗为父亲李渊修建的夏宫。是唐朝17位皇帝处理朝政的地方。', '园区面积大，建议乘坐观光车；注意防晒。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4559, '陕西历史博物馆', '古都明珠 华夏宝库', '陕西历史博物馆是中国第一座大型现代化国家级博物馆，馆藏文物171万余件，其中一级文物762件，国宝级文物18件，是中国博物馆的标杆。', 2, 1843, '陕西省西安市雁塔区小寨东路91号', 34.22555556, 108.94777778, 'https://dimg04.c-ctrip.com/images/0103k120006t7ckgl8C33.jpg', '[\"https://dimg04.c-ctrip.com/images/0103k120006t7ckgl8C33.jpg\", \"https://dimg04.c-ctrip.com/images/0103k120006t7ckgl8C33.jpg\", \"https://dimg04.c-ctrip.com/images/0103k120006t7ckgl8C33.jpg\", \"https://dimg04.c-ctrip.com/images/0103k120006t7ckgl8C33.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:30（周一闭馆）', '全年', '博物馆建筑由张锦秋院士设计，以唐代建筑风格为主，馆藏涵盖从史前到明清的历史文物。', '需提前预约；文明参观，请勿拍照闪光灯。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4560, '西安钟楼', '古城中心地标', '西安钟楼是中国现存形制最大、保存最完整的一座钟楼，始建于明洪武十七年（1384年），位于西安市中心，是西安的地标性建筑。', 2, 1843, '陕西省西安市碑林区东、西、南、北四条大街交汇处', 34.26138889, 108.94222222, 'https://dimg04.c-ctrip.com/images/100e11000000qbyl6C011.jpg', '[\"https://dimg04.c-ctrip.com/images/100e11000000qbyl6C011.jpg\", \"https://dimg04.c-ctrip.com/images/100e11000000qbyl6C011.jpg\", \"https://dimg04.c-ctrip.com/images/100e11000000qbyl6C011.jpg\", \"https://dimg04.c-ctrip.com/images/100e11000000qbyl6C011.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', '钟楼最初位于广济街口，明万历十年（1582年）整体迁移至现址，体现了中国古代建筑技术的高超水平。', '登楼注意台阶；保管好个人物品。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4561, '大唐不夜城', '现代唐人街', '大唐不夜城是集购物、餐饮、娱乐、休闲、旅游、商务为一体的一站式消费天堂，以盛唐文化为主题，夜晚灯火辉煌，是西安最热门的网红打卡地。', 3, 1843, '陕西省西安市雁塔区慈恩路46号', 34.21972222, 108.95972222, 'https://dimg04.c-ctrip.com/images/100c1f000001gsxqd9E36.jpg', '[\"https://dimg04.c-ctrip.com/images/100c1f000001gsxqd9E36.jpg\", \"https://dimg04.c-ctrip.com/images/100c1f000001gsxqd9E36.jpg\", \"https://dimg04.c-ctrip.com/images/100c1f000001gsxqd9E36.jpg\", \"https://dimg04.c-ctrip.com/images/100c1f000001gsxqd9E36.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '大唐不夜城依托大雁塔，打造了“一轴·两市·三核·四区·五内街”的格局，再现大唐盛世景象。', '节假日人流密集，注意防盗；保管好儿童。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4562, '西安半坡博物馆', '黄河流域母系氏族村落遗址', '半坡博物馆是中国第一座史前遗址博物馆，展示了距今6000多年的半坡人聚落遗址，包括房屋、窖穴、墓葬等遗迹，是了解仰韶文化的重要窗口。', 2, 1843, '陕西省西安市灞桥区半坡路155号', 34.27277778, 109.04777778, '/images/attractions/banpo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '08:00-17:30', '全年', '半坡遗址发现于1953年，1958年建成博物馆，是首批全国重点文物保护单位。', '文明参观，保护遗址。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4563, '乾陵景区', '唐高宗与武则天合葬墓', '乾陵是唐高宗李治与女皇武则天的合葬墓，是唐十八陵中主墓保存最完好的一座，也是唯一一座夫妻皇帝合葬陵。陵园有内外两重城垣，神道两侧石刻精美绝伦。', 2, 1846, '陕西省咸阳市乾县城北6公里梁山上', 34.57444444, 108.21333333, 'https://dimg04.c-ctrip.com/images/0104d12000o7lffdo9DF3.jpg', '[\"https://dimg04.c-ctrip.com/images/0104d12000o7lffdo9DF3.jpg\", \"https://dimg04.c-ctrip.com/images/0104d12000o7lffdo9DF3.jpg\", \"https://dimg04.c-ctrip.com/images/0104d12000o7lffdo9DF3.jpg\", \"https://dimg04.c-ctrip.com/images/0104d12000o7lffdo9DF3.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-18:00', '全年', '乾陵建于公元684年，历经23年建成。据文献记载和考古证实，乾陵是目前唯一未被盗掘的唐代帝陵。', '登山台阶较多，建议穿舒适运动鞋；注意防晒。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4564, '茂陵', '汉武帝刘彻陵墓', '茂陵是汉武帝刘彻的陵墓，是汉代帝王陵墓中规模最大、修建时间最长、陪葬品最丰富的一座，有“东方金字塔”之誉。陪葬墓有卫青、霍去病、霍光等。', 2, 1846, '陕西省咸阳市兴平市南位镇', 34.33888889, 108.56972222, '/images/attractions/maoling.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '08:00-18:00', '全年', '茂陵始建于建元二年（前139年），历时53年建成。霍去病墓前的马踏匈奴石刻是中国现存最早的石像生。', '陵区面积大，注意防晒；保护石刻文物。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4565, '昭陵', '唐太宗李世民陵墓', '昭陵是唐太宗李世民的陵墓，首开唐代“因山为陵”之先例，陵园规模宏大，陪葬墓达180余座，是中国历代帝王陵园中规模最大、陪葬墓最多的皇陵。', 2, 1846, '陕西省咸阳市礼泉县烟霞镇九嵕山', 34.63888889, 108.48388889, 'https://dimg04.c-ctrip.com/images/01039120008our9po2CC0.jpg', '[\"https://dimg04.c-ctrip.com/images/01039120008our9po2CC0.jpg\", \"https://dimg04.c-ctrip.com/images/01074120008our42n08D0.jpg\", \"https://dimg04.c-ctrip.com/images/01044120008our3arB11B.jpg\", \"https://dimg04.c-ctrip.com/images/0101s120008our42hDD3A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4g12000icog1x80242.jpg\", \"https://dimg04.c-ctrip.com/images/0Z83f120008aela0w8145_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', '昭陵始建于贞观十年（636年），历时13年建成。著名的“昭陵六骏”浮雕原陈列于此，现藏于西安碑林博物馆。', '登山道路较陡，注意安全；山区天气多变。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4566, '汉阳陵', '汉景帝刘启与皇后合葬陵', '汉阳陵是汉景帝刘启与皇后王氏的合葬陵园，陵区有外藏坑遗址博物馆，游客可透过玻璃地板直接观看考古发掘现场，体验独特的参观方式。', 2, 1846, '陕西省咸阳市渭城区正阳镇', 34.44333333, 108.93972222, '/images/attractions/hanyangling.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:30-18:00', '全年', '汉阳陵始建于公元前153年，历时28年建成。陵区内有陪葬坑90余座，出土大量陶俑、动物塑像等珍贵文物。', '地宫内光线较暗，注意脚下安全；保护文物。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4567, '法门文化景区', '世界佛教圣地', '法门寺因供奉释迦牟尼佛指骨舍利而闻名世界，寺内建有148米高的合十舍利塔。地宫出土了数千件大唐国宝重器，是继半坡、秦兵马俑之后中国又一重大考古发现。', 2, 1845, '陕西省宝鸡市扶风县法门镇', 34.43944444, 107.90166667, 'https://dimg04.c-ctrip.com/images/010021200087cva5o911A.jpg', '[\"https://dimg04.c-ctrip.com/images/010021200087cva5o911A.jpg\", \"https://dimg04.c-ctrip.com/images/010021200087cva5o911A.jpg\", \"https://dimg04.c-ctrip.com/images/010021200087cva5o911A.jpg\", \"https://dimg04.c-ctrip.com/images/010021200087cva5o911A.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4568, '太白山旅游景区', '秦岭第一高峰', '太白山是秦岭山脉的主峰，海拔3771.2米，以“高、寒、险、奇、秀”闻名。景区有高山湖泊、冰川遗迹、原始森林等景观，是登山爱好者的天堂。', 1, 1845, '陕西省宝鸡市眉县汤峪镇', 34.01583333, 107.81527778, '/images/attractions/taibaishan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4569, '中华石鼓园·宝鸡青铜器博物院', '青铜器之乡', '宝鸡青铜器博物院是中国最大的青铜器专题博物馆，馆藏何尊、逨盘等国宝级青铜器。中华石鼓园因出土唐代石鼓而得名。', 2, 1845, '陕西省宝鸡市渭滨区滨河大道', 34.36027778, 107.14944444, '/images/attractions/baoji-bronze.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00（周一闭馆）', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4570, '周公庙风景名胜区', '纪念周公姬旦的庙宇', '周公庙是为纪念西周著名政治家周公姬旦而建，始建于唐代，庙内有周公、召公、太公等殿宇，古柏参天，是了解周文化的重要场所。', 2, 1845, '陕西省宝鸡市岐山县凤鸣镇', 34.44527778, 107.62166667, 'https://dimg04.c-ctrip.com/images/100f0w000000kew2m2502.jpg', '[\"https://dimg04.c-ctrip.com/images/100f0w000000kew2m2502.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0y12000icpk97h32FC.jpg\", \"https://dimg04.c-ctrip.com/images/0Z869120008r28pjnDCBB_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh6x12000g61qjq4E8EA.jpg\", \"https://dimg04.c-ctrip.com/images/1mh0x12000g623abt09AB.jpg\", \"https://dimg04.c-ctrip.com/images/1mh4q12000g61n9gs91AD.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4571, '华山景区', '奇险天下第一山', '华山是中国五岳之一，以险峻著称。有东、西、南、北、中五峰，长空栈道、鹞子翻身等景点惊险刺激。是道教圣地，也是登山爱好者的挑战目标。', 1, 1847, '陕西省渭南市华阴市集灵路', 34.53222222, 110.08027778, 'https://dimg04.c-ctrip.com/images/0106x12000ra20bqwE935.jpg', '[\"https://dimg04.c-ctrip.com/images/0106x12000ra20bqwE935.jpg\", \"https://dimg04.c-ctrip.com/images/0106x12000ra20bqwE935.jpg\", \"https://dimg04.c-ctrip.com/images/0106x12000ra20bqwE935.jpg\", \"https://dimg04.c-ctrip.com/images/0106x12000ra20bqwE935.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '全天', '4-10月', '华山古称“西岳”，是中华文明的发祥地之一，道教全真派圣地。自古有“奇险天下第一山”之说。', '登山需专业装备，建议乘坐索道；注意安全，量力而行。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4572, '少华山国家森林公园', '陕西九寨沟', '少华山是秦岭支脉，因比华山略小而故名。景区有潜龙寺、石门峡、红崖湖等景点，以山水风光和佛教文化著称。', 1, 1847, '陕西省渭南市华州区莲花寺镇', 34.51500000, 109.82027778, '/images/attractions/shaohuashan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-17:00', '4-10月', '少华山在东汉时期就已建寺，潜龙寺始建于东汉，是陕西最早的佛教寺院之一。', '峡谷湿滑，注意防滑；山区天气多变，备好雨具。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4573, '洽川风景名胜区', '中国诗经之乡', '洽川是《诗经》“关关雎鸠，在河之洲”的创作地，有“万顷芦荡、千眼神泉、百种珍禽”的生态美景。处女泉可体验“沙浪浴”的奇妙感觉。', 1, 1847, '陕西省渭南市合阳县洽川镇', 35.13722222, 110.19805556, '/images/attractions/hechuan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '4-10月', '洽川是黄河流域最大的湿地之一，是中华爱情诗的发源地，每年举办“中国合阳洽川荷花节”。', '水上活动注意安全，听从工作人员指挥。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4574, '司马迁祠', '史圣故里', '司马迁祠是为纪念西汉史学家司马迁而建，祠宇依山而建，气势雄伟。登顶可眺望黄河，缅怀这位忍辱负重完成《史记》的伟大史学家。', 2, 1847, '陕西省渭南市韩城市芝川镇', 35.47777778, 110.43972222, '/images/attractions/simaqianci.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', '司马迁祠始建于西晋永嘉四年（310年），历代多次修缮。祠内保存有司马迁墓及历代碑刻。', '台阶较多，注意安全；保护文物古迹。', NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4575, '黄帝陵景区', '天下第一陵', '黄帝陵是中华民族始祖轩辕黄帝的陵寝，位于桥山之巅。景区由轩辕庙和黄帝陵两部分组成，庙内古柏参天，其中“黄帝手植柏”距今约5000年，是世界最古老的柏树。', 2, 1849, '陕西省延安市黄陵县桥山镇', 35.58333333, 109.26666667, 'https://dimg04.c-ctrip.com/images/0106912000l84513m2A49.jpg', '[\"https://dimg04.c-ctrip.com/images/0106912000l84513m2A49.jpg\", \"https://dimg04.c-ctrip.com/images/0106912000l84513m2A49.jpg\", \"https://dimg04.c-ctrip.com/images/0106912000l84513m2A49.jpg\", \"https://dimg04.c-ctrip.com/images/0106912000l84513m2A49.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4576, '延安革命纪念地景区', '中国革命圣地', '延安革命纪念地包括宝塔山、枣园、杨家岭、王家坪等革命旧址，是中国共产党在延安13年革命历程的见证，是全国爱国主义教育示范基地。', 5, 1849, '陕西省延安市宝塔区', 36.59722222, 109.48222222, '/images/attractions/yanan-geming.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4577, '黄河壶口瀑布旅游区', '黄河奇观', '壶口瀑布是中国第二大瀑布，黄河奔流至此，两岸石壁峭立，河口收束狭如壶口，形成壮观的瀑布景观，声如雷鸣，气势磅礴。', 1, 1849, '陕西省延安市宜川县壶口镇', 36.14833333, 110.44611111, '/images/attractions/hukou.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '07:00-18:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4578, '黄河乾坤湾景区', '天下黄河第一湾', '乾坤湾是黄河在延川境内形成的“S”形大转弯，形似太极八卦图，故名乾坤湾。景区可俯瞰黄河壮美河湾，感受大自然的鬼斧神工。', 1, 1849, '陕西省延安市延川县乾坤湾镇', 36.88333333, 110.38333333, '/images/attractions/qiankunwan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4579, '南泥湾风景区', '陕北的好江南', '南泥湾是抗日战争时期八路军359旅屯垦生产的地方，将荒山变成了“陕北好江南”。现已成为红色旅游和生态旅游胜地。', 5, 1849, '陕西省延安市宝塔区南泥湾镇', 36.31666667, 109.61666667, 'https://dimg04.c-ctrip.com/images/100u1800000152qeiB735.jpg', '[\"https://dimg04.c-ctrip.com/images/100u1800000152qeiB735.jpg\", \"https://dimg04.c-ctrip.com/images/100u1800000152qeiB735.jpg\", \"https://dimg04.c-ctrip.com/images/100u1800000152qeiB735.jpg\", \"https://dimg04.c-ctrip.com/images/100u1800000152qeiB735.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4580, '镇北台', '万里长城第一台', '镇北台是明代长城遗址中最为宏大、气势最为磅礴的墩台，素有“中国长城三大奇观之一”之称，与山海关、嘉峪关齐名。', 2, 1850, '陕西省榆林市榆阳区红山', 38.30194444, 109.73833333, '/images/attractions/zhenbeitai.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '5-10月', '镇北台始建于明万历三十五年（1607年），是明代长城上的观察所和指挥台。', NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4581, '红石峡', '塞上碑林', '红石峡因山石呈红色而得名，峡谷两岸崖壁上有宋元以来160多幅石刻，被誉为“塞上碑林”。', 1, 1850, '陕西省榆林市榆阳区北郊', 38.31305556, 109.72666667, 'https://dimg04.c-ctrip.com/images/0HJ5k12000g91q0h30C11.jpg', '[\"https://dimg04.c-ctrip.com/images/0HJ5k12000g91q0h30C11.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ5k12000g91q0h30C11.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ5k12000g91q0h30C11.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ5k12000g91q0h30C11.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '5-10月', '红石峡石窟始凿于宋代，历代文人墨客留下大量摩崖石刻，是研究古代书法艺术的宝库。', NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4582, '石峁遗址', '中华文明探源工程重要遗址', '石峁遗址是中国已发现的龙山晚期到夏早期时期规模最大的城址，距今约4000年，被誉为“华夏第一城”，是探寻中华文明起源的窗口。', 2, 1850, '陕西省榆林市神木市高家堡镇', 38.56666667, 110.32500000, '/images/attractions/shimao.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-17:30', '全年', '石峁遗址发现于1976年，考古发掘表明这里曾是早期国家的都邑性城址，对研究中华文明起源具有重大意义。', NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4583, '波浪谷', '时光的指纹', '波浪谷是典型的丹霞地貌，红色砂岩经亿万年的风雨侵蚀，形成了波浪状的纹理，如同时光的指纹，是摄影爱好者的天堂。', 1, 1850, '陕西省榆林市靖边县龙洲镇', 37.53333333, 108.95000000, '/images/attractions/bolanggu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-18:00', '5-10月', '波浪谷形成于距今1.5亿年前的中生代侏罗纪时期。', NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4584, '白云山道观', '西北道教圣地', '白云山道观始建于宋代，是西北地区最大的道教建筑群，供奉真武祖师。登顶可俯瞰黄河大峡谷。', 2, 1850, '陕西省榆林市佳县城南5公里', 38.01666667, 110.48333333, '/images/attractions/baiyunshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-17:30', '全年', '白云山道观是陕北地区规模最大、保存最完整的道教宫观建筑群。', NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4585, '武侯墓', '诸葛亮长眠之地', '武侯墓是三国时期蜀汉丞相诸葛亮的陵墓，墓区古柏参天，建筑古朴，是纪念诸葛亮的重要场所。', 2, 1851, '陕西省汉中市勉县定军山镇', 33.13333333, 106.66666667, '/images/attractions/wuhoumu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4586, '石门栈道', '明修栈道 暗度陈仓', '石门栈道是古代穿越秦岭的交通要道，始建于战国时期，是沟通关中与汉中盆地的重要通道。景区内有褒斜道遗址、石门摩崖石刻等。', 2, 1851, '陕西省汉中市汉台区河东店镇', 33.18333333, 106.98333333, '/images/attractions/shimenzhandao.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4587, '黎坪国家森林公园', '陕南第一山水', '黎坪国家森林公园以原始森林、奇峰怪石、瀑布溪流著称，有“陕南第一山水”之誉。秋季层林尽染，是赏秋胜地。', 1, 1851, '陕西省汉中市南郑区黎坪镇', 32.88333333, 106.66666667, '/images/attractions/liping.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 95.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4588, '青木川古镇', '一代枭雄魏辅唐故里', '青木川古镇形成于明代，是陕甘川三省交界处的重要古镇。因叶广芩小说《青木川》和电视剧《一代枭雄》而闻名，保存有魏氏宅院、回龙场老街等。', 2, 1851, '陕西省汉中市宁强县青木川镇', 32.83333333, 105.58333333, 'https://dimg04.c-ctrip.com/images/0100812000k0arsvyAB05.jpg', '[\"https://dimg04.c-ctrip.com/images/0100812000k0arsvyAB05.jpg\", \"https://dimg04.c-ctrip.com/images/0104p120008jbwmduC0F0.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000k0arsfsA077.jpg\", \"https://dimg04.c-ctrip.com/images/0100612000k0ar9un7BF0.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2p12000ickshn4C95B.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80412000hgdw02a4320_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4589, '张良庙', '汉初三杰之一张良隐居地', '张良庙是纪念西汉开国功臣张良的祠庙，张良辅佐刘邦建立汉朝后，隐居紫柏山修道。庙内建筑古朴，环境清幽。', 2, 1851, '陕西省汉中市留坝县留侯镇', 33.61666667, 106.91666667, '/images/attractions/zhangliangmiao.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4590, '瀛湖旅游景区', '陕西千岛湖', '瀛湖是安康水电站建成后形成的西北最大的人工湖，湖面广阔，岛屿星罗棋布，有“陕西千岛湖”之称。可乘船游览，欣赏秦巴山水风光。', 1, 1852, '陕西省安康市汉滨区瀛湖镇', 32.68333333, 108.88333333, '/images/attractions/yinghu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4591, '南宫山国家森林公园', '云中净土', '南宫山是巴山深处罕见的冰川地貌和高山自然风景区，以奇峰、怪石、云海、佛光著称，有“云中净土”之誉。', 1, 1852, '陕西省安康市岚皋县南宫山镇', 32.26666667, 108.96666667, '/images/attractions/nangongshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4592, '中坝大峡谷', '秦巴山水画廊', '中坝大峡谷集奇、险、秀、幽于一体，峡谷内瀑布飞泻，溪流潺潺，是秦岭山水风光的精华所在。', 1, 1852, '陕西省安康市石泉县后柳镇', 32.96666667, 108.23333333, 'https://dimg04.c-ctrip.com/images/1lo6r12000rhikj84F93C.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6r12000rhikj84F93C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6r12000rhikj84F93C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6r12000rhikj84F93C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6r12000rhikj84F93C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4593, '香溪洞', '道教洞天福地', '香溪洞是道教名山，相传为吕洞宾修炼之地。景区内有香溪洞、药王洞、八仙洞等洞穴，以及天梯、悬空栈道等景观。', 2, 1852, '陕西省安康市汉滨区新城街道', 32.66666667, 109.01666667, '/images/attractions/xiangxidong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4594, '金丝峡景区', '峡谷之都', '金丝峡是秦岭地区最典型的嶂谷地貌，峡谷深切，瀑布成群，有白龙峡、青龙峡、黑龙峡等景观，被誉为“峡谷之都”。', 1, 1853, '陕西省商洛市商南县金丝峡镇', 33.41666667, 110.81666667, '/images/attractions/jinsixia.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:30-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4595, '牛背梁国家森林公园', '秦岭东段最高峰', '牛背梁是秦岭东段最高峰，海拔2802米。景区以原始森林、高山草甸、峡谷瀑布为特色，有“秦岭之魂”之称。', 1, 1853, '陕西省商洛市柞水县营盘镇', 33.78333333, 108.98333333, 'https://dimg04.c-ctrip.com/images/0100m12000f9s2yg92C3E.jpg', '[\"https://dimg04.c-ctrip.com/images/0100m12000f9s2yg92C3E.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000f9s2yg92C3E.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000f9s2yg92C3E.jpg\", \"https://dimg04.c-ctrip.com/images/0100m12000f9s2yg92C3E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '08:00-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4596, '天竺山国家森林公园', '秦岭奇观', '天竺山以奇峰、怪石、云海、日出著称，有“秦岭奇观”之誉。山上道观始建于隋唐，是道教名山之一。', 1, 1853, '陕西省商洛市山阳县天竺山镇', 33.48333333, 109.98333333, '/images/attractions/tianzhushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4597, '柞水溶洞', '北国奇观', '柞水溶洞是陕西最大的喀斯特溶洞群，有佛爷洞、天洞、百神洞等洞穴，钟乳石千姿百态，被誉为“北国奇观”。', 1, 1853, '陕西省商洛市柞水县石瓮镇', 33.66666667, 109.11666667, 'https://dimg04.c-ctrip.com/images/1A0o15000000xjkzh34D2.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0o15000000xjkzh34D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0o15000000xjkzh34D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0o15000000xjkzh34D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0o15000000xjkzh34D2.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 82.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4598, '药王山', '药王孙思邈故里', '药王山是为纪念唐代医学家孙思邈而建，山上有药王大殿、摩崖造像、古代碑刻等文物古迹，是研究中医药文化的圣地。', 2, 1844, '陕西省铜川市耀州区药王路', 34.91666667, 108.98333333, 'https://dimg04.c-ctrip.com/images/0105a12000ao8kx4rD5B3.jpg', '[\"https://dimg04.c-ctrip.com/images/0105a12000ao8kx4rD5B3.jpg\", \"https://dimg04.c-ctrip.com/images/0104g120008n0pvr6EE85.jpg\", \"https://dimg04.c-ctrip.com/images/0102z120008n0q05sABF1.jpg\", \"https://dimg04.c-ctrip.com/images/0106c120008n0pvs56281.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5012000icknucwF18B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0t12000kyy9cuk0AE6.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4599, '玉华宫遗址', '唐代皇家避暑行宫', '玉华宫是唐高祖李渊、唐太宗李世民时期的皇家避暑行宫，玄奘法师曾在此翻译佛经并圆寂于此。现为国家级考古遗址公园。', 2, 1844, '陕西省铜川市印台区玉华镇', 35.21666667, 109.08333333, '/images/attractions/yuhuagong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4600, '照金香山景区', '红色照金 佛教名山', '照金是陕甘边革命根据地创建地，香山是佛教名山，景区集红色旅游与佛教文化于一体，有薛家寨革命旧址、大香山寺等。', 5, 1844, '陕西省铜川市耀州区照金镇', 34.98333333, 108.73333333, '/images/attractions/zhaojin.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4601, '耀州窑博物馆', '千年窑火 青瓷故里', '耀州窑是中国古代名窑之一，创烧于唐代，鼎盛于宋代。博物馆展示了耀州窑1400多年的烧造历史和精美瓷器。', 2, 1844, '陕西省铜川市王益区黄堡镇', 35.05000000, 109.05000000, '/images/attractions/yaozhouyao.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00（周一闭馆）', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 17:58:12', '2026-03-19 17:58:12');
INSERT INTO `attraction` VALUES (4602, '青城山-都江堰旅游景区', '问道青城山 拜水都江堰', '青城山是中国道教发源地之一，以幽深秀丽著称。都江堰是世界最古老的水利工程之一，至今仍发挥着防洪灌溉作用，被誉为“世界水利文化的鼻祖”。', 2, 1855, '四川省成都市都江堰市青城山镇/都江堰市城西', 31.00222222, 103.60527778, '/images/attractions/qingcheng-dujiangyan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-17:30', '全年', '都江堰建于公元前256年，由李冰父子主持修建。青城山是道教天师道发源地。', '登山注意台阶湿滑，保护文物古迹。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4603, '峨眉山风景名胜区', '中国四大佛教名山', '峨眉山是中国四大佛教名山之一，地势陡峭，风景秀丽，素有“峨眉天下秀”之称。主峰金顶海拔3079米，可观云海、日出、佛光、圣灯四大奇观。', 2, 1865, '四川省乐山市峨眉山市黄湾镇', 29.52000000, 103.33000000, 'https://dimg04.c-ctrip.com/images/0100112000aa36bm74B38.jpg', '[\"https://dimg04.c-ctrip.com/images/0100112000aa36bm74B38.jpg\", \"https://dimg04.c-ctrip.com/images/0100v12000a9f09g37D97.jpg\", \"https://dimg04.c-ctrip.com/images/0104p1200087deb378B5C.jpg\", \"https://dimg04.c-ctrip.com/images/100n0w000000k81kl7149.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6m12000ickrufh97F6.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85e12000jf3oiey8D6C_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '06:00-18:00', '4-10月', '峨眉山早在春秋战国时期就已闻名，汉代开始建寺，是普贤菩萨道场。', '高海拔地区注意高原反应，防寒防晒，登山量力而行。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4604, '乐山大佛景区', '世界最大石刻弥勒佛', '乐山大佛通高71米，开凿于唐代，历时90年完成。大佛依凌云山栖鸾峰临江峭壁凿成，又称凌云大佛，是世界现存最大的摩崖石像。', 2, 1865, '四川省乐山市市中区篦子街', 29.54472222, 103.76944444, 'https://dimg04.c-ctrip.com/images/010511200087crk19504B.jpg', '[\"https://dimg04.c-ctrip.com/images/010511200087crk19504B.jpg\", \"https://dimg04.c-ctrip.com/images/0100612000ikktqugFE55.jpg\", \"https://dimg04.c-ctrip.com/images/0103h12000ikktkua2AF5.jpg\", \"https://dimg04.c-ctrip.com/images/010081200048m5tgw5BAD.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6612000ickspzx88BF.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80412000hgdw02a4320_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '07:30-18:30', '全年', '大佛开凿于唐玄宗开元元年（713年），完成于唐德宗贞元十九年（803年）。', '栈道陡峭，注意安全；雨季防滑。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4605, '九寨沟风景名胜区', '人间仙境 童话世界', '九寨沟以高山湖泊群、瀑布、彩林、雪峰、藏情“五绝”著称，被誉为“人间仙境”。景区呈“Y”字形分布，有树正沟、日则沟、则查洼沟三条主沟。', 1, 1874, '四川省阿坝州九寨沟县漳扎镇', 33.25000000, 104.23333333, 'https://dimg04.c-ctrip.com/images/10071d000001f1xw9D9DE.png', '[\"https://dimg04.c-ctrip.com/images/10071d000001f1xw9D9DE.png\", \"https://dimg04.c-ctrip.com/images/0100812000jih9gi6C702.jpg\", \"https://dimg04.c-ctrip.com/images/0101c12000kno7xht810E.jpg\", \"https://dimg04.c-ctrip.com/images/0104j12000ju09grm178F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3u12000ickyhrf5E63.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85d12000h4ug9lp5291_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 169.00, NULL, '08:00-17:00', '9-10月', '九寨沟1992年被列入世界自然遗产名录，2017年地震后经过修复重新开放。', '高海拔地区注意高原反应，保护生态环境，勿投喂动物。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4606, '黄龙国家级风景名胜区', '人间瑶池', '黄龙以彩池、雪山、峡谷、森林“四绝”著称，最著名的是长达3.6公里的黄龙沟，沟内遍布乳黄色的碳酸钙华沉积，呈梯田状排列，宛如一条金色巨龙。', 1, 1874, '四川省阿坝州松潘县瑟尔磋寨', 32.75000000, 103.83333333, '/images/attractions/huanglong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 170.00, NULL, '08:00-17:00', '6-10月', '黄龙1992年被列入世界自然遗产名录，与九寨沟同为川西北的璀璨明珠。', '海拔较高，注意高反；钙化池不可触摸。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4607, '汶川特别旅游区', '震中重生 见证奇迹', '汶川特别旅游区由映秀地震遗址、水磨古镇、三江生态旅游区组成，是展示灾后重建成果和弘扬抗震救灾精神的重要窗口。', 5, 1874, '四川省阿坝州汶川县', 31.01666667, 103.40000000, '/images/attractions/wenchuan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', '2008年5月12日汶川特大地震震中所在地，现为全国爱国主义教育基地。', '文明参观，保持肃穆。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4608, '北川羌城旅游区', '大禹故里 羌族之乡', '北川羌城旅游区由北川新县城、北川地震遗址、羌族民俗博物馆等组成，是展示羌族文化和抗震救灾精神的重要景区。', 5, 1859, '四川省绵阳市北川县永昌镇', 31.81666667, 104.46666667, '/images/attractions/beichuan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', '北川是中国唯一羌族自治县，2008年地震后异地重建。', '文明参观，尊重当地民俗。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4609, '邓小平故里旅游区', '改革开放总设计师故里', '邓小平故里是全国唯一以纪念邓小平同志为主题的国家5A级景区，包括邓小平故居、陈列馆、缅怀馆等，是红色旅游经典景区。', 5, 1863, '四川省广安市广安区协兴镇牌坊社区', 30.51666667, 106.63333333, 'https://dimg04.c-ctrip.com/images/100n0z000000nbkhjCC29.jpg', '[\"https://dimg04.c-ctrip.com/images/100n0z000000nbkhjCC29.jpg\", \"https://dimg04.c-ctrip.com/images/010501200087e2wgp8C36.jpg\", \"https://dimg04.c-ctrip.com/images/010461200087edm7zC728.jpg\", \"https://dimg04.c-ctrip.com/images/010071200087dycfj2180.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5212000icrhpf193DA.jpg\", \"https://dimg04.c-ctrip.com/images/0104g12000ff85um2E181.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', '邓小平同志1904年出生于此，在此度过了童年和少年时期。', '文明参观，保持肃穆。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4610, '南充市阆中古城旅游区', '中国春节文化之乡', '阆中古城是中国四大古城之一，已有2300多年建城历史，以风水文化和科举文化著称。古城内保存有张飞庙、贡院、华光楼等古建筑。', 2, 1862, '四川省南充市阆中市阆水中路33号', 31.58333333, 105.96666667, '/images/attractions/langzhong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '全天', '全年', '阆中是春节文化的发源地，西汉天文学家落下闳在此创制《太初历》。', '古城内巷弄较多，注意游览路线。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4611, '剑门蜀道剑门关旅游景区', '天下雄关', '剑门关是古蜀道上的重要关隘，因李白“剑阁峥嵘而崔嵬，一夫当关，万夫莫开”而闻名。景区集雄、险、奇、秀于一体。', 2, 1860, '四川省广元市剑阁县剑门关镇', 32.16666667, 105.55000000, '/images/attractions/jianmenguan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 105.00, NULL, '08:30-17:30', '3-11月', '剑门关始建于三国时期，是诸葛亮设关戍守的要地。', '登山台阶较多，建议穿舒适运动鞋；玻璃栈道注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4612, '朱德故里景区', '红军之父故里', '朱德故里景区以朱德故居、朱德诞生地、朱德同志故居纪念馆为核心，是全国爱国主义教育示范基地和红色旅游经典景区。', 5, 1862, '四川省南充市仪陇县马鞍镇大湾路47号', 31.53333333, 106.46666667, 'https://dimg04.c-ctrip.com/images/0104412000k0ubr5t4850.jpg', '[\"https://dimg04.c-ctrip.com/images/0104412000k0ubr5t4850.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000k0ubr5t4850.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000k0ubr5t4850.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000k0ubr5t4850.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', '朱德同志1886年出生于此，在此度过了青少年时代。', '文明参观，保持肃穆。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4613, '泸定海螺沟冰川森林公园', '低海拔现代冰川', '海螺沟是亚洲海拔最低、规模最大的现代海洋性冰川，拥有大冰瀑布、冰川舌、温泉等景观，是观赏贡嘎雪山的绝佳位置。', 1, 1875, '四川省甘孜州泸定县磨西镇', 29.56666667, 101.98333333, '/images/attractions/hailuogou.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '07:30-17:30', '10-5月', '海螺沟是青藏高原东缘的极高山地，以低海拔现代冰川著称于世。', '冰川区域注意防滑，遵守安全规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4614, '碧峰峡旅游景区', '熊猫家园 天然氧吧', '碧峰峡是国家生态旅游示范区，分为野生动物园和生态峡谷两部分。野生动物园可近距离观察大熊猫，峡谷内瀑布飞泻、植被茂密。', 1, 1871, '四川省雅安市雨城区碧峰峡镇', 30.05000000, 103.00000000, 'https://dimg04.c-ctrip.com/images/1lo5312000l938jm553F1.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo5312000l938jm553F1.jpg\", \"https://dimg04.c-ctrip.com/images/010431200090zxcem9677.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0j12000l938k5v7CDD.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0712000l937w2bC3CD.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5312000iclhwum436C.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80a12000gc9q5f46098_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:30-16:30', '全年', '碧峰峡是中国大熊猫保护研究中心雅安基地所在地。', '野生动物区注意安全，听从工作人员指挥。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4615, '巴中市光雾山景区', '亚洲最长红地毯', '光雾山以奇特的喀斯特峰丛地貌、古朴的原生态植被、迷人的瀑潭秀水、秀丽的峡谷风光著称，秋季红叶层林尽染，被誉为“亚洲最长天然红地毯”。', 1, 1861, '四川省巴中市南江县光雾山镇', 32.65000000, 106.81666667, '/images/attractions/guangwushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '10-11月', '光雾山是米仓山国家森林公园的核心区域，是川陕革命根据地的重要组成部分。', '山区路况复杂，自驾注意安全；秋季游客较多，建议错峰。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4616, '甘孜州稻城亚丁景区', '蓝色星球上最后一片净土', '亚丁自然保护区以仙乃日、央迈勇、夏诺多吉三座雪山为核心，被誉为“香格里拉之魂”。雪山、湖泊、草甸、森林构成绝美画卷。', 1, 1875, '四川省甘孜州稻城县香格里拉镇', 28.43333333, 100.33333333, '/images/attractions/yading.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 146.00, NULL, '07:00-17:30', '5-10月', '亚丁在藏语中意为“向阳之地”，是藏传佛教中的圣地。', '海拔4000米以上，务必注意高原反应，准备氧气。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4617, '安仁古镇景区', '中国博物馆小镇', '安仁古镇拥有保存完好的民国公馆建筑群27座，以及建川博物馆聚落、刘氏庄园博物馆等，是中国唯一的博物馆小镇。', 2, 1858, '四川省成都市大邑县安仁镇', 30.51666667, 103.61666667, 'https://dimg04.c-ctrip.com/images/0100o12000abrihox7DCB.jpg', '[\"https://dimg04.c-ctrip.com/images/0100o12000abrihox7DCB.jpg\", \"https://dimg04.c-ctrip.com/images/0102m12000mkfjr6e229E.jpg\", \"https://dimg04.c-ctrip.com/images/0104l120004xa7aftBB32.jpg\", \"https://dimg04.c-ctrip.com/images/0103l1200082yxy0uFF2B.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0k12000icklzg85970.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81912000ik4a21w8E66_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '安仁古镇始建于唐代，民国时期成为刘氏家族聚居地，现存老公馆27座。', '博物馆区需购票参观，可选择性游览。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4618, '四姑娘山景区', '东方阿尔卑斯', '四姑娘山由四座连绵不断的山峰组成，主峰幺妹峰海拔6250米，是邛崃山脉最高峰。景区以雪山、冰川、峡谷、森林、草甸著称，是登山爱好者的天堂。', 1, 1874, '四川省阿坝州小金县四姑娘山镇', 31.10000000, 102.88333333, 'https://dimg04.c-ctrip.com/images/10050z000000mncx7C12A.jpg', '[\"https://dimg04.c-ctrip.com/images/10050z000000mncx7C12A.jpg\", \"https://dimg04.c-ctrip.com/images/01067120008a2i1m7A3E0.jpg\", \"https://dimg04.c-ctrip.com/images/0104v120008a26hi2589F.jpg\", \"https://dimg04.c-ctrip.com/images/0101412000j05q1ysAB14.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3f12000iclixy08CA9.jpg\", \"https://dimg04.c-ctrip.com/images/27c3u12000na9j5gpFBB6_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '07:00-17:30', '6-10月', '四姑娘山是青藏高原的重要组成部分，被誉为“东方的阿尔卑斯”。', '高海拔登山需专业装备和向导，量力而行。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4619, '天台山景区', '山奇、石怪、水美、林幽', '天台山是四川大熊猫栖息地世界自然遗产的一部分，以“山奇、石怪、水美、林幽”著称，景区内有响水滩瀑布、长虹瀑布、倒靴石等景观。', 1, 1856, '四川省成都市邛崃市天台山镇', 30.26666667, 103.13333333, 'https://dimg04.c-ctrip.com/images/0104d12000fi4x31g2440.jpg', '[\"https://dimg04.c-ctrip.com/images/0104d12000fi4x31g2440.jpg\", \"https://dimg04.c-ctrip.com/images/100t0n000000e0szvA735.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M0A/13/C0/CghzgVW-2m6AGVnqAFq0SDxEoR0222.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M01/FD/8F/CghzgFW-2tuADiiRAFeVlkEO5gQ672.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0712000iclxzq22862.jpg\", \"https://dimg04.c-ctrip.com/images/1h662324x97rvlbwk953E_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 58.00, NULL, '08:00-18:00', '4-10月', '天台山古称“蒙山”，是蜀中名山，道教文化深厚。', '夏季涉水项目注意安全，遵守景区规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4620, '成都大熊猫繁育研究基地', '国宝之家', '成都大熊猫繁育研究基地是世界著名的大熊猫迁地保护基地、科研繁育基地和公众教育基地，可近距离观察大熊猫、小熊猫等珍稀动物。', 3, 1854, '四川省成都市成华区熊猫大道1375号', 30.73666667, 104.14277778, 'https://dimg04.c-ctrip.com/images/0105p12000f6scno87BC5.jpg', '[\"https://dimg04.c-ctrip.com/images/0105p12000f6scno87BC5.jpg\", \"https://dimg04.c-ctrip.com/images/10020m000000dmr819B03.jpg\", \"https://dimg04.c-ctrip.com/images/100e180000014g444D0D6.jpg\", \"https://dimg04.c-ctrip.com/images/0103k12000ajm699h3E17.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4y12000icklig404F0.jpg\", \"https://dimg04.c-ctrip.com/images/1h62t12000qhdfi8rB4DD_R_180_180.jpg\"]', 0.00, 0, 1, 0, 0, NULL, 55.00, NULL, '07:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4621, '成都武侯祠博物馆', '三国圣地', '武侯祠是中国唯一的君臣合祀祠庙，由刘备、诸葛亮蜀汉君臣合祀祠宇及惠陵组成，是三国文化的重要载体。', 2, 1854, '四川省成都市武侯区武侯祠大街231号', 30.64944444, 104.04777778, '/images/attractions/wuhouci.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4622, '成都杜甫草堂博物馆', '诗圣故居', '杜甫草堂是唐代诗人杜甫流寓成都时的居所，在此居住近四年创作诗歌240余首。现为纪念杜甫的专题性博物馆。', 2, 1854, '四川省成都市青羊区青华路37号', 30.66361111, 104.03138889, '/images/attractions/dufucaotang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4623, '成都金沙遗址博物馆', '太阳神鸟故里', '金沙遗址是继三星堆之后古蜀文化的又一政治、经济、文化中心，出土了太阳神鸟金饰、金面具、青铜立人等珍贵文物。', 2, 1854, '四川省成都市青羊区金沙遗址路2号', 30.68333333, 104.01666667, '/images/attractions/jinsha.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4624, '成都西岭雪山景区', '窗含西岭千秋雪', '西岭雪山因杜甫“窗含西岭千秋雪”而得名，是成都第一高峰，冬季是滑雪胜地，夏季是避暑天堂。', 1, 1858, '四川省成都市大邑县西岭镇', 30.61666667, 103.21666667, '/images/attractions/xilingxueshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '09:00-17:00', '12-3月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4625, '成都市双流区黄龙溪旅游区', '中国十大水乡古镇', '黄龙溪古镇是川西保存最完整的古镇之一，古街、古树、古庙、古建筑保存完好，“一根面”等特色美食闻名遐迩。', 2, 1854, '四川省成都市双流区黄龙溪镇', 30.31666667, 103.96666667, '/images/attractions/huanglongxi.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4626, '九皇山景区', '羌族风情 猿王洞天', '九皇山是羌族聚居区，景区内有猿王洞、情人桥、羌寨等景点，可体验羌族民俗文化和高山溶洞奇观。', 2, 1859, '四川省绵阳市北川羌族自治县桂溪镇', 31.81666667, 104.51666667, 'https://dimg04.c-ctrip.com/images/1lo1g12000rrbwj8l24B5.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1g12000rrbwj8l24B5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1612000rnnvsl83EED.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3y12000rnnw6gkD91F.png\", \"https://dimg04.c-ctrip.com/images/1lo2w12000rnnvfte828B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5v12000rnnvz987CB6.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3s12000ickks5iCA07.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4627, '绵阳市江油窦圌山风景区', '蜀中奇山', '窦圌山以丹霞地貌为特色，山体由三座孤峰组成，以铁索飞渡闻名，是李白少年时读书之地。', 1, 1859, '四川省绵阳市江油市武都镇', 31.83333333, 104.73333333, '/images/attractions/doushoushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 67.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4628, '皇泽寺博物馆', '女皇祀庙', '皇泽寺是中国唯一的女皇帝武则天的祀庙，始建于北魏，寺内保存有武则天真容石刻像和大量摩崖造像。', 2, 1860, '四川省广元市利州区皇泽路97号', 32.43333333, 105.81666667, '/images/attractions/huangzesi.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4629, '昭化古城', '巴蜀第一县', '昭化古城是国内保存最为完好的三国古城，有“巴蜀第一县，蜀国第二都”之称，是研究三国历史的重要遗址。', 2, 1860, '四川省广元市昭化区昭化镇', 32.33333333, 105.71666667, 'https://dimg04.c-ctrip.com/images/10080z000000nlm9i0F7A.jpg', '[\"https://dimg04.c-ctrip.com/images/10080z000000nlm9i0F7A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1h12000icknmj296FE.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80412000hgdw02a4320_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh1d12000i7pwghg47B5.jpg\", \"https://dimg04.c-ctrip.com/images/1mh6s12000i7p6upq332F.jpg\", \"https://dimg04.c-ctrip.com/images/1mh3l12000i7p39rhF330.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 58.00, NULL, '08:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4630, '东方佛都', '世界最大卧佛', '东方佛都是一座大型佛教艺术博览园，依山而建，拥有世界最大的睡佛和1700多尊佛像，与乐山大佛毗邻。', 2, 1865, '四川省乐山市市中区凌云路', 29.55000000, 103.76666667, 'https://dimg04.c-ctrip.com/images/350u1c000001dkw3mCDBA.jpg', '[\"https://dimg04.c-ctrip.com/images/350u1c000001dkw3mCDBA.jpg\", \"https://dimg04.c-ctrip.com/images/350s1c000001drsv2E56F.jpg\", \"https://dimg04.c-ctrip.com/images/350s1c000001drsv3D590.jpg\", \"https://dimg04.c-ctrip.com/images/350h1c000001dmhwkBD5A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5p12000icoc4eh018E.jpg\", \"https://dimg04.c-ctrip.com/images/27c6412000na9jnck75BB_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4631, '蜀南竹海风景名胜区', '中国最美十大森林', '蜀南竹海是国内唯一以竹类资源为主的国家级风景名胜区，7万亩翠竹覆盖27条峻岭、500多座峰峦，是电影《卧虎藏龙》取景地。', 1, 1866, '四川省宜宾市长宁县竹海镇', 28.46666667, 105.00000000, 'https://dimg04.c-ctrip.com/images/0100d12000ji0iyoz7CE9.jpg', '[\"https://dimg04.c-ctrip.com/images/0100d12000ji0iyoz7CE9.jpg\", \"https://dimg04.c-ctrip.com/images/100313000000v8ycdAB6A.png\", \"https://dimg04.c-ctrip.com/images/100c13000000v9vb139F1.png\", \"https://dimg04.c-ctrip.com/images/0100e12000ji0iyr5060C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6m12000ickn387C02B.jpg\", \"https://dimg04.c-ctrip.com/images/27c6412000na9jnck75BB_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4632, '兴文石海洞乡旅游区', '中国最美的十大地质公园', '兴文石海是四川首家世界地质公园，以喀斯特地貌著称，拥有天坑、溶洞、石林、峡谷四大景观。', 1, 1866, '四川省宜宾市兴文县石海镇', 28.21666667, 105.11666667, '/images/attractions/xingwenstone.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4633, '自贡恐龙博物馆', '世界三大恐龙博物馆之一', '自贡恐龙博物馆是在世界著名的“大山铺恐龙化石群遗址”上兴建的大型遗址类博物馆，馆藏恐龙化石数量居全国之首。', 2, 1868, '四川省自贡市大安区燊海井路四段268号', 29.38333333, 104.78333333, 'https://dimg04.c-ctrip.com/images/0106g12000hzj42489D6F.jpg', '[\"https://dimg04.c-ctrip.com/images/0106g12000hzj42489D6F.jpg\", \"https://dimg04.c-ctrip.com/images/0106f12000hzj3lcf4F65.jpg\", \"https://dimg04.c-ctrip.com/images/100c1f000001gsvc0207B.jpg\", \"https://dimg04.c-ctrip.com/images/tg/097/162/353/fdf5a140f6b746bdb17b5fd80ac53a15.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0n12000icnuy47401A.jpg\", \"https://dimg04.c-ctrip.com/images/Z80l0d0000006tbwy3D88_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4634, '中华彩灯大世界', '中国灯城', '自贡灯会被誉为“天下第一灯”，中华彩灯大世界是自贡灯会的永久举办地，集彩灯艺术、民俗文化、互动体验于一体。', 3, 1868, '四川省自贡市大安区东盐都大道', 29.38333333, 104.78333333, '/images/attractions/zigonglantern.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '18:00-22:30', '春节前后', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4635, '三苏祠博物馆', '三苏故里', '三苏祠是北宋文学家苏洵、苏轼、苏辙父子三人的故居，占地65000平方米，是一座典型的四川园林式祠堂。', 2, 1870, '四川省眉山市东坡区纱縠行南段72号', 30.05000000, 103.83333333, '/images/attractions/sansuci.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4636, '瓦屋山国家森林公园', '中国最大桌山', '瓦屋山是世界第二大平顶桌状山，被誉为“云霭之上的诺亚方舟”，冬季冰雪景观壮美，夏季是避暑胜地。', 1, 1870, '四川省眉山市洪雅县瓦屋山镇', 29.61666667, 103.00000000, '/images/attractions/wawushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4637, '蒙顶山旅游景区', '世界茶文化发源地', '蒙顶山是世界茶文化的发源地，有“扬子江中水，蒙山顶上茶”之誉。景区内古银杏参天，可体验采茶、制茶、品茶。', 2, 1871, '四川省雅安市名山区蒙顶山镇', 30.06666667, 103.10000000, 'https://dimg04.c-ctrip.com/images/0104c12000aey1mpq38FA.jpg', '[\"https://dimg04.c-ctrip.com/images/0104c12000aey1mpq38FA.jpg\", \"https://dimg04.c-ctrip.com/images/0102x120008iy7p7i027D.jpg\", \"https://dimg04.c-ctrip.com/images/0105w12000aey1k7uDE04.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1d12000ccsclveEE4A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1012000ickkx52741D.jpg\", \"https://dimg04.c-ctrip.com/images/0Z82b12000cgxoftdFD32_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4638, '西昌市邛海泸山风景名胜区', '川南胜境', '邛海是四川第二大淡水湖，泸山与邛海相映成趣，可登山俯瞰邛海全景，感受“月出邛池水，空明彻九霄”的意境。', 1, 1873, '四川省凉山州西昌市海滨中路28号', 27.88333333, 102.26666667, '/images/attractions/qionghai.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4639, '凉山州泸沽湖旅游景区', '母系氏族最后的领地', '泸沽湖是川滇两省界湖，以摩梭人独特的母系氏族文化和走婚习俗闻名。湖水清澈，被誉为“高原明珠”。', 1, 1873, '四川省凉山州盐源县泸沽湖镇', 27.70000000, 100.80000000, '/images/attractions/luguhu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '全天', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4640, '凉山州普格县螺髻山旅游景区', '第四纪古冰川公园', '螺髻山以高山湖泊、杜鹃花海、温泉瀑布著称，拥有世界最大的古冰川刻槽，被誉为“世界古冰川地质公园”。', 1, 1873, '四川省凉山州普格县螺髻山镇', 27.55000000, 102.41666667, '/images/attractions/luoji.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:30-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4641, '康定情歌(木格措)风景区', '情歌故乡 高原湖泊', '木格措是康定情歌的发源地，由高山湖泊、原始森林、温泉、雪峰组成，可体验“一日四时景，十里不同天”的奇观。', 1, 1875, '四川省甘孜州康定市雅拉乡', 30.20000000, 101.86666667, 'https://dimg04.c-ctrip.com/images/0106k12000j0ejm0x6633.jpg', '[\"https://dimg04.c-ctrip.com/images/0106k12000j0ejm0x6633.jpg\", \"https://dimg04.c-ctrip.com/images/0103f1200090b7mzm8788.jpg\", \"https://dimg04.c-ctrip.com/images/100h1f000001grv7h1D05.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000j0ej61lED28.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6012000icktu4w05F1.jpg\", \"https://dimg04.c-ctrip.com/images/0Z82u12000cbd4jebC697_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 105.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4642, '丹巴甲居藏寨', '中国最美乡村', '甲居藏寨是丹巴最具代表性的嘉绒藏族村寨，数百座藏式民居依山而建，色彩斑斓，与雪山、森林、溪流构成绝美画卷。', 2, 1875, '四川省甘孜州丹巴县聂呷乡', 30.88333333, 101.88333333, '/images/attractions/jiaju.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4643, '道孚墨石公园景区', '高原石林奇观', '墨石公园是中国唯一的高原石林景观，岩石在风雨侵蚀下形成千姿百态的石柱、石笋、石蘑菇，被誉为“地质奇观博物馆”。', 1, 1875, '四川省甘孜州道孚县八美镇', 30.58333333, 101.41666667, '/images/attractions/moshigongyuan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4644, '达古冰川', '最近的遥远', '达古冰川是全球海拔最低、面积最大、年纪最轻的冰川，也是距离城市最近的冰川，可乘坐世界海拔最高的索道直达冰川。', 1, 1874, '四川省阿坝州黑水县芦花镇', 32.20000000, 102.90000000, 'https://dimg04.c-ctrip.com/images/0105c12000f6t3uo7B22C.jpg', '[\"https://dimg04.c-ctrip.com/images/0105c12000f6t3uo7B22C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1b12000e8gqufb8C76.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3r12000e8gra2uFC8B.jpg\", \"https://dimg04.c-ctrip.com/images/100g10000000p45eeA6DA.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4412000ickynum10A8.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3b12000e8gu3hiD6C1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:30-17:00', '9-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4645, '毕棚沟景区', '四姑娘山背影', '毕棚沟是国内知名的红叶观赏胜地，集雪山、湖泊、森林、瀑布于一体，被誉为“四姑娘山的美丽背影”。', 1, 1874, '四川省阿坝州理县朴头乡', 31.30000000, 102.90000000, 'https://dimg04.c-ctrip.com/images/010731200085d3leiD694.jpg', '[\"https://dimg04.c-ctrip.com/images/010731200085d3leiD694.jpg\", \"https://dimg04.c-ctrip.com/images/0102z1200093cw25v92A0.jpg\", \"https://dimg04.c-ctrip.com/images/0105e1200093cvuui5A02.jpg\", \"https://dimg04.c-ctrip.com/images/0106s12000ag9ncoh99A5.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3h12000icmss8j9E3A.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84m12000llvftd50F3C_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:00', '10-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4646, '昆明石林风景区', '天下第一奇观', '石林是世界自然遗产，典型的喀斯特地貌，经过亿万年地质变迁形成。景区由大石林、小石林、步哨山、李子园箐和万年灵芝五个片区组成。', 1, 1876, '云南省昆明市石林彝族自治县石林中路', 24.82000000, 103.33000000, '/images/attractions/shilin.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '07:30-18:00', '全年', '石林形成于2.7亿年前，是阿诗玛的故乡，彝族撒尼人聚居地。', '游览时注意防晒，部分区域需攀爬，注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4647, '昆明世博园', '世界园林园艺大观园', '昆明世博园是1999年昆明世界园艺博览会会址，占地218公顷，集全国各省、区、市地方特色和95个国家风格的园林园艺于一体。', 3, 1876, '云南省昆明市盘龙区世博路10号', 25.08000000, 102.75000000, '/images/attractions/kunming-expo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '全年', '1999年世博会举办地，是中国举办的首届专业类世博会。', '园区面积大，建议乘坐电瓶车。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4648, '玉龙雪山', '纳西族神山', '玉龙雪山是北半球最南的大雪山，主峰扇子陡海拔5596米，终年积雪。景区有冰川公园、蓝月谷、云杉坪、牦牛坪等景点。', 1, 1881, '云南省丽江市玉龙纳西族自治县', 27.10000000, 100.25000000, 'https://dimg04.c-ctrip.com/images/10080h00000091sqyC8C0.jpg', '[\"https://dimg04.c-ctrip.com/images/10080h00000091sqyC8C0.jpg\", \"https://dimg04.c-ctrip.com/images/0101r120009laggn6EC7B.jpg\", \"https://dimg04.c-ctrip.com/images/0105v120009lagdz86C86.jpg\", \"https://dimg04.c-ctrip.com/images/0104b120009lagf80D01C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0k12000ickzvsg055C.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81v12000f4hsc082CDD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:00-18:00', '全年', '玉龙雪山是纳西族保护神“三多”的化身，纳西族心中的神山。', '海拔较高，注意高原反应，准备氧气；防寒防晒。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4649, '丽江古城', '世界文化遗产', '丽江古城是中国以整座古城申报世界文化遗产获得成功的古城之一，保存完好的古建筑群、小桥流水、纳西族文化吸引着全球游客。', 2, 1881, '云南省丽江市古城区', 26.87000000, 100.23000000, 'https://dimg04.c-ctrip.com/images/0100j12000g2oj728A7F4.jpg', '[\"https://dimg04.c-ctrip.com/images/0100j12000g2oj728A7F4.jpg\", \"https://dimg04.c-ctrip.com/images/100f12000000rz2qm851C.jpg\", \"https://dimg04.c-ctrip.com/images/0100g120008c4m8hw1A0C.jpg\", \"https://dimg04.c-ctrip.com/images/0100z12000nuux88t5279.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3i12000ickigdcF676.jpg\", \"https://dimg04.c-ctrip.com/images/0Z86n120008r5fufp9A20_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', '丽江古城始建于宋末元初，是茶马古道上的重要集散地。', '古城内石板路湿滑，注意脚下；保管好个人物品。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4650, '崇圣寺三塔文化旅游区', '大理地标', '崇圣寺三塔是大理的标志和象征，三塔由一大二小组成，大塔名千寻塔，建于南诏国时期。景区集苍洱风光、文物古迹、佛教文化于一体。', 2, 1888, '云南省大理白族自治州大理市中和镇三文笔村', 25.71000000, 100.15000000, 'https://dimg04.c-ctrip.com/images/1lo6n12000l3438lkEE08.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6n12000l3438lkEE08.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2412000l343g3b2506.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6h12000l343g28113B.jpg\", \"https://dimg04.c-ctrip.com/images/100o1f000001gp4osAED3.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3412000icl06wf5FCD.jpg\", \"https://dimg04.c-ctrip.com/images/1h61812000owes594EFD9_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '08:00-18:00', '全年', '崇圣寺始建于南诏国时期，是南诏国和大理国的皇家寺院。', '登塔注意安全；尊重佛教信仰。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4651, '普达措国家公园', '中国首个国家公园', '普达措是中国大陆第一个国家公园，由碧塔海、属都湖和弥里塘亚高山牧场组成，原始生态环境保存完好，湖泊、牧场、森林应有尽有。', 1, 1891, '云南省迪庆州香格里拉市建塘镇红坡村', 27.90000000, 99.90000000, 'https://dimg04.c-ctrip.com/images/10020y000000m22ji5824.jpg', '[\"https://dimg04.c-ctrip.com/images/10020y000000m22ji5824.jpg\", \"https://dimg04.c-ctrip.com/images/0105s1200087d2wadF298.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000j07iba34984.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000j07hvwxB8C4.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4v12000icl6ee3CCEF.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84s1200028u4rc6A9FB_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-16:00', '5-10月', '普达措在藏语中意为“普度众生到达苦海彼岸的湖”，是香格里拉旅游的核心景区。', '海拔3500-4200米，注意高原反应，保暖防晒。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4652, '西双版纳热带植物园', '植物王国缩影', '中科院西双版纳热带植物园是中国面积最大、收集物种最丰富、植物专类园区最多的植物园，收集有活植物13000多种。', 3, 1887, '云南省西双版纳州勐腊县勐仑镇葫芦岛', 21.93000000, 101.27000000, '/images/attractions/xishuangbanna-botanical.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', '1959年由蔡希陶教授领导创建，是中国最重要的热带植物研究基地。', '热带地区注意防蚊虫、防晒。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4653, '普者黑风景区', '三生三世十里桃花取景地', '普者黑是典型的喀斯特山水田园风光，以“水上田园、彝家水乡、荷花世界、岩溶湿地”著称，是电视剧《三生三世十里桃花》取景地。', 1, 1886, '云南省文山州丘北县双龙营镇普者黑村', 24.15000000, 104.15000000, 'https://dimg04.c-ctrip.com/images/100d11000000r0dm84ADA.jpg', '[\"https://dimg04.c-ctrip.com/images/100d11000000r0dm84ADA.jpg\", \"https://dimg04.c-ctrip.com/images/100d11000000r0dm84ADA.jpg\", \"https://dimg04.c-ctrip.com/images/100d11000000r0dm84ADA.jpg\", \"https://dimg04.c-ctrip.com/images/100d11000000r0dm84ADA.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:30', '6-9月', '普者黑在彝语中意为“鱼虾丰美的池塘”，是彝族支系撒尼人聚居地。', '水上活动注意安全，穿救生衣；夏季荷花盛开最美。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4654, '腾冲火山热海旅游区', '地热奇观', '热海景区有气泉、热泉、温泉80多处，以大滚锅最为著名。火山景区有90多座火山锥，是集火山观光、温泉康养于一体的景区。', 1, 1879, '云南省保山市腾冲市清水乡', 25.03000000, 98.43000000, '/images/attractions/tengchong-rehai.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', '腾冲是中国三大地热区之一，明清时期就享有“一泓热海”之美誉。', '温泉区域注意防滑，部分泉眼水温高请勿触摸。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4655, '腾冲和顺古镇', '中国十大魅力名镇', '和顺古镇是云南著名侨乡，已有600多年历史。古镇环山而建，明清时期的祠堂、牌坊、古宅遍布，艾思奇故居坐落于此。', 2, 1879, '云南省保山市腾冲市和顺镇', 25.03000000, 98.48000000, '/images/attractions/heshun.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '全天', '全年', '和顺古名“阳温墩”，因小河绕村而过故名“河顺”，后取“士和民顺”之意。', '古镇内巷道较多，可乘坐观光车。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4656, '云南民族村', '民族风情大观园', '云南民族村占地1300亩，集中展示了云南25个少数民族的村寨、建筑、服饰、歌舞和民俗文化，是体验云南多民族风情的窗口。', 2, 1876, '云南省昆明市西山区滇池路1310号', 24.97000000, 102.67000000, 'https://dimg04.c-ctrip.com/images/1lo0312000q7pam3l4961.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0312000q7pam3l4961.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000q7pam3l4961.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000q7pam3l4961.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0312000q7pam3l4961.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4657, '昆明金殿风景名胜区', '中国最大铜殿', '金殿始建于明代，是供奉真武大帝的道教宫观，主殿由青铜铸造，重约200吨，是中国最大的铜殿。', 2, 1876, '云南省昆明市盘龙区穿金路', 25.10000000, 102.75000000, '/images/attractions/kunming-jindian.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4658, '宜良九乡风景区', '溶洞之乡', '九乡是国际洞穴协会成员，拥有大小溶洞上百座，是国内规模最大、数量最多的洞穴群落体系，被誉为“溶洞博物馆”。', 1, 1876, '云南省昆明市宜良县九乡彝族回族乡', 25.15000000, 103.38000000, '/images/attractions/jiuxiang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4659, '昆明轿子雪山', '滇中第一山', '轿子雪山因最高峰形如轿子而得名，海拔4223米，是滇中最高峰。冬季冰雪覆盖，可赏雪景、冰瀑、雾凇。', 1, 1876, '云南省昆明市禄劝县乌蒙乡', 26.10000000, 102.88000000, '/images/attractions/jiaozi.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-17:00', '12-3月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4660, '大理古城', '风花雪月之城', '大理古城始建于明洪武十五年，是古代南诏国和大理国的都城。城内保存有文献楼、五华楼、人民路、洋人街等景点。', 2, 1888, '云南省大理白族自治州大理市古城区', 25.70000000, 100.16000000, 'https://dimg04.c-ctrip.com/images/0101t12000jco2p76D9FE.jpg', '[\"https://dimg04.c-ctrip.com/images/0101t12000jco2p76D9FE.jpg\", \"https://dimg04.c-ctrip.com/images/0105f12000f3yx8tk44A3.jpg\", \"https://dimg04.c-ctrip.com/images/100n0h0000008rbfs673A.jpg\", \"https://dimg04.c-ctrip.com/images/0102712000jco2g526983.jpg\", \"https://dimg04.c-ctrip.com/images/0zg7412000icl2tusC437.jpg\", \"https://dimg04.c-ctrip.com/images/Z80s160000010jwbr7246_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4661, '洱海', '高原明珠', '洱海是云南第二大淡水湖，因形似人耳而得名。环湖有双廊、喜洲、才村等古镇，可骑行、拍照、赏日落。', 1, 1888, '云南省大理白族自治州大理市环海路', 25.80000000, 100.20000000, 'https://dimg04.c-ctrip.com/images/0102a12000f6scutxD6C9.jpg', '[\"https://dimg04.c-ctrip.com/images/0102a12000f6scutxD6C9.jpg\", \"https://dimg04.c-ctrip.com/images/0100t12000g3b5zsaA9A7.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000j0apewb12F9.jpg\", \"https://dimg04.c-ctrip.com/images/100p0h0000008s7xqA6E5.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0c12000icks2l6EEDE.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84s1200028u4rc6A9FB_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4662, '丽江束河古镇', '茶马古道重镇', '束河古镇是纳西族先民最早的聚居地之一，比大研古城更安静，保留着茶马古道的历史风貌和田园风光。', 2, 1881, '云南省丽江市古城区束河路', 26.92000000, 100.22000000, '/images/attractions/shuhe.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4663, '丽江泸沽湖风景名胜区', '东方女儿国', '泸沽湖是川滇界湖，湖水清澈，摩梭人世代居住于此，保留着母系氏族社会和走婚习俗，被誉为“东方女儿国”。', 1, 1881, '云南省丽江市宁蒗彝族自治县永宁乡', 27.70000000, 100.80000000, '/images/attractions/lugu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '全天', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4664, '噶丹·松赞林寺', '小布达拉宫', '松赞林寺是云南规模最大的藏传佛教寺院，有“小布达拉宫”之称。寺院依山而建，金顶白墙，气势恢宏。', 2, 1891, '云南省迪庆州香格里拉市建塘镇尼旺路', 27.83000000, 99.70000000, 'https://dimg04.c-ctrip.com/images/100f1f000001gqa3a2533.jpg', '[\"https://dimg04.c-ctrip.com/images/100f1f000001gqa3a2533.jpg\", \"https://dimg04.c-ctrip.com/images/0101a120008kyo5a8A516.jpg\", \"https://dimg04.c-ctrip.com/images/0104i120008kyod405D8D.jpg\", \"https://dimg04.c-ctrip.com/images/01034120008c4vkw15B76.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6p12000iclozyw6DA1.jpg\", \"https://dimg04.c-ctrip.com/images/1h61812000owes594EFD9_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4665, '香格里拉大峡谷·巴拉格宗景区', '香格里拉秘境', '巴拉格宗集雪山、峡谷、冰川、森林、牧场于一体，是香格里拉最深藏不露的秘境，有“香格里拉最后一片净土”之称。', 1, 1891, '云南省迪庆州香格里拉市尼西乡', 28.10000000, 99.50000000, '/images/attractions/balagezong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 170.00, NULL, '08:00-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4666, '西双版纳望天树景区', '空中树冠走廊', '望天树景区以望天树群落为核心，可挑战惊险刺激的“空中树冠走廊”，在几十米高的树冠间穿行，感受热带雨林的魅力。', 1, 1887, '云南省西双版纳州勐腊县补蚌村', 21.60000000, 101.60000000, '/images/attractions/wangtianshu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4667, '西双版纳傣族园', '傣家风情第一园', '傣族园由五个保存完好的傣族村寨组成，可体验傣家竹楼、傣族泼水节、传统手工艺等民俗文化。', 2, 1887, '云南省西双版纳州景洪市勐罕镇', 21.85000000, 101.07000000, 'https://dimg04.c-ctrip.com/images/1lo0f12000dsi3p219189.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0f12000dsi3p219189.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0f12000dsi3p219189.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0f12000dsi3p219189.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0f12000dsi3p219189.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 45.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4668, '元阳哈尼梯田', '世界文化遗产', '元阳梯田是哈尼族人1300多年来生生不息“雕刻”的山水田园画，是世界文化遗产、全球重要农业文化遗产。', 1, 1885, '云南省红河州元阳县新街镇', 23.16000000, 102.76000000, 'https://dimg04.c-ctrip.com/images/0100d12000j0if0cw6146.jpg', '[\"https://dimg04.c-ctrip.com/images/0100d12000j0if0cw6146.jpg\", \"https://dimg04.c-ctrip.com/images/0100x12000nt73p19AAE1.jpg\", \"https://dimg04.c-ctrip.com/images/0100e12000j0ifyi87826.jpg\", \"https://dimg04.c-ctrip.com/images/100e070000002qpuw162B.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5h12000ickuafpB9FC.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80a12000gc9q5f46098_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '全天', '11-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4669, '建水古城', '古建筑博物馆', '建水古城已有1200多年历史，保存有朝阳楼、朱家花园、文庙、团山民居等50余座古建筑，被誉为“古建筑博物馆”。', 2, 1885, '云南省红河州建水县临安镇', 23.62000000, 102.82000000, 'https://dimg04.c-ctrip.com/images/0101512000jnc9jwuDEA1.jpg', '[\"https://dimg04.c-ctrip.com/images/0101512000jnc9jwuDEA1.jpg\", \"https://dimg04.c-ctrip.com/images/0101512000jnc9jwuDEA1.jpg\", \"https://dimg04.c-ctrip.com/images/0101512000jnc9jwuDEA1.jpg\", \"https://dimg04.c-ctrip.com/images/0101512000jnc9jwuDEA1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4670, '罗平九龙瀑布群', '中国最美瀑布', '九龙瀑布群由十级瀑布组成，被誉为“九龙十瀑，南国一绝”。春季油菜花盛开时，瀑布与花海相映成趣。', 1, 1877, '云南省曲靖市罗平县长底乡', 24.98000000, 104.33000000, '/images/attractions/jiulong-waterfall.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 95.00, NULL, '08:00-18:00', '2-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4671, '陆良彩色沙林', '世界唯一的彩色沙林', '彩色沙林形成于3.4亿年前，沙峰、沙柱、沙壁色彩斑斓，以红、黄、白为主色调，是世界唯一的彩色沙林景观。', 1, 1877, '云南省曲靖市陆良县马街镇', 24.98000000, 103.68000000, 'https://dimg04.c-ctrip.com/images/0100z12000k05vvxrC915.jpg', '[\"https://dimg04.c-ctrip.com/images/0100z12000k05vvxrC915.jpg\", \"https://dimg04.c-ctrip.com/images/0100z12000k05vvxrC915.jpg\", \"https://dimg04.c-ctrip.com/images/0100z12000k05vvxrC915.jpg\", \"https://dimg04.c-ctrip.com/images/0100z12000k05vvxrC915.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4672, '抚仙湖', '琉璃万顷', '抚仙湖是中国最大的深水型淡水湖，湖水清澈见底，被誉为“琉璃万顷”。可环湖骑行、乘船游览、品尝铜锅鱼。', 1, 1878, '云南省玉溪市澄江市', 24.55000000, 102.88000000, 'https://dimg04.c-ctrip.com/images/0107312000hnrd27w482C.jpg', '[\"https://dimg04.c-ctrip.com/images/0107312000hnrd27w482C.jpg\", \"https://dimg04.c-ctrip.com/images/0107312000hnrd27w482C.jpg\", \"https://dimg04.c-ctrip.com/images/0107312000hnrd27w482C.jpg\", \"https://dimg04.c-ctrip.com/images/0107312000hnrd27w482C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4673, '通海秀山公园', '秀甲南滇', '秀山是云南四大名山之一，有“秀甲南滇”之称。山上有万寿台、普光寺、玉皇阁等古建筑群，林木葱郁，环境清幽。', 1, 1878, '云南省玉溪市通海县秀山街道', 24.11000000, 102.76000000, '/images/attractions/xiushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 10.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4674, '元谋土林', '世界土林奇观', '元谋土林是地质奇观，土柱形态千姿百态，色彩斑斓，是摄影爱好者的天堂，电影《无极》取景地。', 1, 1884, '云南省楚雄州元谋县物茂乡', 25.70000000, 101.87000000, '/images/attractions/yuanmou-tulin.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4675, '禄丰世界恐龙谷', '恐龙之乡', '禄丰恐龙谷是在世界最大的恐龙化石遗址上兴建的大型恐龙主题公园，馆藏恐龙化石数量居世界前列。', 3, 1884, '云南省楚雄州禄丰市川街乡', 25.13000000, 102.08000000, '/images/attractions/lufeng-dinosaur.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4676, '坝美世外桃源', '最后的世外桃源', '坝美是一个与世隔绝的壮族村寨，需乘船穿过溶洞才能进入，村内田园风光优美，被誉为“最后的世外桃源”。', 1, 1886, '云南省文山州广南县坝美镇', 24.20000000, 104.80000000, 'https://dimg04.c-ctrip.com/images/100m0d0000006y6bdB18C.jpg', '[\"https://dimg04.c-ctrip.com/images/100m0d0000006y6bdB18C.jpg\", \"https://dimg04.c-ctrip.com/images/100m0d0000006y6bdB18C.jpg\", \"https://dimg04.c-ctrip.com/images/100m0d0000006y6bdB18C.jpg\", \"https://dimg04.c-ctrip.com/images/100m0d0000006y6bdB18C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 85.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4677, '昭通水富西部大峡谷', '中国第三大温泉', '西部大峡谷是金沙江峡谷中的大型温泉度假区，温泉水温高达82℃，富含多种矿物质。', 4, 1880, '云南省昭通市水富市云富街道', 28.60000000, 104.40000000, '/images/attractions/xibu-daxiagu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 128.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:05:37', '2026-03-19 18:05:37');
INSERT INTO `attraction` VALUES (4678, '故宫博物院', '世界五大宫之首', '故宫是明清两代的皇家宫殿，旧称紫禁城，始建于1420年，是世界上现存规模最大、保存最完整的木质结构古建筑群。收藏有180余万件珍贵文物。', 2, 1892, '北京市东城区景山前街4号', 39.91666667, 116.38333333, 'https://dimg04.c-ctrip.com/images/010671200087d4o7zEA88.jpg', '[\"https://dimg04.c-ctrip.com/images/010671200087d4o7zEA88.jpg\", \"https://dimg04.c-ctrip.com/images/100k0q000000gqnh8EE78.jpg\", \"https://dimg04.c-ctrip.com/images/100310000000om1k74D93.jpg\", \"https://dimg04.c-ctrip.com/images/100g0x000000let3k0858.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4112000ickkp0344F8.jpg\", \"https://dimg04.c-ctrip.com/images/100l10000000pb1f3F2BC.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:30-17:00', '全年', '1420年建成，先后有24位皇帝在此居住。1987年被列入世界文化遗产。', '周一闭馆（法定节假日除外）；提前预约，刷身份证入园。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4679, '八达岭长城', '天下九塞之一', '八达岭长城是明长城中保存最完好、最具代表性的一段，自古便有“居庸之险不在关而在八达岭”之说。', 2, 1893, '北京市延庆区八达岭特区', 40.35000000, 116.01666667, 'https://dimg04.c-ctrip.com/images/100c0u000000jjsf87E14.jpg', '[\"https://dimg04.c-ctrip.com/images/100c0u000000jjsf87E14.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0i12000rrex15uE41D.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4k12000p93y56n3849.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6812000rrexo1d9E27.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6p12000ickxhwlD14F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6912000hrx3ysu483E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '06:30-19:00', '4-10月', '明代弘治十八年（1505年）开始修建，是拱卫京师的重要屏障。', '长城台阶陡峭，注意安全；节假日人流量大，建议错峰。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4680, '颐和园', '皇家园林博物馆', '颐和园是中国现存规模最大、保存最完整的皇家园林，以昆明湖、万寿山为基础，汲取江南园林的设计手法而建成。', 2, 1892, '北京市海淀区新建宫门路19号', 39.99972222, 116.27111111, 'https://dimg04.c-ctrip.com/images/0104812000f9tho5g2832.jpg', '[\"https://dimg04.c-ctrip.com/images/0104812000f9tho5g2832.jpg\", \"https://dimg04.c-ctrip.com/images/0101412000izsevl82780.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000knl23un6BC7.jpg\", \"https://dimg04.c-ctrip.com/images/0100b12000izsfc392C93.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4812000icknkqcE3AE.jpg\", \"https://dimg04.c-ctrip.com/images/Z80o10000000oifxc67D7_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '06:30-20:00', '全年', '始建于1750年，1860年被英法联军焚毁，1888年重建。1998年被列入世界文化遗产。', '游船注意安全；冬季湖面结冰禁止行走。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4681, '天坛公园', '明清帝王祭天场所', '天坛是明清两代皇帝“祭天”“祈谷”的场所，是中国现存最大的古代祭祀性建筑群。祈年殿是其标志性建筑。', 2, 1892, '北京市东城区天坛路甲1号', 39.88222222, 116.40666667, 'https://dimg04.c-ctrip.com/images/10040h0000008s9n50143.jpg', '[\"https://dimg04.c-ctrip.com/images/10040h0000008s9n50143.jpg\", \"https://dimg04.c-ctrip.com/images/0101t12000farlckv781A.jpg\", \"https://dimg04.c-ctrip.com/images/0102p1200082jbu2fAD72.jpg\", \"https://dimg04.c-ctrip.com/images/0103l1200082jcx0v68B2.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2h12000ickxiht48F0.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84s12000dhpyjt31528_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 15.00, NULL, '06:00-22:00', '全年', '始建于明永乐十八年（1420年），清乾隆、光绪时曾重修改建。1998年被列入世界文化遗产。', '祈年殿、皇穹宇等景点需单独购票。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4682, '慕田峪长城', '长城精华所在', '慕田峪长城是明代长城的精华段落，敌楼密集，关隘险要，城墙保存完好，植被覆盖率达96%以上。', 2, 1894, '北京市怀柔区渤海镇慕田峪村', 40.43333333, 116.56666667, 'https://dimg04.c-ctrip.com/images/1lo0m12000bjgo0zjBC35.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0m12000bjgo0zjBC35.jpg\", \"https://dimg04.c-ctrip.com/images/0100u12000jj2elam8FE6.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000jj2e56l4316.jpg\", \"https://dimg04.c-ctrip.com/images/350k180000014qfcj7E73.png\", \"https://dimg04.c-ctrip.com/images/0zg0y12000ickqmysD5E2.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0j12000bjgnzar37F0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 45.00, NULL, '07:30-18:00', '4-10月', '慕田峪长城由朱元璋手下大将徐达在北齐长城遗址上督建而成。', '缆车、索道、滑道选择多样，根据体力选择。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4683, '明十三陵', '世界最大帝王陵寝', '明十三陵是明朝13位皇帝的陵墓群，陵区面积约40平方公里，长陵、定陵、昭陵已对公众开放。', 2, 1892, '北京市昌平区十三陵镇', 40.26666667, 116.21666667, 'https://dimg04.c-ctrip.com/images/0106d12000imdov3p607F.jpg', '[\"https://dimg04.c-ctrip.com/images/0106d12000imdov3p607F.jpg\", \"https://dimg04.c-ctrip.com/images/100m1f000001gznjj0C53.jpg\", \"https://dimg04.c-ctrip.com/images/0104112000imdoxlo4266.jpg\", \"https://dimg04.c-ctrip.com/images/0107112000imdp2196F9C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4912000icl2vigD2CE.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4u12000cuum50n45B4.png\"]', 0.00, 0, 0, 0, 0, NULL, 45.00, NULL, '08:00-17:30', '全年', '自明永乐七年（1409年）开始修建，至清初完工，历时200余年。2003年被列入世界文化遗产。', '定陵地宫较深，上下楼梯注意安全。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4684, '恭王府', '一座恭王府，半部清朝史', '恭王府是清代规模最大的一座王府，曾为和珅、永璘、恭亲王奕訢的宅邸。府内建筑精巧，花园优美。', 2, 1892, '北京市西城区前海西街17号', 39.93333333, 116.38333333, 'https://dimg04.c-ctrip.com/images/0103o12000jtaf06u56A4.jpg', '[\"https://dimg04.c-ctrip.com/images/0103o12000jtaf06u56A4.jpg\", \"https://dimg04.c-ctrip.com/images/0104412000jtafathD789.jpg\", \"https://dimg04.c-ctrip.com/images/100713000000vhaoaF81F.jpg\", \"https://dimg04.c-ctrip.com/images/0103412000izrx6331C88.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0h12000ickm2qm5C72.jpg\", \"https://dimg04.c-ctrip.com/images/1h65m12000g2m15qa0C2D_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-17:00', '全年', '始建于1776年，见证了清王朝由盛转衰的历史。', '府内禁止吸烟，保护文物。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4685, '鸟巢·水立方', '奥运遗产', '国家体育场（鸟巢）是2008年北京奥运会主体育场，国家游泳中心（水立方）是奥运会游泳比赛场馆，现已成为北京新地标。', 3, 1892, '北京市朝阳区国家体育场南路1号', 39.99166667, 116.38333333, '/images/attractions/beijing-olympic.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '09:00-21:00', '全年', '2008年北京奥运会核心场馆，2022年冬奥会再次使用。', '参观时遵守场馆规定。', NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4686, '天津盘山风景名胜区', '京东第一山', '盘山因山势如龙盘虎踞而得名，集自然山水与皇家园林于一体，乾隆皇帝曾32次登临，留下“早知有盘山，何必下江南”的感叹。', 1, 1896, '天津市蓟州区官庄镇莲花岭村', 40.08333333, 117.25000000, '/images/attractions/panshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 78.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4687, '五大道文化旅游区', '万国建筑博览苑', '五大道是天津保留最完整的洋楼建筑群，拥有20世纪二三十年代建成的英、法、意、德、西班牙等国风格建筑2000多栋。', 2, 1895, '天津市和平区成都道以南、马场道以北区域', 39.11666667, 117.20000000, '/images/attractions/five-avenue.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4688, '天津古文化街', '津门故里', '古文化街是天津最早的文化、宗教和商业聚集地，以天后宫为中心，集中了杨柳青年画、泥人张彩塑等传统手工艺。', 2, 1895, '天津市南开区古文化街', 39.13333333, 117.18333333, '/images/attractions/tianjin-oldstreet.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4689, '天津之眼', '世界上唯一建在桥上的摩天轮', '天津之眼是一座跨河建设、桥轮合一的摩天轮，直径110米，旋转一周约30分钟，可俯瞰天津市区景色。', 3, 1895, '天津市河北区李公祠大街与五马路交口', 39.15000000, 117.18333333, '/images/attractions/tianjineye.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '09:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4690, '意大利风情区', '地中海风情', '意大利风情区是原意大利租界，保存完整的欧洲建筑200余栋，马可波罗广场、但丁广场等景点充满异域风情。', 2, 1895, '天津市河北区自由道25号', 39.13333333, 117.20000000, '/images/attractions/italian-style.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4691, '黄崖关长城', '蓟北雄关', '黄崖关长城是明代长城的重要关隘，以雄险著称，城墙和敌楼保存完好，有“蓟北雄关”之称。', 2, 1896, '天津市蓟州区下营镇黄崖关村', 40.21666667, 117.48333333, '/images/attractions/huangyaguan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4692, '承德避暑山庄及周围寺庙', '清代夏宫', '避暑山庄是清代皇帝夏日避暑和处理政务的场所，由宫殿区、湖泊区、平原区、山峦区组成。周围寺庙融合汉、藏、蒙等民族建筑风格。', 2, 1898, '河北省承德市双桥区丽正门路20号', 40.98333333, 117.93333333, '/images/attractions/bishushanzhuang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '07:00-18:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4693, '山海关', '天下第一关', '山海关是明长城的东部起点，与万里之外的嘉峪关遥相呼应，有“天下第一关”之称。', 2, 1899, '河北省秦皇岛市山海关区', 40.00000000, 119.75000000, 'https://dimg04.c-ctrip.com/images/100r1f000001gonz01F00.jpg', '[\"https://dimg04.c-ctrip.com/images/100r1f000001gonz01F00.jpg\", \"https://dimg04.c-ctrip.com/images/10081f000001gqhpwF43B.jpg\", \"https://dimg04.c-ctrip.com/images/0102812000mpvr8aaE328.jpg\", \"https://dimg04.c-ctrip.com/images/10050u000000j9yvk90AE.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2n12000icklnu035D6.jpg\", \"https://dimg04.c-ctrip.com/images/0Z82e12000djlmni534B5_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '07:30-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4694, '北戴河', '中国夏都', '北戴河是著名的海滨度假胜地，拥有鸽子窝公园、老虎石公园、联峰山等景点，是避暑休闲的理想之地。', 4, 1899, '河北省秦皇岛市北戴河区', 39.83333333, 119.48333333, 'https://dimg04.c-ctrip.com/images/0105v120009hor1tm73F6.jpg', '[\"https://dimg04.c-ctrip.com/images/0105v120009hor1tm73F6.jpg\", \"https://dimg04.c-ctrip.com/images/0103q120004gikhjsBCEF.jpg\", \"https://dimg04.c-ctrip.com/images/01060120009hor19f02C9.jpg\", \"https://dimg04.c-ctrip.com/images/0103o12000nur5s1w91A3.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2x12000ickv3em3699.jpg\", \"https://dimg04.c-ctrip.com/images/27c3k12000na9jmdu23FE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4695, '野三坡风景名胜区', '太行山深处的世外桃源', '野三坡以“雄、险、奇、幽”著称，由百里峡、鱼谷洞、龙门天关等景区组成，是华北地区著名的自然风景区。', 1, 1900, '河北省保定市涞水县三坡镇', 39.63333333, 115.20000000, 'https://dimg04.c-ctrip.com/images/350716000001007pk0DB9.jpg', '[\"https://dimg04.c-ctrip.com/images/350716000001007pk0DB9.jpg\", \"https://dimg04.c-ctrip.com/images/0105e12000fcyidyq9E32.jpg\", \"https://dimg04.c-ctrip.com/images/0102i12000fcyig8z83BD.jpg\", \"https://dimg04.c-ctrip.com/images/0101j12000fcyi72o3D1F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1d12000ickkqsm1F9F.jpg\", \"https://dimg04.c-ctrip.com/images/0Z87012000fm9i2rs7482_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4696, '白洋淀', '华北明珠', '白洋淀是华北地区最大的淡水湖，由143个淀泊组成，芦苇摇曳，荷花飘香，是抗日战争时期雁翎队的战斗地。', 1, 1900, '河北省保定市安新县旅游东路', 38.91666667, 115.95000000, 'https://dimg04.c-ctrip.com/images/01048120008k1cmq97056.jpg', '[\"https://dimg04.c-ctrip.com/images/01048120008k1cmq97056.jpg\", \"https://dimg04.c-ctrip.com/images/01048120008k1cmq97056.jpg\", \"https://dimg04.c-ctrip.com/images/01048120008k1cmq97056.jpg\", \"https://dimg04.c-ctrip.com/images/01048120008k1cmq97056.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-17:30', '7-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4697, '西柏坡景区', '新中国从这里走来', '西柏坡是解放战争时期中共中央所在地，党中央在此指挥了三大战役，召开了七届二中全会。', 5, 1897, '河北省石家庄市平山县西柏坡镇', 38.33333333, 114.03333333, '/images/attractions/xibaipo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4698, '娲皇宫', '女娲补天处', '娲皇宫是神话传说中女娲抟土造人、炼石补天的地方，依山而建，悬空而立，是中国最大的女娲祭祀地。', 2, 1901, '河北省邯郸市涉县索堡镇', 36.58333333, 113.68333333, '/images/attractions/wahuanggong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4699, '崇礼滑雪场', '冬奥圣地', '崇礼是2022年北京冬奥会雪上项目举办地，拥有万龙、云顶、太舞等多家国际标准的滑雪场，是中国最大的滑雪度假区。', 4, 1902, '河北省张家口市崇礼区', 40.96666667, 115.28333333, '/images/attractions/chongli.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 300.00, NULL, '08:30-16:30', '12-3月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4700, '云冈石窟', '中国四大石窟之一', '云冈石窟开凿于北魏时期，现存主要洞窟45个，造像59000余尊，是中国佛教艺术第一个巅峰时期的经典杰作。', 2, 1904, '山西省大同市云冈区云冈镇', 40.11666667, 113.16666667, 'https://dimg04.c-ctrip.com/images/1lo2c12000rhitlf82992.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2c12000rhitlf82992.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2c12000rhitlf82992.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2c12000rhitlf82992.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2c12000rhitlf82992.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4701, '五台山', '中国四大佛教名山之首', '五台山是文殊菩萨的道场，由五座台顶组成，现存寺院47处，台内39处，台外8处，是中国唯一兼有汉传佛教和藏传佛教的圣地。', 2, 1905, '山西省忻州市五台县台怀镇', 38.96666667, 113.56666667, 'https://dimg04.c-ctrip.com/images/0105e120004gpgjbp5392.jpg', '[\"https://dimg04.c-ctrip.com/images/0105e120004gpgjbp5392.jpg\", \"https://dimg04.c-ctrip.com/images/0102w12000falrh07722C.jpg\", \"https://dimg04.c-ctrip.com/images/0101e12000jgvixpx408E.jpg\", \"https://dimg04.c-ctrip.com/images/0103h12000jgvj5h410C7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3712000icl5kgq6A5B.jpg\", \"https://dimg04.c-ctrip.com/images/Z80t16000000zqfky9B31_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 135.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4702, '平遥古城', '中国保存最完整的明清县城', '平遥古城是中国汉民族地区现存最为完整的古城，城墙、街道、店铺、民居保存完好，是研究明清城市的活化石。', 2, 1906, '山西省晋中市平遥县', 37.20000000, 112.16666667, 'https://dimg04.c-ctrip.com/images/0102z12000f6pnna58EEF.jpg', '[\"https://dimg04.c-ctrip.com/images/0102z12000f6pnna58EEF.jpg\", \"https://dimg04.c-ctrip.com/images/0100512000jcndabi1D54.jpg\", \"https://dimg04.c-ctrip.com/images/0100p12000jcnd016FE50.jpg\", \"https://dimg04.c-ctrip.com/images/0104a12000o9ofgxuC38A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4a12000ickktku70DA.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85m1200086tsr8kCBDF_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 125.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4703, '乔家大院', '皇家看故宫，民宅看乔家', '乔家大院是清代晋商乔致庸的宅邸，建筑精美，布局讲究，电影《大红灯笼高高挂》在此取景。', 2, 1906, '山西省晋中市祁县乔家堡村', 37.35000000, 112.33333333, 'https://dimg04.c-ctrip.com/images/0HJ5n12000g8zzaev8D50.jpg', '[\"https://dimg04.c-ctrip.com/images/0HJ5n12000g8zzaev8D50.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0c12000ieexf6o6CEA.jpg\", \"https://dimg04.c-ctrip.com/images/0106q12000lhv48u47CBB.jpg\", \"https://dimg04.c-ctrip.com/images/0100p120009szg7ydBE42.jpg\", \"https://dimg04.c-ctrip.com/images/0104a120009qykxnrA48D.jpg\", \"https://dimg04.c-ctrip.com/images/01022120008xunyvk31A1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 115.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4704, '雁门关', '中华第一关', '雁门关是长城上的重要关隘，以“险”著称，自古就有“天下九塞，雁门为首”之说，是古代中原抵御北方游牧民族的屏障。', 2, 1905, '山西省忻州市代县雁门关镇', 39.20000000, 112.91666667, 'https://dimg04.c-ctrip.com/images/100u1c000001drtqo986B.jpg', '[\"https://dimg04.c-ctrip.com/images/100u1c000001drtqo986B.jpg\", \"https://dimg04.c-ctrip.com/images/0104v12000fcxaptn11D0.jpg\", \"https://dimg04.c-ctrip.com/images/0106t1200086vhiyeD4D4.jpg\", \"https://dimg04.c-ctrip.com/images/0104h1200082j93af7A82.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1l12000iclg0yiE949.jpg\", \"https://dimg04.c-ctrip.com/images/Z80t16000000zqfky9B31_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4705, '悬空寺', '天下奇观', '悬空寺建于北魏后期，建在恒山金龙峡翠屏峰的悬崖峭壁上，楼阁悬空，结构奇巧，是国内仅存的佛、道、儒三教合一的寺庙。', 2, 1904, '山西省大同市浑源县东南郊恒山脚下', 39.66666667, 113.71666667, 'https://dimg04.c-ctrip.com/images/0100412000ilk58yz1285.jpg', '[\"https://dimg04.c-ctrip.com/images/0100412000ilk58yz1285.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0112000icnvr9x55EE.jpg\", \"https://dimg04.c-ctrip.com/images/0101w1200092oimbwED00.jpg\", \"https://dimg04.c-ctrip.com/images/0101y1200086wwijz1B8A.jpg\", \"https://dimg04.c-ctrip.com/images/010521200087edgx398A8.jpg\", \"https://dimg04.c-ctrip.com/images/010011200082e5z476113.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 115.00, NULL, '08:30-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4706, '壶口瀑布', '黄河奇观', '壶口瀑布是中国第二大瀑布，黄河奔流至此，两岸石壁峭立，河口收束狭如壶口，形成壮观的瀑布景观。', 1, 1907, '山西省临汾市吉县壶口镇', 36.15000000, 110.45000000, 'https://dimg04.c-ctrip.com/images/1mh0u12000g6xo0or9211.jpg', '[\"https://dimg04.c-ctrip.com/images/1mh0u12000g6xo0or9211.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1012000icykpxv33AD.jpg\", \"https://dimg04.c-ctrip.com/images/zc0l170000011e3741A91_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2x12000g3858rjDD3C.jpg\", \"https://dimg04.c-ctrip.com/images/1mh5d12000g38hhvx9244.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2k12000g37pibjC989.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '06:30-19:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4707, '晋祠', '山西小江南', '晋祠是为纪念晋国开国诸侯唐叔虞而建，是中国现存最早的皇家园林。圣母殿、鱼沼飞梁、献殿被誉为“晋祠三宝”。', 2, 1903, '山西省太原市晋源区晋祠镇', 37.70000000, 112.43333333, '/images/attractions/jinci.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4708, '呼伦贝尔大草原', '世界四大草原之一', '呼伦贝尔大草原是中国保存最完好的草原，水草丰美，有“牧草王国”之称。夏季绿草如茵，牛羊成群，是体验草原风情的理想之地。', 1, 1910, '内蒙古呼伦贝尔市陈巴尔虎旗', 49.35000000, 119.75000000, 'https://dimg04.c-ctrip.com/images/10091f000001gso4wC2C0.jpg', '[\"https://dimg04.c-ctrip.com/images/10091f000001gso4wC2C0.jpg\", \"https://dimg04.c-ctrip.com/images/0105u120008a5mrb8DD73.jpg\", \"https://dimg04.c-ctrip.com/images/100b180000014fr36197F.jpg\", \"https://dimg04.c-ctrip.com/images/0105912000j0h49tpE37D.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1612000ico9z7w1FAB.jpg\", \"https://dimg04.c-ctrip.com/images/1mh5f12000gb3m7ksF497.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '6-8月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4709, '成吉思汗陵', '一代天骄长眠地', '成吉思汗陵是蒙古族人民心中的圣地，陵园由三座蒙古包式的大殿相连，供奉着成吉思汗的灵帐、遗物等。', 2, 1911, '内蒙古鄂尔多斯市伊金霍洛旗', 39.36666667, 109.71666667, 'https://dimg04.c-ctrip.com/images/0106k12000ax99j74586C.jpg', '[\"https://dimg04.c-ctrip.com/images/0106k12000ax99j74586C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4r12000icxa6cf4F8E.jpg\", \"https://dimg04.c-ctrip.com/images/Z80s11000000qj6wiE602_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/01033120006ysm6a86CF5.jpg\", \"https://dimg04.c-ctrip.com/images/0105l120006ysmtayEBA7.jpg\", \"https://dimg04.c-ctrip.com/images/01062120006ysmwfm3157.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4710, '响沙湾', '这里的沙子会唱歌', '响沙湾是库布其沙漠的边缘地带，因沙子滑动时会发出响声而得名。景区集沙漠观光、滑沙、沙漠越野于一体。', 1, 1911, '内蒙古鄂尔多斯市达拉特旗', 40.35000000, 109.90000000, 'https://dimg04.c-ctrip.com/images/1lo2212000bcbgk9l60B7.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2212000bcbgk9l60B7.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2212000bcbgk9l60B7.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2212000bcbgk9l60B7.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2212000bcbgk9l60B7.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '08:00-19:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4711, '满洲里国门景区', '中国陆路口岸之最', '满洲里国门是中国陆路口岸中规模最大的国门，第五代国门庄严雄伟，可俯瞰俄罗斯后贝加尔斯克小镇。', 5, 1910, '内蒙古呼伦贝尔市满洲里市', 49.61666667, 117.45000000, 'https://dimg04.c-ctrip.com/images/100i1a0000019r06u14C1.jpg', '[\"https://dimg04.c-ctrip.com/images/100i1a0000019r06u14C1.jpg\", \"https://dimg04.c-ctrip.com/images/100i1a0000019r06u14C1.jpg\", \"https://dimg04.c-ctrip.com/images/100i1a0000019r06u14C1.jpg\", \"https://dimg04.c-ctrip.com/images/100i1a0000019r06u14C1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4712, '阿尔山国家森林公园', '大兴安岭明珠', '阿尔山国家森林公园集原始森林、火山遗迹、温泉、天池于一体，有驼峰岭天池、三潭峡、石塘林等景点。', 1, 1914, '内蒙古兴安盟阿尔山市', 47.18333333, 120.46666667, 'https://dimg04.c-ctrip.com/images/1005180000015chbo1954.jpg', '[\"https://dimg04.c-ctrip.com/images/1005180000015chbo1954.jpg\", \"https://dimg04.c-ctrip.com/images/1005180000015chbo1954.jpg\", \"https://dimg04.c-ctrip.com/images/1005180000015chbo1954.jpg\", \"https://dimg04.c-ctrip.com/images/1005180000015chbo1954.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 180.00, NULL, '07:00-17:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4713, '额济纳胡杨林', '生而不死一千年', '额济纳胡杨林是世界上仅存的三大胡杨林之一，每年10月，胡杨树叶金黄灿烂，与沙漠、湖泊构成绝美画卷。', 1, 1913, '内蒙古阿拉善盟额济纳旗', 41.95000000, 101.06666667, '/images/attractions/ejina.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 240.00, NULL, '08:00-19:00', '10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4714, '乌兰布统草原', '欧式草原', '乌兰布统是清朝皇家围场，草原、湖泊、丘陵、森林并存，是《还珠格格》等影视剧的取景地。', 1, 1912, '内蒙古赤峰市克什克腾旗', 42.48333333, 117.23333333, '/images/attractions/wulanbutong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:34:56', '2026-03-19 18:34:56');
INSERT INTO `attraction` VALUES (4827, '沈阳故宫', '关外紫禁城', '沈阳故宫是清朝初期的皇宫，始建于1625年，占地6万平方米，有建筑114座，是除北京故宫外中国仅存的古代皇宫建筑群。', 2, 1915, '辽宁省沈阳市沈河区沈阳路171号', 41.79611111, 123.44972222, 'https://dimg04.c-ctrip.com/images/0100i12000jn8cd9nE3D8.jpg', '[\"https://dimg04.c-ctrip.com/images/0100i12000jn8cd9nE3D8.jpg\", \"https://dimg04.c-ctrip.com/images/0100i12000jn8cd9nE3D8.jpg\", \"https://dimg04.c-ctrip.com/images/0100i12000jn8cd9nE3D8.jpg\", \"https://dimg04.c-ctrip.com/images/0100i12000jn8cd9nE3D8.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4828, '大连金石滩国家旅游度假区', '神力雕塑公园', '金石滩拥有独特的海岸奇石景观，恐龙探海、龟裂石等地质奇观闻名遐迩，还有发现王国主题乐园。', 1, 1916, '辽宁省大连市金州区金石路', 39.08333333, 121.96666667, '/images/attractions/jinshitan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '08:30-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4829, '老虎滩海洋公园', '海洋世界', '老虎滩海洋公园集海洋动物展示、表演、娱乐于一体，拥有极地馆、珊瑚馆、鸟语林、海兽馆等。', 3, 1916, '辽宁省大连市中山区滨海中路9号', 38.86666667, 121.65000000, 'https://dimg04.c-ctrip.com/images/0105o12000kx48p8iCCF6.jpg', '[\"https://dimg04.c-ctrip.com/images/0105o12000kx48p8iCCF6.jpg\", \"https://dimg04.c-ctrip.com/images/0103o12000f6s0xl5CA0D.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5212000d38c35h9369.png\", \"https://dimg04.c-ctrip.com/images/1lo1r12000d38bh2m4FE7.png\", \"https://dimg04.c-ctrip.com/images/0zg7312000icl8m3e9FE8.jpg\", \"https://dimg04.c-ctrip.com/images/27c2112000na9j9p95174_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 220.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4830, '千山风景名胜区', '东北明珠', '千山由近千座山峰组成，以奇峰、岩松、古庙、梨花著称，有“无峰不奇，无石不峭，无寺不古”之誉。', 1, 1917, '辽宁省鞍山市铁东区千山东路', 41.01666667, 123.03333333, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2h12000no6do8218B3.jpg\", \"https://dimg04.c-ctrip.com/images/01065120005zkw9he9249.jpg\", \"https://dimg04.c-ctrip.com/images/01021120005znwtdt0DCB.jpg\", \"https://dimg04.c-ctrip.com/images/0104w12000abs7wzu7EE8.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1412000hpsh2vs7B1F.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '06:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4831, '本溪水洞', '世界最长可供游览的地下暗河', '本溪水洞是数百万年前形成的大型石灰岩充水溶洞，暗河全长5800米，可乘船游览，洞内钟乳石千姿百态。', 1, 1918, '辽宁省本溪市本溪满族自治县', 41.30000000, 124.10000000, 'https://dimg04.c-ctrip.com/images/1lo6412000gk76ta7E6BB.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6412000gk76ta7E6BB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6412000gk76ta7E6BB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6412000gk76ta7E6BB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6412000gk76ta7E6BB.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 140.00, NULL, '08:30-16:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4832, '鸭绿江断桥', '抗美援朝见证', '鸭绿江断桥原为鸭绿江上第一座桥，抗美援朝期间被美军炸毁，现作为历史遗迹向游客开放，见证中朝友谊。', 5, 1919, '辽宁省丹东市振兴区江岸路', 40.11666667, 124.38333333, '/images/attractions/yalujiang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4833, '红海滩风景廊道', '世界红色海岸线', '红海滩因碱蓬草生长而形成，秋季碱蓬草变红，与芦苇荡、稻田画构成壮丽景观，是摄影爱好者的天堂。', 1, 1920, '辽宁省盘锦市大洼区赵圈河镇', 40.96666667, 121.95000000, '/images/attractions/honghaitan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '08:30-17:00', '9-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4834, '长白山景区', '关东第一山', '长白山是中国东北最高山，主峰白头山海拔2691米。天池是中国最深的湖泊，也是松花江、图们江、鸭绿江三江之源。', 1, 1950, '吉林省延边州安图县二道白河镇', 42.00000000, 128.06666667, '/images/attractions/changbaishan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 190.00, NULL, '07:00-17:00', '7-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4835, '伪满皇宫博物院', '中国三大宫廷遗址之一', '伪满皇宫是清朝末代皇帝溥仪在日本扶持下建立的傀儡政权皇宫，建筑融合中日风格，是研究近代史的重要场所。', 2, 1948, '吉林省长春市宽城区光复北路5号', 43.90000000, 125.33333333, 'https://dimg04.c-ctrip.com/images/1A0w1d000001ell24858D.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0w1d000001ell24858D.jpg\", \"https://dimg04.c-ctrip.com/images/0104e120005zeufdkB9E4.jpg\", \"https://dimg04.c-ctrip.com/images/0104q12000hymtdqe54F8.jpg\", \"https://dimg04.c-ctrip.com/images/0106r12000hymtf1qA615.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4b12000icm8oe170DE.jpg\", \"https://dimg04.c-ctrip.com/images/0Z82q120008f73cl396C6_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4836, '净月潭', '亚洲最大人工林海', '净月潭因形似弯月而得名，森林覆盖率达96%，有“绿海明珠”之称，是长春市的天然氧吧和休闲胜地。', 1, 1948, '吉林省长春市南关区净月大街', 43.78333333, 125.43333333, 'https://dimg04.c-ctrip.com/images/01065120005zkw9he9249.jpg', '[\"https://dimg04.c-ctrip.com/images/01065120005zkw9he9249.jpg\", \"https://dimg04.c-ctrip.com/images/0101v12000f80s0izDD04.jpg\", \"https://dimg04.c-ctrip.com/images/0105q120005zda3pk3363.jpg\", \"https://dimg04.c-ctrip.com/images/0100j12000f80rcdv0502.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5712000ickovxi7156.jpg\", \"https://dimg04.c-ctrip.com/images/0Z82l12000getpj3v9699_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4837, '雾凇岛', '中国四大自然奇观之一', '雾凇岛因冬季雾凇而得名，每年12月至次年2月，岛上树木挂满晶莹剔透的雾凇，宛如仙境。', 1, 1949, '吉林省吉林市龙潭区乌拉街满族镇', 44.08333333, 126.56666667, 'https://dimg04.c-ctrip.com/images/0104z12000rd7h6crFD88.jpg', '[\"https://dimg04.c-ctrip.com/images/0104z12000rd7h6crFD88.jpg\", \"https://dimg04.c-ctrip.com/images/0103v1200088l8nda6023.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1912000cz84xgi5DC7.jpg\", \"https://dimg04.c-ctrip.com/images/10081b000001a90mfDF39.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1012000icknzt71433.jpg\", \"https://dimg04.c-ctrip.com/images/0Z822120008n7njob7B10_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '全天', '12-2月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4838, '六鼎山文化旅游区', '佛教文化与自然风光', '六鼎山拥有世界最高释迦牟尼青铜坐佛——金鼎大佛，以及正觉寺、清祖祠等景点，是集佛教文化、渤海文化于一体的景区。', 2, 1950, '吉林省延边州敦化市南郊', 43.35000000, 128.21666667, 'https://dimg04.c-ctrip.com/images/01A3c12000915x6fq1021.jpg', '[\"https://dimg04.c-ctrip.com/images/01A3c12000915x6fq1021.jpg\", \"https://dimg04.c-ctrip.com/images/01A3c12000915x6fq1021.jpg\", \"https://dimg04.c-ctrip.com/images/01A3c12000915x6fq1021.jpg\", \"https://dimg04.c-ctrip.com/images/01A3c12000915x6fq1021.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4839, '哈尔滨冰雪大世界', '世界最大冰雪主题乐园', '哈尔滨冰雪大世界每年冬季在松花江畔建造，用冰雪打造出梦幻的童话世界，冰雕、雪雕、冰滑梯等娱乐项目丰富。', 3, 1952, '黑龙江省哈尔滨市松北区太阳岛西区', 45.78333333, 126.55000000, 'https://dimg04.c-ctrip.com/images/1lo0i12000jh0ef7sF29A.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0i12000jh0ef7sF29A.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4312000d91fbo0FB3E.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5012000d91fsft7F01.jpg\", \"https://dimg04.c-ctrip.com/images/1lo7212000rl8zjlh4045.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4g12000ickkdu250F4.jpg\", \"https://dimg04.c-ctrip.com/images/1h66c12000opsogic5A15_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 330.00, NULL, '11:00-22:00', '12-2月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4840, '太阳岛风景名胜区', '哈尔滨的城市绿肺', '太阳岛是松花江中的沙丘岛，夏季是避暑胜地，冬季是雪博会举办地。', 1, 1952, '黑龙江省哈尔滨市松北区太阳岛', 45.80000000, 126.56666667, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0y12000myb2aba0B3C.jpg\", \"https://dimg04.c-ctrip.com/images/010511200087crk19504B.jpg\", \"https://dimg04.c-ctrip.com/images/0100112000aa36bm74B38.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000ln73y5fE300.jpg\", \"https://dimg04.c-ctrip.com/images/350u1c000001dkw3mCDBA.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4841, '圣索菲亚教堂', '哈尔滨地标', '圣索菲亚教堂是远东地区最大的东正教教堂，建于1907年，拜占庭式建筑风格，现为建筑艺术博物馆。', 2, 1952, '黑龙江省哈尔滨市道里区透笼街88号', 45.76666667, 126.61666667, 'https://dimg04.c-ctrip.com/images/0101y12000rqt2s7hD680.jpg', '[\"https://dimg04.c-ctrip.com/images/0101y12000rqt2s7hD680.jpg\", \"https://dimg04.c-ctrip.com/images/0101y12000rqt2s7hD680.jpg\", \"https://dimg04.c-ctrip.com/images/0101y12000rqt2s7hD680.jpg\", \"https://dimg04.c-ctrip.com/images/0101y12000rqt2s7hD680.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 20.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4842, '中央大街', '东方小巴黎', '中央大街是哈尔滨最繁华的商业街，全长1450米，铺有方石路，两侧汇集了文艺复兴、巴洛克等风格的欧式建筑。', 2, 1952, '黑龙江省哈尔滨市道里区中央大街', 45.76666667, 126.61666667, 'https://dimg04.c-ctrip.com/images/100q0z000000nrju094B1.jpg', '[\"https://dimg04.c-ctrip.com/images/100q0z000000nrju094B1.jpg\", \"https://dimg04.c-ctrip.com/images/100q0z000000nrju094B1.jpg\", \"https://dimg04.c-ctrip.com/images/100q0z000000nrju094B1.jpg\", \"https://dimg04.c-ctrip.com/images/100q0z000000nrju094B1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4843, '镜泊湖', '中国最大高山堰塞湖', '镜泊湖是5000年前火山喷发形成的堰塞湖，湖水清澈，瀑布壮观，吊水楼瀑布是中国三大瀑布之一。', 1, 1954, '黑龙江省牡丹江市宁安市', 43.88333333, 128.93333333, '/images/attractions/jingpo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4844, '中国雪乡', '中国冰雪第一村', '雪乡因积雪期长、雪质好而得名，积雪最深处可达2米，夜晚红灯笼映照下，宛如童话世界。', 1, 1954, '黑龙江省牡丹江市海林市大海林林业局', 44.36666667, 128.21666667, 'https://dimg04.c-ctrip.com/images/0102q120006dfdcvt51BB.jpg', '[\"https://dimg04.c-ctrip.com/images/0102q120006dfdcvt51BB.jpg\", \"https://dimg04.c-ctrip.com/images/0102q120006dfdcvt51BB.jpg\", \"https://dimg04.c-ctrip.com/images/0102q120006dfdcvt51BB.jpg\", \"https://dimg04.c-ctrip.com/images/0102q120006dfdcvt51BB.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '全天', '12-2月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4845, '五大连池风景区', '天然火山博物馆', '五大连池是由火山喷发形成的堰塞湖，拥有14座火山、5个串珠状湖泊，是世界地质公园，以冷矿泉闻名。', 1, 1956, '黑龙江省黑河市五大连池市', 48.71666667, 126.20000000, 'https://dimg04.c-ctrip.com/images/0103t120009lbiy390508.jpg', '[\"https://dimg04.c-ctrip.com/images/0103t120009lbiy390508.jpg\", \"https://dimg04.c-ctrip.com/images/0103t120009lbiy390508.jpg\", \"https://dimg04.c-ctrip.com/images/0103t120009lbiy390508.jpg\", \"https://dimg04.c-ctrip.com/images/0103t120009lbiy390508.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4846, '北极村', '中国最北', '北极村是中国大陆最北端的临江村镇，可观赏北极光、极昼现象，有最北哨所、最北邮局、最北人家等打卡点。', 1, 1957, '黑龙江省大兴安岭地区漠河市北极镇', 53.48333333, 122.35000000, 'https://dimg04.c-ctrip.com/images/0100h12000f6se7skAB64.jpg', '[\"https://dimg04.c-ctrip.com/images/0100h12000f6se7skAB64.jpg\", \"https://dimg04.c-ctrip.com/images/0100h12000f6se7skAB64.jpg\", \"https://dimg04.c-ctrip.com/images/0100h12000f6se7skAB64.jpg\", \"https://dimg04.c-ctrip.com/images/0100h12000f6se7skAB64.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 68.00, NULL, '全天', '6-8月、12-2月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4847, '扎龙自然保护区', '丹顶鹤的故乡', '扎龙是世界上最大的丹顶鹤繁殖地，每年有数百只丹顶鹤在此栖息，可观赏丹顶鹤放飞表演。', 1, 1953, '黑龙江省齐齐哈尔市铁锋区扎龙镇', 47.20000000, 124.20000000, '/images/attractions/zhalong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4848, '上海迪士尼乐园', '奇幻童话城堡', '上海迪士尼乐园是中国大陆第一个迪士尼主题乐园，拥有七大主题园区，包括米奇大街、奇想花园、探险岛、宝藏湾、明日世界、梦幻世界、玩具总动员。', 3, 1958, '上海市浦东新区川沙新镇黄赵路310号', 31.14555556, 121.66527778, '/images/attractions/shanghai-disney.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 399.00, NULL, '09:00-20:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4849, '东方明珠广播电视塔', '上海地标', '东方明珠高468米，是上海的地标性建筑，塔上有悬空观光廊、旋转餐厅等，可俯瞰黄浦江两岸风光。', 3, 1958, '上海市浦东新区世纪大道1号', 31.23916667, 121.49944444, '/images/attractions/oriental-pearl.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 199.00, NULL, '09:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4850, '外滩', '万国建筑博览群', '外滩是上海的象征，黄浦江西岸矗立着52幢风格各异的大楼，被誉为“万国建筑博览群”。对岸是陆家嘴金融区。', 2, 1958, '上海市黄浦区中山东一路', 31.23638889, 121.48527778, 'https://dimg04.c-ctrip.com/images/0102p1200082jbvtcD451.jpg', '[\"https://dimg04.c-ctrip.com/images/0102p1200082jbvtcD451.jpg\", \"https://dimg04.c-ctrip.com/images/100s0f0000007gibsA35A.jpg\", \"https://dimg04.c-ctrip.com/images/01038120006d693ko385C.jpg\", \"https://dimg04.c-ctrip.com/images/100o0b0000005bxej3E7E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6y12000ickozqp82F9.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84a120008ntubhfB0EF_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4851, '豫园', '江南古典园林', '豫园始建于明代，是典型的江南古典园林，园内亭台楼阁、假山池塘精巧别致，与城隍庙相邻。', 2, 1958, '上海市黄浦区安仁街218号', 31.22750000, 121.48805556, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2a12000joxkqaeF772.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000iznjmym62D5.jpg\", \"https://dimg04.c-ctrip.com/images/0105412000fcw2ugxC7B4.jpg\", \"https://dimg04.c-ctrip.com/images/0104t12000k12ya40394B.jpg\", \"https://dimg04.c-ctrip.com/images/0102712000cf853ci1CBB.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:45-16:45', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4852, '上海野生动物园', '国家5A级景区', '上海野生动物园是中国首座国家级野生动物园，拥有大熊猫、金丝猴等珍稀动物，可车入区、步行区游览。', 3, 1958, '上海市浦东新区南六公路178号', 31.05277778, 121.72611111, 'https://dimg04.c-ctrip.com/images/1lo2i12000rv6by6819B5.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2i12000rv6by6819B5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5p12000hxsg5qsBA00.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4e12000hxsi46p2C79.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4512000hxsgblzA223.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5m12000hxsgbxv82E6.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1b12000ickpof3BD3D.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4853, '上海科技馆', '科普殿堂', '上海科技馆以“自然·人·科技”为主题，有生物万象、地壳探秘、彩虹乐园等11个展区，互动体验丰富。', 3, 1958, '上海市浦东新区世纪大道2000号', 31.21805556, 121.54250000, 'https://dimg04.c-ctrip.com/images/0103b12000lkrnxjv140B.jpg', '[\"https://dimg04.c-ctrip.com/images/0103b12000lkrnxjv140B.jpg\", \"https://dimg04.c-ctrip.com/images/0105g1200087d6lidB450.jpg\", \"https://dimg04.c-ctrip.com/images/0101d12000lkrmdqjFBBA.jpg\", \"https://dimg04.c-ctrip.com/images/0101812000lkrk1m27893.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2z12000icl4354A5BE.jpg\", \"https://dimg04.c-ctrip.com/images/0103b12000lkrnxjv140B_Z_1000_0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 45.00, NULL, '09:00-17:15', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4854, '中山陵', '中国近代建筑史上第一陵', '中山陵是孙中山先生的陵寝，依山而建，气势恢宏，392级台阶象征着当时中国的3亿9千2百万人口。', 5, 1960, '江苏省南京市玄武区石象路7号', 32.06138889, 118.85027778, 'https://dimg04.c-ctrip.com/images/100h11000000ripuy3B79.jpg', '[\"https://dimg04.c-ctrip.com/images/100h11000000ripuy3B79.jpg\", \"https://dimg04.c-ctrip.com/images/100r0n000000eg700A328.jpg\", \"https://dimg04.c-ctrip.com/images/100b1f000001gso2vEBE4.jpg\", \"https://dimg04.c-ctrip.com/images/100g0y000000ltbqk4AF7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3e12000icksd222EA5.jpg\", \"https://dimg04.c-ctrip.com/images/1h65d120008ni3kxyAE3F_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4855, '夫子庙-秦淮风光带', '中国四大文庙之一', '夫子庙是供奉孔子的庙宇，周边秦淮河畔是南京最繁华的商业区，可品尝小吃、乘坐画舫夜游秦淮河。', 2, 1960, '江苏省南京市秦淮区贡院西街', 32.02083333, 118.78583333, 'https://dimg04.c-ctrip.com/images/100g1f000001gqya4D90B.jpg', '[\"https://dimg04.c-ctrip.com/images/100g1f000001gqya4D90B.jpg\", \"https://dimg04.c-ctrip.com/images/100p12000000s1um90B6D.jpg\", \"https://dimg04.c-ctrip.com/images/10070y000000mksq823D9.jpg\", \"https://dimg04.c-ctrip.com/images/100s0g00000086s9zD645.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5j12000icle7qq74F3.jpg\", \"https://dimg04.c-ctrip.com/images/Z80u0w000000k9tyr3474_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4856, '明孝陵', '明清皇家第一陵', '明孝陵是明太祖朱元璋与马皇后的合葬陵墓，开创了明清帝陵的规制，神道石刻精美。', 2, 1960, '江苏省南京市玄武区紫金山南麓', 32.06166667, 118.84416667, 'https://dimg04.c-ctrip.com/images/0106x120008c3xrzo253C.jpg', '[\"https://dimg04.c-ctrip.com/images/0106x120008c3xrzo253C.jpg\", \"https://dimg04.c-ctrip.com/images/0104z12000izt9yws33B9.jpg\", \"https://dimg04.c-ctrip.com/images/0105d1200087rbz9x8778.jpg\", \"https://dimg04.c-ctrip.com/images/100g0y000000ltasp53F4.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4312000ickoi7b153C.jpg\", \"https://dimg04.c-ctrip.com/images/1h62x120008iq1k6wB093_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '06:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4857, '总统府', '中国近代史博物馆', '总统府是中国近代建筑遗存中规模最大、保存最完整的建筑群，曾是太平天国天王府、中华民国总统府。', 5, 1960, '江苏省南京市玄武区长江路292号', 32.04722222, 118.79250000, '/images/attractions/presidential-palace.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4858, '拙政园', '中国园林之母', '拙政园是苏州最大的古典园林，以水为中心，亭台楼榭皆临水而建，具有浓郁的江南水乡特色。', 2, 1961, '江苏省苏州市姑苏区东北街178号', 31.32611111, 120.62527778, 'https://dimg04.c-ctrip.com/images/1lo1r12000ddckfh27420.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1r12000ddckfh27420.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5g12000ddcjzuiD305.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1k12000ddck5226264.jpg\", \"https://dimg04.c-ctrip.com/images/010301200087cs4sb1EFF.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6x12000ickms9v3D82.jpg\", \"https://dimg04.c-ctrip.com/images/0Z83u12000iz3eicb3D89_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4859, '留园', '中国四大名园之一', '留园以建筑布局精巧著称，厅堂宏敞华丽，庭院富有变化，冠云峰是太湖石中的珍品。', 2, 1961, '江苏省苏州市姑苏区阊门外留园路338号', 31.31888889, 120.59500000, 'https://dimg04.c-ctrip.com/images/1A0h15000000y5fksF33A.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0h15000000y5fksF33A.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g1/M04/7D/24/CghzfFWwzv2AG--_AA8UEqqDiu0460.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5s12000ddcl3hl5E0D.jpg\", \"https://dimg04.c-ctrip.com/images/0105u12000izsze2u7414.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4t12000icm6wd3C8DA.jpg\", \"https://dimg04.c-ctrip.com/images/0Z841120009dx8i2k4556_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4860, '周庄古镇', '中国第一水乡', '周庄是江南水乡古镇的典范，小桥流水人家，有双桥、沈厅、张厅等景点。', 2, 1961, '江苏省苏州市昆山市周庄镇', 31.11805556, 120.85000000, '/images/attractions/zhouzhuang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:30-20:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4861, '同里古镇', '东方小威尼斯', '同里古镇被五湖环抱，网状河流将镇区分割成七个小岛，有退思园、三桥等景点。', 2, 1961, '江苏省苏州市吴江区同里镇', 31.15583333, 120.71583333, 'https://dimg04.c-ctrip.com/images/1A04170000011owx6650C.jpg', '[\"https://dimg04.c-ctrip.com/images/1A04170000011owx6650C.jpg\", \"https://dimg04.c-ctrip.com/images/350m1e000001fdld58145.jpg\", \"https://dimg04.c-ctrip.com/images/100m0g00000087brh49B1.jpg\", \"https://dimg04.c-ctrip.com/images/010511200086ww9beAED7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5a12000icknmnb307F.jpg\", \"https://dimg04.c-ctrip.com/images/zc0e170000011go8z7956_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4862, '虎丘山', '吴中第一名胜', '虎丘山有2500多年历史，云岩寺塔（虎丘塔）是世界第二斜塔，苏东坡曾言“到苏州不游虎丘，乃憾事也”。', 2, 1961, '江苏省苏州市姑苏区虎丘山门内8号', 31.33611111, 120.57722222, 'https://dimg04.c-ctrip.com/images/1lo1c12000bd0rvagE751.png', '[\"https://dimg04.c-ctrip.com/images/1lo1c12000bd0rvagE751.png\", \"https://dimg04.c-ctrip.com/images/0102712000rqetkq2BBE1.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1o12000fuik8g81110.jpg\", \"https://dimg04.c-ctrip.com/images/0105l1200086v5g48A644.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4912000ickoxuq8E5D.jpg\", \"https://dimg04.c-ctrip.com/images/0Z841120009dx8i2k4556_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4863, '鼋头渚', '太湖佳绝处', '鼋头渚是太湖风景的精华所在，有充山隐秀、鹿顶迎晖、鼋渚春涛等景点，春季樱花盛开时尤为美丽。', 1, 1962, '江苏省无锡市滨湖区鼋渚路1号', 31.52138889, 120.23555556, '/images/attractions/yuantouzhu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-17:00', '3-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4864, '灵山大佛', '神州五方五佛之一', '灵山大佛高88米，是世界上最高的青铜佛像，景区还有九龙灌浴、梵宫等景点，气势恢宏。', 2, 1962, '江苏省无锡市滨湖区马山镇灵山路1号', 31.44055556, 120.09583333, 'https://dimg04.c-ctrip.com/images/1lo0j12000mgsrm13C29F.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0j12000mgsrm13C29F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3p12000mgsri9c2FDA.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1d12000mgsrjvvF38F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0812000mgsr32pBE8A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0e12000icks5pwD69B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4z12000e13laym1F2E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 210.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4865, '中央电视台无锡影视基地', '三国水浒城', '无锡影视基地是央视为拍摄《三国演义》《水浒传》而建，可观看马术表演、乘古船游太湖。', 3, 1962, '江苏省无锡市滨湖区山水西路', 31.52138889, 120.23555556, '/images/attractions/wuxi-film.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4866, '瘦西湖', '园林之盛，甲于天下', '瘦西湖是扬州著名的风景名胜区，湖面瘦长，犹如彩带般飘动，有长堤春柳、徐园、小金山、五亭桥、白塔等景点。', 1, 1963, '江苏省扬州市邗江区大虹桥路28号', 32.40111111, 119.42888889, 'https://dimg04.c-ctrip.com/images/100chk124drqf7c1sB82E.jpg', '[\"https://dimg04.c-ctrip.com/images/100chk124drqf7c1sB82E.jpg\", \"https://dimg04.c-ctrip.com/images/0102312000f9e7wum8841.jpg\", \"https://dimg04.c-ctrip.com/images/100p12000000s1wng4ACF.jpg\", \"https://dimg04.c-ctrip.com/images/0104u120002d69kzwBB36.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1212000ickkouz9E9B.jpg\", \"https://dimg04.c-ctrip.com/images//Z80b0i0000009erus7015_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '06:30-17:30', '3-5月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4867, '个园', '中国四大名园之一', '个园以叠石艺术著称，用石笋、太湖石、黄石、宣石叠成四季假山，融造园法则与山水画理于一体。', 2, 1963, '江苏省扬州市广陵区盐阜东路10号', 32.39277778, 119.43888889, 'https://dimg04.c-ctrip.com/images/0102512000bdvwphq34ED.jpg', '[\"https://dimg04.c-ctrip.com/images/0102512000bdvwphq34ED.jpg\", \"https://dimg04.c-ctrip.com/images/0101g12000c165ym1AE98.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4212000iemdf9cA0A0.jpg\", \"https://dimg04.c-ctrip.com/images/27c0812000na9jbqk7A54_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/010671200087d4o7zEA88.jpg\", \"https://dimg04.c-ctrip.com/images/0102y120008y7oi767248.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 45.00, NULL, '07:15-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4868, '中华恐龙园', '东方侏罗纪', '中华恐龙园是集科普、娱乐、演艺于一体的恐龙主题乐园，拥有中华恐龙馆、鲁布拉、库克苏克等七大主题区域。', 3, 1965, '江苏省常州市新北区河海东路60号', 31.82527778, 119.99111111, 'https://dimg04.c-ctrip.com/images/1lo6w12000pnbb95j6A56.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6w12000pnbb95j6A56.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4b12000pnbcjlnAD87.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5812000ikip4wuD173.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6912000lokp02i0F5E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5b12000ickmdia51DB.jpg\", \"https://dimg04.c-ctrip.com/images/0Z86d12000hmki5ta4FCD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 260.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4869, '天目湖', '江南明珠', '天目湖是国家级旅游度假区，湖水清澈，周围群山环抱，有龙兴岛、山水园、南山竹海等景点。', 1, 1965, '江苏省常州市溧阳市天目湖镇', 31.32972222, 119.48222222, '/images/attractions/tianmu-lake.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4870, '金山寺', '水漫金山', '金山寺始建于东晋，因《白蛇传》“水漫金山”的故事而闻名。寺庙依山而建，殿宇楼阁鳞次栉比。', 2, 1964, '江苏省镇江市润州区金山路62号', 32.22361111, 119.42500000, 'https://dimg04.c-ctrip.com/images/0100p12000f7unsif5B83.jpg', '[\"https://dimg04.c-ctrip.com/images/0100p12000f7unsif5B83.jpg\", \"https://dimg04.c-ctrip.com/images/0101012000f7uohy36B08.jpg\", \"https://dimg04.c-ctrip.com/images/0106o12000f7uoe9q1B59.jpg\", \"https://dimg04.c-ctrip.com/images/0100q12000f7uo1wp4362.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5u12000icm34pk19CB.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81f12000msmpwo85C0C_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4871, '周恩来故里', '一代伟人故里', '周恩来故里包括周恩来故居、周恩来纪念馆、驸马巷等，展示了周恩来总理的生平事迹。', 5, 1966, '江苏省淮安市淮安区驸马巷7号', 33.50305556, 119.14833333, '/images/attractions/zhouenlai.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:30-16:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4872, '杭州西湖', '世界文化遗产', '西湖是中国著名的风景名胜区，三面环山，湖中有苏堤、白堤、三潭印月、雷峰塔等景点，被誉为“人间天堂”。', 1, 1967, '浙江省杭州市西湖区', 30.25555556, 120.14333333, 'https://dimg04.c-ctrip.com/images/0102112000f6uadu36D11.jpg', '[\"https://dimg04.c-ctrip.com/images/0102112000f6uadu36D11.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5l12000ie9lcwb84B5.jpg\", \"https://dimg04.c-ctrip.com/images/0104q1200087dqmasDFD3.jpg\", \"https://dimg04.c-ctrip.com/images/0102s12000jgo2twg871C.jpg\", \"https://dimg04.c-ctrip.com/images/0103w12000hyg3apk3EBF.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6x12000roau0hyEE33.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4873, '千岛湖', '天下第一秀水', '千岛湖是新安江水电站建成后形成的人工湖，拥有1078个岛屿，水质清澈，可乘船游览、登岛观光。', 1, 1967, '浙江省杭州市淳安县千岛湖镇', 29.60722222, 119.02861111, 'https://dimg04.c-ctrip.com/images/1lo5o12000rhj6nmu05F8.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo5o12000rhj6nmu05F8.jpg\", \"https://dimg04.c-ctrip.com/images/10071f000001h6ymy0856.jpg\", \"https://dimg04.c-ctrip.com/images/01042120008pfcvfi186D.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0d12000htza8w6FF54.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2e12000ickkv2f7B7D.jpg\", \"https://dimg04.c-ctrip.com/images/1h64m12000qghs7016967_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4874, '灵隐寺', '江南禅宗五山之一', '灵隐寺是杭州最早的古寺，始建于东晋，寺内大雄宝殿、飞来峰石刻造像闻名遐迩。', 2, 1967, '浙江省杭州市西湖区灵隐路法云弄1号', 30.24583333, 120.09722222, 'https://dimg04.c-ctrip.com/images/0104t12000k12ya40394B.jpg', '[\"https://dimg04.c-ctrip.com/images/0104t12000k12ya40394B.jpg\", \"https://dimg04.c-ctrip.com/images/100912000000s1pmu735E.jpg\", \"https://dimg04.c-ctrip.com/images/100u12000000rza1n3779.jpg\", \"https://dimg04.c-ctrip.com/images/0105d12000o9hstwt2C1A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1b12000ickkt8u27C1.jpg\", \"https://dimg04.c-ctrip.com/images/Z80s160000010jwbr7246_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '07:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4875, '宋城', '给我一天，还你千年', '宋城是主题公园，以宋代文化为背景，大型歌舞《宋城千古情》是核心看点。', 3, 1967, '浙江省杭州市西湖区之江路148号', 30.18472222, 120.09388889, '/images/attractions/songcheng.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 300.00, NULL, '09:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4876, '天一阁', '中国现存最古老私家藏书楼', '天一阁建于明代，是亚洲现存最古老的私家藏书楼，藏书达30万卷，园林优美。', 2, 1968, '浙江省宁波市海曙区天一街10号', 29.87722222, 121.55111111, 'https://dimg04.c-ctrip.com/images/0104712000mc2qe3uC914.jpg', '[\"https://dimg04.c-ctrip.com/images/0104712000mc2qe3uC914.jpg\", \"https://dimg04.c-ctrip.com/images/0104712000mc2qe3uC914.jpg\", \"https://dimg04.c-ctrip.com/images/0104712000mc2qe3uC914.jpg\", \"https://dimg04.c-ctrip.com/images/0104712000mc2qe3uC914.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4877, '溪口雪窦山', '蒋氏故里', '溪口是蒋介石的故乡，有蒋氏故居、丰镐房、玉泰盐铺等景点。雪窦山是弥勒道场，有露天弥勒大佛。', 2, 1968, '浙江省宁波市奉化区溪口镇', 29.67527778, 121.27861111, '/images/attractions/xikou.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4878, '雁荡山', '东南第一山', '雁荡山以山水奇秀闻名，有灵峰、灵岩、大龙湫三大景区，被称为“海上名山”。', 1, 1969, '浙江省温州市乐清市雁荡镇', 28.36638889, 121.06000000, 'https://dimg04.c-ctrip.com/images/0100a12000ir8wfddC507.jpg', '[\"https://dimg04.c-ctrip.com/images/0100a12000ir8wfddC507.jpg\", \"https://dimg04.c-ctrip.com/images/0100a12000jgw99ii1E59.jpg\", \"https://dimg04.c-ctrip.com/images/0102y12000ir8x22aD0CC.jpg\", \"https://dimg04.c-ctrip.com/images/0104v12000mkfrb0b944B.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0m12000ickn7c04AFA.jpg\", \"https://dimg04.c-ctrip.com/images/1me4e12000pm95k394E2E_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '06:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4879, '楠溪江', '中国山水画摇篮', '楠溪江以水美、岩奇、瀑多、村古闻名，可乘坐竹筏漂流，欣赏两岸田园风光。', 1, 1969, '浙江省温州市永嘉县岩头镇', 28.28333333, 120.66666667, '/images/attractions/nanxijiang.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4880, '乌镇', '中国最后的枕水人家', '乌镇是江南水乡古镇的杰出代表，分为东栅、西栅，西栅夜景尤为迷人。', 2, 1970, '浙江省嘉兴市桐乡市乌镇镇', 30.74972222, 120.48527778, 'https://dimg04.c-ctrip.com/images/1lo4k12000hs4mjbwDBEB.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo4k12000hs4mjbwDBEB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2e12000hs4ukf712C0.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0o12000hs4njurCB58.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6e12000hs4ue5i311D.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3l12000icktu8w0BE9.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84112000eeddll0AD47_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 190.00, NULL, '07:00-22:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4881, '西塘古镇', '生活着的千年古镇', '西塘以桥多、弄多、廊棚多著称，有烟雨长廊、送子来凤桥等景点，是汉服打卡胜地。', 2, 1970, '浙江省嘉兴市嘉善县西塘镇', 30.93833333, 120.88416667, 'https://dimg04.c-ctrip.com/images/100a0g00000087bj10080.jpg', '[\"https://dimg04.c-ctrip.com/images/100a0g00000087bj10080.jpg\", \"https://dimg04.c-ctrip.com/images/100h0u000000iziz2069B.jpg\", \"https://dimg04.c-ctrip.com/images/0104l120008ih5n0c5EF4.jpg\", \"https://dimg04.c-ctrip.com/images/0105812000jfq1n4d9561.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2q12000ickq0cx2C1A.jpg\", \"https://dimg04.c-ctrip.com/images/1me2a12000pxugrmx4EDA_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 95.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4882, '南湖', '中国共产党诞生地', '南湖是红船起航的地方，湖心岛上有烟雨楼，是红色旅游经典景区。', 5, 1970, '浙江省嘉兴市南湖区', 30.76555556, 120.76138889, 'https://dimg04.c-ctrip.com/images/1lo0s12000hs4za9bA09E.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0s12000hs4za9bA09E.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1x12000hs4rudvA1F5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6a12000hs5044v6754.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3w12000hs4ulfu5A17.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5412000icm17id62D9.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4k12000hs4mjbwDBEB.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4883, '南浔古镇', '江南豪门古镇', '南浔是江南唯一的中西合璧古镇，拥有小莲庄、嘉业堂藏书楼、张石铭旧宅等。', 2, 1971, '浙江省湖州市南浔区人瑞路51号', 30.87722222, 120.42027778, 'https://dimg04.c-ctrip.com/images/100b0z000000nerlzADF0.jpg', '[\"https://dimg04.c-ctrip.com/images/100b0z000000nerlzADF0.jpg\", \"https://dimg04.c-ctrip.com/images/01066120008f4zmc64950.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6s12000hs6cufb34BB.jpg\", \"https://dimg04.c-ctrip.com/images/0106312000izt500v1683.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5p12000ickkywk46D5.jpg\", \"https://dimg04.c-ctrip.com/images/1h64b120008kjcheq9FA8_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4884, '莫干山', '中国四大避暑胜地之一', '莫干山以竹、云、泉“三胜”和清、静、绿、凉“四优”著称，有众多民国别墅和民宿。', 1, 1971, '浙江省湖州市德清县莫干山镇', 30.60083333, 119.86527778, 'https://dimg04.c-ctrip.com/images/1lo0j12000iftqpnx1507.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0j12000iftqpnx1507.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0912000ihfe5bd18B8.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2w12000ihfdpp302C4.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5712000iftq6ti83F8.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4w12000icknub47DE6.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84812000flza0u8CE6E_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:00', '6-8月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4885, '鲁迅故里', '跟着课本游绍兴', '鲁迅故里包括鲁迅故居、百草园、三味书屋、鲁迅纪念馆等，是感受鲁迅文学的好地方。', 5, 1972, '浙江省绍兴市越城区鲁迅中路241号', 29.99638889, 120.58361111, 'https://dimg04.c-ctrip.com/images/0100712000kl8icpc9886.jpg', '[\"https://dimg04.c-ctrip.com/images/0100712000kl8icpc9886.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6912000husap1x8F19.jpg\", \"https://dimg04.c-ctrip.com/images/0101312000feplfi05641.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5p12000ickwix81261.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80u12000gorimmz26A1_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh5o12000gskoft25398.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4886, '沈园', '宋代爱情名园', '沈园因陆游与唐婉的爱情故事而闻名，园内有孤鹤轩、钗头凤碑等。', 2, 1972, '浙江省绍兴市越城区鲁迅中路318号', 29.99222222, 120.58888889, 'https://dimg04.c-ctrip.com/images/0104h12000ogaa58x1495.jpg', '[\"https://dimg04.c-ctrip.com/images/0104h12000ogaa58x1495.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6y12000ol6yj6i30CF.png\", \"https://dimg04.c-ctrip.com/images/0100212000rqsxtfwB2A1.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ5n12000rmy9hro9E70.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5p12000ickl7u71691.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80u12000gorimmz26A1_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4887, '兰亭', '书法圣地', '兰亭是王羲之《兰亭集序》的创作地，有鹅池、流觞亭、御碑亭等，可体验曲水流觞。', 2, 1972, '浙江省绍兴市柯桥区兰亭镇', 29.94472222, 120.51027778, 'https://dimg04.c-ctrip.com/images/100k1f000001gui3g361D.jpg', '[\"https://dimg04.c-ctrip.com/images/100k1f000001gui3g361D.jpg\", \"https://dimg04.c-ctrip.com/images/100d10000000ow1wt971B.jpg\", \"https://dimg04.c-ctrip.com/images/100v10000000p8kxv6384.jpg\", \"https://dimg04.c-ctrip.com/images/100q10000000oytlhFB2F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2712000icllxr32B6F.jpg\", \"https://dimg04.c-ctrip.com/images/1h64r12000aqghk85E921_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4888, '横店影视城', '中国好莱坞', '横店影视城是全球最大的影视拍摄基地，有秦王宫、清明上河图、明清宫苑等景区，可体验影视拍摄。', 3, 1973, '浙江省金华市东阳市横店镇', 29.15638889, 120.31333333, 'https://dimg04.c-ctrip.com/images/1lo4w12000rte5762DDBD.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo4w12000rte5762DDBD.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1g12000irlekimB516.jpg\", \"https://dimg04.c-ctrip.com/images/100812000000t96q22551.jpg\", \"https://dimg04.c-ctrip.com/images/100112000000tlwzs8D3D.jpg\", \"https://dimg04.c-ctrip.com/images/tg/712/825/590/7dda4fac32a24165a585b09e2735f306.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4d12000icksv5aF6C5.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 170.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4889, '诸葛八卦村', '八卦布局的奇村', '诸葛八卦村是诸葛亮后裔的最大聚居地，村落布局按八卦图设计，有钟池、丞相祠堂等。', 2, 1973, '浙江省金华市兰溪市诸葛镇', 29.26444444, 119.39833333, 'https://dimg04.c-ctrip.com/images/0104c1200098zbulo0621.jpg', '[\"https://dimg04.c-ctrip.com/images/0104c1200098zbulo0621.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000nowije69043.jpg\", \"https://dimg04.c-ctrip.com/images/0101j1200098zcm3uE718.jpg\", \"https://dimg04.c-ctrip.com/images/0102w1200098zck6b0905.jpg\", \"https://dimg04.c-ctrip.com/images/0zg7212000icloww76A69.jpg\", \"https://dimg04.c-ctrip.com/images/Z80r0n000000egotmC124_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4890, '普陀山', '海天佛国', '普陀山是观音菩萨道场，有普济寺、法雨寺、慧济寺、南海观音立像等，是佛教圣地。', 2, 1974, '浙江省舟山市普陀区普陀山岛', 30.00472222, 122.38472222, 'https://dimg04.c-ctrip.com/images/100t0f0000007gl73177C.jpg', '[\"https://dimg04.c-ctrip.com/images/100t0f0000007gl73177C.jpg\", \"https://dimg04.c-ctrip.com/images/10090r000000gseqp19BC.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ5x12000rlv5omo385F.jpg\", \"https://dimg04.c-ctrip.com/images/0101l12000922kdcbCCCD.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3m12000ickljqy47BD.jpg\", \"https://dimg04.c-ctrip.com/images/27c2m12000na9j4bl5392_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '06:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4891, '朱家尖', '沙雕故乡', '朱家尖有十里金沙、大青山国家公园，每年举办国际沙雕节。', 1, 1974, '浙江省舟山市普陀区朱家尖街道', 29.91638889, 122.38750000, 'https://dimg04.c-ctrip.com/images/1lo1x12000hs5hpa23BD0.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1x12000hs5hpa23BD0.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3w12000hs5ioobA889.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4p12000hs5j9s3B6C7.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0112000hs5ii9c27B2.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4x12000iclokfxBEE7.jpg\", \"https://dimg04.c-ctrip.com/images/1h62o12000dqxk08d37CD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4892, '黄山风景区', '天下第一奇山', '黄山以奇松、怪石、云海、温泉、冬雪“五绝”著称，有迎客松、莲花峰、光明顶、西海大峡谷等景点。', 1, 1976, '安徽省黄山市黄山区汤口镇', 30.13333333, 118.16666667, 'https://dimg04.c-ctrip.com/images/0101p1200087cum179214.jpg', '[\"https://dimg04.c-ctrip.com/images/0101p1200087cum179214.jpg\", \"https://dimg04.c-ctrip.com/images/0100e12000izqvkxv2500.jpg\", \"https://dimg04.c-ctrip.com/images/0105k12000rnf8d9e0241.jpg\", \"https://dimg04.c-ctrip.com/images/0102h1200087cwuv61C67.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5e12000icks4dz9E7A.jpg\", \"https://dimg04.c-ctrip.com/images/Z805090000004a8zf4B93_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 190.00, NULL, '06:30-17:00', '4-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4893, '宏村', '中国画里乡村', '宏村是徽派民居的代表，以牛形水系布局，南湖、月沼、承志堂是精华，电影《卧虎藏龙》取景地。', 2, 1976, '安徽省黄山市黟县宏村镇', 30.00527778, 117.99111111, 'https://dimg04.c-ctrip.com/images/1lo2812000rooc9uu04DB.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2812000rooc9uu04DB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2u12000rooccsl8F0B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3012000rilu7xqEA8E.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2312000rilw90398B0.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6j12000ickrjke256B.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84k120005rq2b2g89DD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 104.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4894, '西递', '桃花源里人家', '西递有“世界上最美的村庄”之称，胡文光刺史牌楼、敬爱堂、履福堂等古建筑精美。', 2, 1976, '安徽省黄山市黟县西递镇', 29.90444444, 117.99027778, 'https://dimg04.c-ctrip.com/images/1lo5612000roopq2h443B.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo5612000roopq2h443B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1y12000rf6vt0p89AB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2o12000rf6w8e313BA.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1n12000rilwo5w0022.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4p12000iclrq321B97.jpg\", \"https://dimg04.c-ctrip.com/images/1h65712000glaafomDEF3_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 104.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4895, '九华山', '莲花佛国', '九华山是地藏菩萨道场，有99座寺庙，百岁宫、肉身宝殿、天台峰等景点。', 2, 1977, '安徽省池州市青阳县九华镇', 30.48527778, 117.80277778, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5912000idvq67d3447.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000iznjmym62D5.jpg\", \"https://dimg04.c-ctrip.com/images/0105412000fcw2ugxC7B4.jpg\", \"https://dimg04.c-ctrip.com/images/0104t12000k12ya40394B.jpg\", \"https://dimg04.c-ctrip.com/images/0105d12000jc363pv3AB5.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '06:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4896, '天柱山', '江淮第一山', '天柱山以花岗岩地貌著称，主峰天柱峰如巨柱擎天，有炼丹湖、神秘谷、三祖寺等。', 1, 1978, '安徽省安庆市潜山市天柱山镇', 30.72611111, 116.45777778, 'https://dimg04.c-ctrip.com/images/1lo0o12000i2rhzn28407.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0o12000i2rhzn28407.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0o12000i2rhzn28407.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0o12000i2rhzn28407.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0o12000i2rhzn28407.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '07:00-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4897, '绩溪龙川', '江南第一祠', '龙川是胡姓聚族而居的古村落，胡氏宗祠被誉为“江南第一祠”，奕世尚书坊精美绝伦。', 2, 1979, '安徽省宣城市绩溪县瀛洲镇', 30.12250000, 118.58472222, '/images/attractions/longchuan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4898, '天堂寨', '华东最后一片原始森林', '天堂寨是大别山第二高峰，有瀑布群、白马峰、龙剑峰等，可观赏原始森林和云海。', 1, 1980, '安徽省六安市金寨县天堂寨镇', 31.16305556, 115.78277778, 'https://dimg04.c-ctrip.com/images/1lo2k12000jwhcsmxE85A.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2k12000jwhcsmxE85A.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3u12000jwh8htj11DF.jpg\", \"https://dimg04.c-ctrip.com/images/0106912000f84ca2u5480.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0z12000jwh8ts5C316.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3u12000icl0le171D9.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80812000jqdgh4r9972_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:00-17:30', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4899, '鼓浪屿', '万国建筑博览', '鼓浪屿是厦门的一个小岛，岛上遍布欧式建筑，有日光岩、菽庄花园、钢琴博物馆等景点，被誉为“海上花园”。', 2, 1982, '福建省厦门市思明区鼓浪屿', 24.44527778, 118.06083333, 'https://dimg04.c-ctrip.com/images/0101t12000825yd946670.jpg', '[\"https://dimg04.c-ctrip.com/images/0101t12000825yd946670.jpg\", \"https://dimg04.c-ctrip.com/images/10030p000000fkgatFC2E.jpg\", \"https://dimg04.c-ctrip.com/images/10070q000000gpmnjA205.jpg\", \"https://dimg04.c-ctrip.com/images/01001120008261fvw7FEE.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4b12000ickk87w9E31.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85g12000dfussmx6764_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 35.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4900, '武夷山', '碧水丹山', '武夷山是世界自然与文化双遗产地，有九曲溪竹筏漂流、天游峰、一线天、大红袍茶树等景点。', 1, 1984, '福建省南平市武夷山市武夷街道', 27.64694444, 117.92583333, 'https://dimg04.c-ctrip.com/images/0105m12000f6ptyq6F00A.jpg', '[\"https://dimg04.c-ctrip.com/images/0105m12000f6ptyq6F00A.jpg\", \"https://dimg04.c-ctrip.com/images/0104e12000d9qkwn09B3B.jpg\", \"https://dimg04.c-ctrip.com/images/0100812000d9qkitmD07A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5f12000icpp7mz6F44.jpg\", \"https://dimg04.c-ctrip.com/images/27c6c12000na9je1x4B57_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2d12000d6s40soFE41.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 140.00, NULL, '07:00-17:00', '4-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4901, '永定土楼', '东方古城堡', '永定土楼是世界上独一无二的山区大型夯土民居建筑，以振成楼、承启楼为代表，被称为“神话般的山区建筑”。', 2, 1985, '福建省龙岩市永定区湖坑镇', 24.66500000, 116.95694444, '/images/attractions/yongding-tulou.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4902, '三坊七巷', '中国城市里坊制度的活化石', '三坊七巷是福州的历史文化街区，有衣锦坊、文儒坊、光禄坊和杨桥巷、郎官巷等，保存了大量明清古建筑。', 2, 1981, '福建省福州市鼓楼区', 26.08694444, 119.29888889, 'https://dimg04.c-ctrip.com/images/0103q12000aoh72b2D3E9.jpg', '[\"https://dimg04.c-ctrip.com/images/0103q12000aoh72b2D3E9.jpg\", \"https://dimg04.c-ctrip.com/images/100p0h0000008w4eo9DFB.jpg\", \"https://dimg04.c-ctrip.com/images/0102p1200082hvxfcB9C2.jpg\", \"https://dimg04.c-ctrip.com/images/0103j12000aoh6xlz9840.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1612000iclnowl9312.jpg\", \"https://dimg04.c-ctrip.com/images/100k0n000000e5m3yB22B.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4903, '清源山', '泉州第一山', '清源山有老君岩造像、千手岩、弥陀岩等，以道教文化著称，是国家级风景名胜区。', 2, 1983, '福建省泉州市丰泽区清源山', 24.94472222, 118.59888889, 'https://dimg04.c-ctrip.com/images/0101y12000j04ofyb94C4.jpg', '[\"https://dimg04.c-ctrip.com/images/0101y12000j04ofyb94C4.jpg\", \"https://dimg04.c-ctrip.com/images/0100812000molocyf11B3.jpg\", \"https://dimg04.c-ctrip.com/images/350t170000011290j937F.jpg\", \"https://dimg04.c-ctrip.com/images/350f170000011283kE15B.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6c12000ickljzi1505.jpg\", \"https://dimg04.c-ctrip.com/images/27c2312000na9j5h1276B_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4904, '太姥山', '海上仙都', '太姥山以花岗岩峰林地貌为特色，有夫妻峰、一片瓦、九鲤朝天等景观，山海相连。', 1, 1986, '福建省宁德市福鼎市太姥山镇', 27.08916667, 120.12916667, 'https://dimg04.c-ctrip.com/images/010171200087d7st5FE6C.jpg', '[\"https://dimg04.c-ctrip.com/images/010171200087d7st5FE6C.jpg\", \"https://dimg04.c-ctrip.com/images/10010r000000hpswe946D.jpg\", \"https://dimg04.c-ctrip.com/images/100l0q000000gbr3a5266.jpg\", \"https://dimg04.c-ctrip.com/images/0100l120008e8mp2wD953.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6712000iclujpoDA71.jpg\", \"https://dimg04.c-ctrip.com/images/350i0y000000lu8qz215F_Z_1000_0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4905, '白水洋', '天下绝景', '白水洋是鸳鸯溪的河床，平坦的岩石河床一石而就，水流平缓，可赤足涉水，是世界唯一的“浅水广场”。', 1, 1986, '福建省宁德市屏南县双溪镇', 27.11305556, 119.08111111, 'https://dimg04.c-ctrip.com/images/010401200088teu8q6C77.jpg', '[\"https://dimg04.c-ctrip.com/images/010401200088teu8q6C77.jpg\", \"https://dimg04.c-ctrip.com/images/0106y1200088tes4vE25E.jpg\", \"https://dimg04.c-ctrip.com/images/0104i1200088tes6l9FF9.jpg\", \"https://dimg04.c-ctrip.com/images/0106m1200088tfmonBBF7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5m12000icpbtzz080D.jpg\", \"https://dimg04.c-ctrip.com/images/Z80n0l000000cwzsrBE90_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4906, '古田会议会址', '红色圣地', '古田会议会址是中国共产党红军第四军第九次代表大会召开地，确立了思想建党、政治建军原则。', 5, 1985, '福建省龙岩市上杭县古田镇', 25.22638889, 116.82416667, '/images/attractions/gutian.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4907, '庐山', '匡庐奇秀甲天下', '庐山以雄、奇、险、秀闻名，有花径、仙人洞、三叠泉、含鄱口、美庐别墅等景点，是避暑胜地。', 1, 1988, '江西省九江市庐山市', 29.51972222, 115.99250000, 'https://dimg04.c-ctrip.com/images/10021f000001gxelv1DD4.jpg', '[\"https://dimg04.c-ctrip.com/images/10021f000001gxelv1DD4.jpg\", \"https://dimg04.c-ctrip.com/images/0100612000jhymwth21D4.jpg\", \"https://dimg04.c-ctrip.com/images/01046120004gesr5x9B21.jpg\", \"https://dimg04.c-ctrip.com/images/100j0u000000j1zf01511.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0112000icldl625FE9.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85u12000j2c7yoqA7AE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 160.00, NULL, '07:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4908, '井冈山', '中国革命的摇篮', '井冈山是毛泽东创建的第一个农村革命根据地，有黄洋界、八角楼、井冈山革命博物馆等红色景点，自然风光也优美。', 5, 1990, '江西省吉安市井冈山市', 26.57416667, 114.16750000, 'https://dimg04.c-ctrip.com/images/350d15000000y5ci2A9C0.jpg', '[\"https://dimg04.c-ctrip.com/images/350d15000000y5ci2A9C0.jpg\", \"https://dimg04.c-ctrip.com/images/350d15000000y5ci2A9C0.jpg\", \"https://dimg04.c-ctrip.com/images/350d15000000y5ci2A9C0.jpg\", \"https://dimg04.c-ctrip.com/images/350d15000000y5ci2A9C0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 165.00, NULL, '08:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4909, '三清山', '西太平洋边缘最美丽的花岗岩', '三清山有司春女神、巨蟒出山、一线天等奇峰怪石，道教文化深厚，是世界自然遗产。', 1, 1989, '江西省上饶市玉山县三清乡', 28.91083333, 118.06194444, 'https://dimg04.c-ctrip.com/images/100v0z000000nsk5eBAA6.jpg', '[\"https://dimg04.c-ctrip.com/images/100v0z000000nsk5eBAA6.jpg\", \"https://dimg04.c-ctrip.com/images/10030x000000lfzhw4F40.jpg\", \"https://dimg04.c-ctrip.com/images/0105e12000h6tra78CFF8.jpg\", \"https://dimg04.c-ctrip.com/images/0100b1200087e57q407C8.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3z12000ickm4n4957A.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84s12000h1yvzwmF263_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '07:30-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4910, '婺源', '中国最美的乡村', '婺源有江湾、李坑、汪口、篁岭等古村落，春季油菜花盛开，秋季晒秋景色迷人。', 2, 1989, '江西省上饶市婺源县', 29.25277778, 117.86027778, 'https://dimg04.c-ctrip.com/images/100i080000002xq4tFAA3.jpg', '[\"https://dimg04.c-ctrip.com/images/100i080000002xq4tFAA3.jpg\", \"https://dimg04.c-ctrip.com/images/010661200092mh9cp6E7E.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5b12000gntnlekAE7F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5t12000gns9q426CEB.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0j12000ickjguwD7EF.jpg\", \"https://dimg04.c-ctrip.com/images/27c1212000na9ji4x8795_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '全天', '3-4月、10-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4911, '龙虎山', '道教祖庭', '龙虎山是道教正一派的发源地，有嗣汉天师府、上清宫、悬棺表演等，可乘竹筏游览泸溪河。', 2, 1991, '江西省鹰潭市贵溪市龙虎山镇', 28.09611111, 117.01527778, 'https://dimg04.c-ctrip.com/images/3504160000010eiys2862.jpg', '[\"https://dimg04.c-ctrip.com/images/3504160000010eiys2862.jpg\", \"https://dimg04.c-ctrip.com/images/350b160000010eygy9B71.jpg\", \"https://dimg04.c-ctrip.com/images/350s160000010jg3hE307.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0a12000n93ztkoE11C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1q12000icl9g1iB76D.jpg\", \"https://dimg04.c-ctrip.com/images/1h65d12000p4ft8t158CE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4912, '景德镇古窑民俗博览区', '千年瓷都', '景德镇古窑展示了古代制瓷工艺，有宋代龙窑、元代馒头窑、明代葫芦窑等，可亲手体验制瓷。', 2, 1992, '江西省景德镇市昌江区瓷都大道', 29.28916667, 117.17888889, 'https://dimg04.c-ctrip.com/images/1lo0212000bpmv29s96FD.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0212000bpmv29s96FD.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2412000bp27dfgF5B4.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1h12000bp28ghyC379.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2812000bp27w6k0D92.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6012000ickzytsA39C.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80512000efp71qhB291_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 95.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4913, '滕王阁', '江南三大名楼之一', '滕王阁因王勃《滕王阁序》而名扬天下，登阁可远眺赣江，是南昌的地标。', 2, 1987, '江西省南昌市东湖区仿古街58号', 28.68277778, 115.87444444, 'https://dimg04.c-ctrip.com/images/100g1f000001gqwviAF2C.jpg', '[\"https://dimg04.c-ctrip.com/images/100g1f000001gqwviAF2C.jpg\", \"https://dimg04.c-ctrip.com/images/100c0n000000e33ajF0B3.jpg\", \"https://dimg04.c-ctrip.com/images/100m12000000s8h2i5597.jpg\", \"https://dimg04.c-ctrip.com/images/0106f12000jc0sf5nEA82.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0y12000ickmlc7629F.jpg\", \"https://dimg04.c-ctrip.com/images/Z8020i0000009bqe17BF7_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4914, '武功山', '云中草原', '武功山以高山草甸、帐篷露营、日出云海著称，是户外徒步爱好者的天堂。', 1, 1990, '江西省吉安市安福县武功山景区', 27.45527778, 114.17694444, '/images/attractions/wugongshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-17:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4915, '泰山', '五岳独尊', '泰山是五岳之首，有“天下第一山”之称，可登山观日出、云海，沿途有岱庙、红门、中天门、南天门、玉皇顶等。', 1, 1995, '山东省泰安市岱岳区', 36.25333333, 117.10750000, 'https://dimg04.c-ctrip.com/images/100c0z000000nnlzdA153.jpg', '[\"https://dimg04.c-ctrip.com/images/100c0z000000nnlzdA153.jpg\", \"https://dimg04.c-ctrip.com/images/0100312000mjw767s306C.jpg\", \"https://dimg04.c-ctrip.com/images/0100n12000f7kk44dA2EC.jpg\", \"https://dimg04.c-ctrip.com/images/0102v12000fmy2zyw1E58.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1s12000ickmqi0A877.jpg\", \"https://dimg04.c-ctrip.com/images/1h62o12000dqxk08d37CD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 115.00, NULL, '全天', '4-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4916, '曲阜三孔', '儒家圣地', '孔庙、孔府、孔林是祭祀孔子及其家族的场所，是儒家文化的象征，世界文化遗产。', 2, 1996, '山东省济宁市曲阜市', 35.59000000, 116.98638889, 'https://dimg04.c-ctrip.com/images/0101l120008ybqg3b01A2.jpg', '[\"https://dimg04.c-ctrip.com/images/0101l120008ybqg3b01A2.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5x12000b85bucc1A5F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0e12000b85bmtdE2E8.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3w12000b85b2301EDD.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3i12000ickzywbB703.jpg\", \"https://dimg04.c-ctrip.com/images/0Z874120009cm7vly06FA_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 140.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4917, '崂山', '海上第一名山', '崂山是道教名山，山海相连，有太清宫、巨峰、仰口、北九水等景区，可登山观海。', 1, 1994, '山东省青岛市崂山区', 36.20361111, 120.46944444, 'https://dimg04.c-ctrip.com/images/010141200087e556s7C80.jpg', '[\"https://dimg04.c-ctrip.com/images/010141200087e556s7C80.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0m12000kmybl7n297C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6312000kmmf10z8753.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5z12000kmy9f973380.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2q12000icla1gs2FD0.jpg\", \"https://dimg04.c-ctrip.com/images/1h66112000qw7zm7t5558_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '07:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4918, '蓬莱阁', '人间仙境', '蓬莱阁是传说中八仙过海的地方，古建筑群临海而立，可远眺长岛，是中国古代四大名楼之一。', 2, 1997, '山东省烟台市蓬莱区迎宾路7号', 37.81333333, 120.74277778, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6b12000id9n76sB383.jpg\", \"https://dimg04.c-ctrip.com/images/0104q1200087dqmasDFD3.jpg\", \"https://dimg04.c-ctrip.com/images/0103w12000hyg3apk3EBF.jpg\", \"https://dimg04.c-ctrip.com/images/0102s12000jgo2twg871C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6x12000roau0hyEE33.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '07:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4919, '刘公岛', '甲午战争纪念地', '刘公岛是北洋水师的诞生地和甲午战争的主战场，有甲午战争博物馆、北洋海军提督署等。', 5, 1998, '山东省威海市环翠区', 37.49888889, 122.18916667, 'https://dimg04.c-ctrip.com/images/0101y12000rqbe42iFC27.jpg', '[\"https://dimg04.c-ctrip.com/images/0101y12000rqbe42iFC27.jpg\", \"https://dimg04.c-ctrip.com/images/0100x1200081q1c5iB1DA.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g1/M01/B1/DA/CghzfVW7Oc6AcOWCABfjgQZciP4292.jpg\", \"https://dimg04.c-ctrip.com/images/0102s12000rqbe7zo545F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0w12000iclb23h8636.jpg\", \"https://dimg04.c-ctrip.com/images/1h62812000nadb54tE0D4_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 122.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4920, '趵突泉', '天下第一泉', '趵突泉是济南七十二名泉之首，泉水喷涌，清澈甘甜，李清照纪念堂坐落于此。', 1, 1993, '山东省济南市历下区趵突泉南路1号', 36.66222222, 117.00611111, 'https://dimg04.c-ctrip.com/images/0103212000l65p69jC65D.jpg', '[\"https://dimg04.c-ctrip.com/images/0103212000l65p69jC65D.jpg\", \"https://dimg04.c-ctrip.com/images/0100o12000l65ovb8542E.jpg\", \"https://dimg04.c-ctrip.com/images/0104512000rn2i59dA846.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ7212000qfv2v2xEA34.png\", \"https://dimg04.c-ctrip.com/images/0zg4s12000icknzju08D3.jpg\", \"https://dimg04.c-ctrip.com/images/Z80q0e00000075u32032C_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 40.00, NULL, '07:00-19:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4921, '大明湖', '泉城明珠', '大明湖是济南三大名胜之一，湖水由泉水汇流而成，有历下亭、铁公祠、北极阁等景点。', 1, 1993, '山东省济南市历下区大明湖路271号', 36.67305556, 117.02194444, 'https://dimg04.c-ctrip.com/images/0101l120008anfd516A8F.jpg', '[\"https://dimg04.c-ctrip.com/images/0101l120008anfd516A8F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1212000icl6alqA521.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81g120006mam1r2A217_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/010741200088ljiu0D175.jpg\", \"https://dimg04.c-ctrip.com/images/0104f1200088lib8z9901.jpg\", \"https://dimg04.c-ctrip.com/images/010681200088lhx438FDF.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4922, '成山头', '中国好望角', '成山头是中国大陆伸向海洋的最东端，有“天尽头”之称，可观赏海上日出。', 1, 1998, '山东省威海市荣成市成山镇', 37.40138889, 122.70527778, 'https://dimg04.c-ctrip.com/images/1lo0t12000ejp0c219309.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0t12000ejp0c219309.jpg\", \"https://dimg04.c-ctrip.com/images/3501170000011o1322577.jpg\", \"https://dimg04.c-ctrip.com/images/350o1700000119y4u4EDE.jpg\", \"https://dimg04.c-ctrip.com/images/350k170000011faflEC91.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1p12000icliida73B3.jpg\", \"https://dimg04.c-ctrip.com/images/1h65d12000p4ft8t158CE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 180.00, NULL, '07:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4923, '龙门石窟', '中国石刻艺术巅峰', '龙门石窟开凿于北魏孝文帝年间，历经400余年营造，现存窟龛2345个，造像10万余尊，碑刻题记2800余品。', 2, 2001, '河南省洛阳市洛龙区龙门镇', 34.46666667, 112.46666667, 'https://dimg04.c-ctrip.com/images/0104p12000rpdckmaD19D.jpg', '[\"https://dimg04.c-ctrip.com/images/0104p12000rpdckmaD19D.jpg\", \"https://dimg04.c-ctrip.com/images/0104p12000rpdckmaD19D.jpg\", \"https://dimg04.c-ctrip.com/images/0104p12000rpdckmaD19D.jpg\", \"https://dimg04.c-ctrip.com/images/0104p12000rpdckmaD19D.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4924, '嵩山少林寺', '天下第一名刹', '少林寺是中国佛教禅宗祖庭和少林武术发源地，始建于北魏太和十九年（495年）。塔林、常住院、初祖庵是核心景点。', 2, 2000, '河南省郑州市登封市嵩山少林寺景区', 34.50000000, 112.93333333, '/images/attractions/shaolin.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4925, '清明上河园', '宋代主题公园', '清明上河园是按照北宋画家张择端《清明上河图》1:1复建的大型宋代文化主题公园，再现了北宋汴京的繁华景象。', 3, 2002, '河南省开封市龙亭区龙亭西路5号', 34.80000000, 114.33333333, 'https://dimg04.c-ctrip.com/images/100s0z000000nrpwy7C2A.jpg', '[\"https://dimg04.c-ctrip.com/images/100s0z000000nrpwy7C2A.jpg\", \"https://dimg04.c-ctrip.com/images/100s0z000000nrpwy7C2A.jpg\", \"https://dimg04.c-ctrip.com/images/100s0z000000nrpwy7C2A.jpg\", \"https://dimg04.c-ctrip.com/images/100s0z000000nrpwy7C2A.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '09:00-22:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4926, '云台山', '北方奇景', '云台山是世界地质公园，以红石峡、潭瀑峡、泉瀑峡、茱萸峰、猕猴谷著称，是河南山水旅游的标杆。', 1, 2003, '河南省焦作市修武县七贤镇', 35.43333333, 113.36666667, 'https://dimg04.c-ctrip.com/images/0104t120007nvqev4066E.jpg', '[\"https://dimg04.c-ctrip.com/images/0104t120007nvqev4066E.jpg\", \"https://dimg04.c-ctrip.com/images/0101x12000jb8fii5B47F.jpg\", \"https://dimg04.c-ctrip.com/images/0103l12000jb8g09i58D6.jpg\", \"https://dimg04.c-ctrip.com/images/0104n12000pzjkrey30AE.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5212000icknkpi2D0F.jpg\", \"https://dimg04.c-ctrip.com/images/fd/headphoto/g3/M08/BA/42/CggYG1YPDWmAHTaZAAA1eZaOodU871_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '07:00-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4927, '白马寺', '中国第一古刹', '白马寺是中国最早的佛教寺院，始建于东汉永平十一年（68年），是佛教传入中国后兴建的第一座官办寺院。', 2, 2001, '河南省洛阳市洛龙区白马寺镇', 34.71666667, 112.58333333, 'https://dimg04.c-ctrip.com/images/0HJ0212000g652jld7C0F.jpg', '[\"https://dimg04.c-ctrip.com/images/0HJ0212000g652jld7C0F.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1v12000ifie6hq72BC.jpg\", \"https://dimg04.c-ctrip.com/images/0105p12000f6scno87BC5.jpg\", \"https://dimg04.c-ctrip.com/images/0103n12000f6trha712AE.jpg\", \"https://dimg04.c-ctrip.com/images/1A0e14000000wmh4a9B1D.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000rlz0fi2A832.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 35.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4928, '老君山', '道教圣地', '老君山是道教名山，相传老子在此归隐修炼。山顶金顶道观群气势恢宏，是摄影爱好者的天堂。', 2, 2001, '河南省洛阳市栾川县七里坪村', 33.73333333, 111.66666667, 'https://dimg04.c-ctrip.com/images/0100p120009412ps933BA.jpg', '[\"https://dimg04.c-ctrip.com/images/0100p120009412ps933BA.jpg\", \"https://dimg04.c-ctrip.com/images/0103y12000rizn62d5979.jpg\", \"https://dimg04.c-ctrip.com/images/0105x12000j2s0ua09AB3.jpg\", \"https://dimg04.c-ctrip.com/images/0101912000rizmaqeC6CC.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6112000ickrkseF58B.jpg\", \"https://dimg04.c-ctrip.com/images/1me6b12000qjr0i3gC1EC_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4929, '鸡公山', '万国建筑博览', '鸡公山是中国四大避暑胜地之一，山上建有数百幢西式别墅，有“万国建筑博览”之称。', 4, 2005, '河南省信阳市浉河区鸡公山风景区', 31.81666667, 114.08333333, 'https://dimg04.c-ctrip.com/images/1me7112000e8h1gaiF875.jpg', '[\"https://dimg04.c-ctrip.com/images/1me7112000e8h1gaiF875.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6l12000icmluit7326.jpg\", \"https://dimg04.c-ctrip.com/images/27c2m12000na9j4bl5392_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh09224x96kk91llA87F.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2h224x96kki1w11426.jpg\", \"https://dimg04.c-ctrip.com/images/1mh56224x96kkk25336F3.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-17:00', '5-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4930, '黄鹤楼', '天下江山第一楼', '黄鹤楼始建于三国时期，历代屡毁屡建，现楼为1985年重建。登楼可俯瞰长江大桥和武汉三镇风光。', 2, 2006, '湖北省武汉市武昌区蛇山西山坡特1号', 30.55000000, 114.30000000, 'https://dimg04.c-ctrip.com/images/0103w12000ibkyi833A93.png', '[\"https://dimg04.c-ctrip.com/images/0103w12000ibkyi833A93.png\", \"https://dimg04.c-ctrip.com/images/0zg2r12000icqzqf32E69.jpg\", \"https://dimg04.c-ctrip.com/images/1h66b12000frb8mim6EE7_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2s12000i72ioliD919.jpg\", \"https://dimg04.c-ctrip.com/images/1mh0m12000i73wjecF65E.jpg\", \"https://dimg04.c-ctrip.com/images/1A0e14000000wmh4a9B1D.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4931, '武当山', '亘古无双胜境', '武当山是道教圣地、太极拳发祥地，古建筑群始建于唐，明代达到鼎盛，被誉为“中国古代建筑博物馆”。', 2, 2008, '湖北省十堰市丹江口市武当山特区', 32.40000000, 111.00000000, 'https://dimg04.c-ctrip.com/images/0105512000bbdzt2t4533.jpg', '[\"https://dimg04.c-ctrip.com/images/0105512000bbdzt2t4533.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2q12000icuq49s8125.jpg\", \"https://dimg04.c-ctrip.com/images/Z80210000000pnwdkC0B3_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1h63j120008t5krgk4AC3_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh3o12000bgljuz39542.jpg\", \"https://dimg04.c-ctrip.com/images/1mh1d12000bgltbr2B25E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '07:30-17:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4932, '三峡大坝', '世界水利奇观', '三峡大坝是世界上规模最大的水电站，全长2309米，高185米。坛子岭、185平台、截流纪念园是观景最佳位置。', 3, 2007, '湖北省宜昌市夷陵区三峡坝区', 30.83333333, 111.00000000, 'https://dimg04.c-ctrip.com/images/0100x12000aao20wz0054.jpg', '[\"https://dimg04.c-ctrip.com/images/0100x12000aao20wz0054.jpg\", \"https://dimg04.c-ctrip.com/images/0100x12000aao20wz0054.jpg\", \"https://dimg04.c-ctrip.com/images/0100x12000aao20wz0054.jpg\", \"https://dimg04.c-ctrip.com/images/0100x12000aao20wz0054.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4933, '恩施大峡谷', '东方科罗拉多', '恩施大峡谷以绝壁、峰柱、地缝、天坑著称，云龙地缝、一炷香是标志性景观。', 1, 2009, '湖北省恩施州恩施市屯堡乡', 30.30000000, 109.06666667, 'https://dimg04.c-ctrip.com/images/01022120008xunyvk31A1.jpg', '[\"https://dimg04.c-ctrip.com/images/01022120008xunyvk31A1.jpg\", \"https://dimg04.c-ctrip.com/images/0103w12000aqrl33x3562.jpg\", \"https://dimg04.c-ctrip.com/images/0103l12000aqrkzq28CC2.jpg\", \"https://dimg04.c-ctrip.com/images/0105n12000aqrl6qg3577.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4q12000ickmt7u5235.jpg\", \"https://dimg04.c-ctrip.com/images/27c2112000na9j9p95174_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 155.00, NULL, '08:30-17:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4934, '神农顶风景区', '华中屋脊', '神农顶是神农架最高峰，海拔3106.2米，有“华中屋脊”之称。景区内有高山草甸、箭竹林、冷杉林等原始生态。', 1, 2010, '湖北省神农架林区红坪镇', 31.50000000, 110.30000000, '/images/attractions/shennongding.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '07:00-17:30', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4935, '三峡人家', '依山傍水的土家风情', '三峡人家融合三峡文化、巴楚风情，依山傍水，吊脚楼、渔船、溪边人家构成一幅山水画卷。', 2, 2007, '湖北省宜昌市夷陵区三斗坪镇', 30.80000000, 111.06666667, 'https://dimg04.c-ctrip.com/images/1lo5u12000b6yxm11AF03.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo5u12000b6yxm11AF03.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5u12000b6yxm11AF03.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5u12000b6yxm11AF03.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5u12000b6yxm11AF03.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4936, '荆州古城', '南方完璧', '荆州古城是我国南方保存最为完好的古城墙，可登城楼远眺，参观宾阳楼、关帝庙等。', 2, 2011, '湖北省荆州市荆州区', 30.35000000, 112.20000000, '/images/attractions/jingzhou.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 35.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4937, '张家界国家森林公园', '世界自然遗产', '张家界是中国第一个国家森林公园，以石英砂岩峰林地貌著称，电影《阿凡达》取景地哈利路亚山在此。', 1, 2013, '湖南省张家界市武陵源区', 29.35000000, 110.53333333, 'https://dimg04.c-ctrip.com/images/0106q12000f6turu2F806.jpg', '[\"https://dimg04.c-ctrip.com/images/0106q12000f6turu2F806.jpg\", \"https://dimg04.c-ctrip.com/images/0106j120009h4cwiy9BD5.jpg\", \"https://dimg04.c-ctrip.com/images/100m0m000000dp757A1E3.jpg\", \"https://dimg04.c-ctrip.com/images/0105i120009h4cqeg9E20.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4912000ickmp7o5620.jpg\", \"https://dimg04.c-ctrip.com/images/fd/headphoto/g4/M00/76/3B/CggYHlYI-FCAIeynAAAojZoEpnQ936_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 228.00, NULL, '07:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4938, '天门山', '湘西第一神山', '天门山因自然奇观天门洞而得名，拥有世界最长高山观光索道、玻璃栈道、99道弯通天大道。', 1, 2013, '湖南省张家界市永定区官黎坪', 29.06666667, 110.48333333, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4z12000ifi7bew0B29.jpg\", \"https://dimg04.c-ctrip.com/images/0106q12000f6turu2F806.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1l12000r80nvwwBC8B.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1j12000oll883fAFE6.jpg\", \"https://dimg04.c-ctrip.com/images/0103x12000lgqckyt5EE5.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 278.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4939, '凤凰古城', '中国最美小城', '凤凰古城是湘西民族风情与自然风光的完美结合，沱江两岸的吊脚楼、虹桥、沈从文故居是核心景点。', 2, 2014, '湖南省湘西州凤凰县沱江镇', 27.95000000, 109.60000000, 'https://dimg04.c-ctrip.com/images/1A0q1700000118gee3001.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0q1700000118gee3001.jpg\", \"https://dimg04.c-ctrip.com/images/0104l1200086vuo2l42D2.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2412000ir7iota9432.jpg\", \"https://dimg04.c-ctrip.com/images/100i18000001455buC78C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0n12000ickmc3h2353.jpg\", \"https://dimg04.c-ctrip.com/images/Z80615000000y1mut2A23_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4940, '南岳衡山', '五岳独秀', '衡山是中国五岳之一，以秀美著称。祝融峰是最高峰，南岳大庙是江南最大的宫殿式古建筑群。', 1, 2015, '湖南省衡阳市南岳区', 27.25000000, 112.73333333, 'https://dimg04.c-ctrip.com/images/0103u12000jgwsut3E652.jpg', '[\"https://dimg04.c-ctrip.com/images/0103u12000jgwsut3E652.jpg\", \"https://dimg04.c-ctrip.com/images/0103u12000jgwsut3E652.jpg\", \"https://dimg04.c-ctrip.com/images/0103u12000jgwsut3E652.jpg\", \"https://dimg04.c-ctrip.com/images/0103u12000jgwsut3E652.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 110.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4941, '韶山毛泽东故居', '伟人故里', '韶山是毛泽东同志的故乡，故居为土木结构农舍，陈列有部分原物。铜像广场、纪念馆是必游之地。', 5, 2016, '湖南省湘潭市韶山市韶山乡', 27.91666667, 112.51666667, '/images/attractions/shaoshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4942, '岳阳楼', '洞庭天下水，岳阳天下楼', '岳阳楼是江南三大名楼之一，因范仲淹《岳阳楼记》而名扬天下。登楼可眺望八百里洞庭。', 2, 2017, '湖南省岳阳市岳阳楼区洞庭北路', 29.38333333, 113.08333333, 'https://dimg04.c-ctrip.com/images/0105e12000nu6s6efECF4.jpg', '[\"https://dimg04.c-ctrip.com/images/0105e12000nu6s6efECF4.jpg\", \"https://dimg04.c-ctrip.com/images/0103812000lgq7i8o8E86.jpg\", \"https://dimg04.c-ctrip.com/images/01043120006efsrbuCCC6.jpg\", \"https://dimg04.c-ctrip.com/images/0105t12000lgq6yrcFC1D.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5u12000ickr038F1A3.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80412000hgdw02a4320_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 70.00, NULL, '07:30-18:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4943, '东江湖', '人间天上一湖水', '东江湖以雾漫小东江闻名，清晨湖面薄雾缭绕，渔夫撒网，宛如仙境。', 1, 2018, '湖南省郴州市资兴市东江镇', 25.95000000, 113.33333333, 'https://dimg04.c-ctrip.com/images/0100512000jhzssxyA0F5.jpg', '[\"https://dimg04.c-ctrip.com/images/0100512000jhzssxyA0F5.jpg\", \"https://dimg04.c-ctrip.com/images/0100512000jhzssxyA0F5.jpg\", \"https://dimg04.c-ctrip.com/images/0100512000jhzssxyA0F5.jpg\", \"https://dimg04.c-ctrip.com/images/0100512000jhzssxyA0F5.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '06:00-18:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4944, '岳麓山·橘子洲', '山水洲城', '岳麓山是南岳72峰之一，爱晚亭、岳麓书院坐落其中。橘子洲是湘江中的沙洲，有青年毛泽东雕像。', 2, 2012, '湖南省长沙市岳麓区', 28.18333333, 112.93333333, '/images/attractions/yuelushan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4945, '广州塔', '小蛮腰', '广州塔是中国第一高塔，高600米，塔顶摩天轮、极速云霄等娱乐项目惊险刺激，可俯瞰广州全景。', 3, 2019, '广东省广州市海珠区阅江西路222号', 23.11666667, 113.31666667, 'https://dimg04.c-ctrip.com/images/0105j12000bzanxfaBAF2.jpg', '[\"https://dimg04.c-ctrip.com/images/0105j12000bzanxfaBAF2.jpg\", \"https://dimg04.c-ctrip.com/images/0103c120008rrco4n6FB7.jpg\", \"https://dimg04.c-ctrip.com/images/0101p120008rrcqtrD5BC.jpg\", \"https://dimg04.c-ctrip.com/images/01072120008rrd0q9289C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4y12000ickrsboA2B5.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4h12000hyn809y7B56.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '09:30-22:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4946, '长隆旅游度假区', '中国最佳主题乐园', '长隆拥有欢乐世界、野生动物世界、水上乐园、飞鸟乐园四大园区，是亲子游的热门选择。', 3, 2019, '广东省广州市番禺区汉溪大道东299号', 23.00000000, 113.31666667, '/images/attractions/chimelong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 250.00, NULL, '09:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4947, '丹霞山', '中国丹霞命名地', '丹霞山是世界自然遗产“中国丹霞”的命名地，以赤壁丹崖为特色，阳元石、阴元石是标志性景观。', 1, 2023, '广东省韶关市仁化县', 25.00000000, 113.73333333, 'https://dimg04.c-ctrip.com/images/0104l1200048mguv521D1.jpg', '[\"https://dimg04.c-ctrip.com/images/0104l1200048mguv521D1.jpg\", \"https://dimg04.c-ctrip.com/images/0104l1200048mguv521D1.jpg\", \"https://dimg04.c-ctrip.com/images/0104l1200048mguv521D1.jpg\", \"https://dimg04.c-ctrip.com/images/0104l1200048mguv521D1.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4948, '世界之窗', '微缩世界公园', '世界之窗将世界奇观、历史遗迹、古今名胜微缩于一园，是深圳的旅游地标之一。', 3, 2020, '广东省深圳市南山区华侨城', 22.53333333, 113.96666667, 'https://dimg04.c-ctrip.com/images/0100x120009ezysch905F.jpg', '[\"https://dimg04.c-ctrip.com/images/0100x120009ezysch905F.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ0x12000rraxmg3745E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0t12000icz1baz7C8B.jpg\", \"https://dimg04.c-ctrip.com/images/27c6412000na9jnck75BB_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh2012000mvzktje57BC.jpg\", \"https://dimg04.c-ctrip.com/images/1mh1q12000mvyxy4b80CF.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 220.00, NULL, '09:00-22:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4949, '珠海长隆海洋王国', '世界最大的海洋主题乐园', '珠海长隆拥有珍稀海洋动物展馆、动感游乐设施、大型表演，鲸鲨馆、企鹅馆、烟花表演是亮点。', 3, 2021, '广东省珠海市横琴新区富祥湾', 22.10000000, 113.53333333, 'https://dimg04.c-ctrip.com/images/tg/847/784/623/89f5b1550d0643479ccb0770d843f78c.jpg', '[\"https://dimg04.c-ctrip.com/images/tg/847/784/623/89f5b1550d0643479ccb0770d843f78c.jpg\", \"https://dimg04.c-ctrip.com/images/0105t120005or7v5sB9D4.jpg\", \"https://dimg04.c-ctrip.com/images/350h1f000001fzea78141.jpg\", \"https://dimg04.c-ctrip.com/images/01031120003hb4wozBA0E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0b12000ickvy7zCAB9.jpg\", \"https://dimg04.c-ctrip.com/images/100fhk1439kevc4leCF33.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 280.00, NULL, '10:00-20:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4950, '西樵山', '南粤名山', '西樵山是广东四大名山之一，以火山地貌、观音文化、理学文化著称，南海观音坐像高达61.9米。', 2, 2022, '广东省佛山市南海区西樵镇', 22.91666667, 112.96666667, 'https://dimg04.c-ctrip.com/images/1lo1312000b2johfq92DB.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1312000b2johfq92DB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2p12000crsdzox953F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2812000eba0it377FF.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6f12000crsdohjFF43.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2h12000icksd1k89CF.jpg\", \"https://dimg04.c-ctrip.com/images/27c3k12000na9jmdu23FE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '07:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4951, '罗浮山', '岭南第一山', '罗浮山是道教名山，有朱明洞、冲虚观、葛洪炼丹灶等，被誉为“岭南第一山”。', 2, 2024, '广东省惠州市博罗县长宁镇', 23.26666667, 114.03333333, 'https://dimg04.c-ctrip.com/images/0102y12000f6t428w82A6.jpg', '[\"https://dimg04.c-ctrip.com/images/0102y12000f6t428w82A6.jpg\", \"https://dimg04.c-ctrip.com/images/100g1f000001gr0a39384.jpg\", \"https://dimg04.c-ctrip.com/images/0zg3j12000icm0vlwCF0E.jpg\", \"https://dimg04.c-ctrip.com/images/27c3j12000na9jmxj3516_R_180_180.jpg\", \"https://dimg04.c-ctrip.com/images/1mh3r12000h9gvldp6A80.jpg\", \"https://dimg04.c-ctrip.com/images/1mh5s12000h9gn7bg49F6.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4952, '七星岩', '岭南第一奇观', '七星岩由七座石灰岩山峰组成，湖光山色，摩崖石刻众多，有“岭南第一奇观”之称。', 1, 2025, '广东省肇庆市端州区七星岩风景区', 23.08333333, 112.46666667, 'https://dimg04.c-ctrip.com/images/0103y12000f7kvxqm2E98.jpg', '[\"https://dimg04.c-ctrip.com/images/0103y12000f7kvxqm2E98.jpg\", \"https://dimg04.c-ctrip.com/images/100i12000000rth5vAE6E.jpg\", \"https://dimg04.c-ctrip.com/images/0103612000j1pv73pE959.jpg\", \"https://dimg04.c-ctrip.com/images/0104r12000f7kwb2lBFC9.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1912000iclj0lbE97E.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85i12000avkuaf0EAA8_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 78.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4953, '漓江风景名胜区', '百里漓江，百里画廊', '漓江是桂林山水的精华，两岸奇峰倒影，江水碧绿，从桂林至阳朔83公里，是喀斯特地貌的完美展现。', 1, 2027, '广西桂林市灵川县至阳朔县', 25.26666667, 110.28333333, 'https://dimg04.c-ctrip.com/images/01059120005qzc6xp3CF2.jpg', '[\"https://dimg04.c-ctrip.com/images/01059120005qzc6xp3CF2.jpg\", \"https://dimg04.c-ctrip.com/images/01059120005qzc6xp3CF2.jpg\", \"https://dimg04.c-ctrip.com/images/01059120005qzc6xp3CF2.jpg\", \"https://dimg04.c-ctrip.com/images/01059120005qzc6xp3CF2.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 210.00, NULL, '全天', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4954, '阳朔西街', '洋人街', '阳朔西街是阳朔最古老的街道，中西文化交融，酒吧、餐馆、手工艺品店林立，是休闲度假的好去处。', 2, 2027, '广西桂林市阳朔县阳朔镇', 24.76666667, 110.48333333, 'https://dimg04.c-ctrip.com/images/0105z12000abrjn57B4E8.jpg', '[\"https://dimg04.c-ctrip.com/images/0105z12000abrjn57B4E8.jpg\", \"https://dimg04.c-ctrip.com/images/0105z12000abrjn57B4E8.jpg\", \"https://dimg04.c-ctrip.com/images/0105z12000abrjn57B4E8.jpg\", \"https://dimg04.c-ctrip.com/images/0105z12000abrjn57B4E8.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4955, '龙脊梯田', '世界梯田原乡', '龙脊梯田始建于元代，距今有650多年历史，梯田如链似带，层层叠叠，是壮族、瑶族人民智慧的结晶。', 1, 2027, '广西桂林市龙胜各族自治县龙脊镇', 25.75000000, 110.00000000, 'https://dimg04.c-ctrip.com/images/0105d120008245j400186.jpg', '[\"https://dimg04.c-ctrip.com/images/0105d120008245j400186.jpg\", \"https://dimg04.c-ctrip.com/images/0105d120008245j400186.jpg\", \"https://dimg04.c-ctrip.com/images/0105d120008245j400186.jpg\", \"https://dimg04.c-ctrip.com/images/0105d120008245j400186.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '全天', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4956, '德天跨国瀑布', '亚洲第一跨国瀑布', '德天瀑布与越南板约瀑布相连，宽200多米，落差70米，年均水流量是黄果树瀑布的三倍。', 1, 2029, '广西崇左市大新县硕龙镇', 22.85000000, 106.71666667, 'https://dimg04.c-ctrip.com/images/0105h12000now8gvl237F.jpg', '[\"https://dimg04.c-ctrip.com/images/0105h12000now8gvl237F.jpg\", \"https://dimg04.c-ctrip.com/images/0105h12000now8gvl237F.jpg\", \"https://dimg04.c-ctrip.com/images/0105h12000now8gvl237F.jpg\", \"https://dimg04.c-ctrip.com/images/0105h12000now8gvl237F.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:30', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4957, '北海银滩', '天下第一滩', '北海银滩沙滩长24公里，由高品质石英砂堆积而成，沙质洁白细腻，在阳光照射下泛出银光。', 4, 2028, '广西北海市银海区银滩中路', 21.40000000, 109.10000000, 'https://dimg04.c-ctrip.com/images/0HJ6x12000g2uclh4E1BD.jpg', '[\"https://dimg04.c-ctrip.com/images/0HJ6x12000g2uclh4E1BD.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2212000idodj8pE461.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6112000qps0lzg87B7.jpg\", \"https://dimg04.c-ctrip.com/images/0103p12000rg62rb9203A.jpg\", \"https://dimg04.c-ctrip.com/images/0105u120008jvydv63344.jpg\", \"https://dimg04.c-ctrip.com/images/10031c000001dcdk19FC2.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '4-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4958, '涠洲岛', '中国最美海岛', '涠洲岛是中国最年轻的火山岛，拥有火山口、鳄鱼山、滴水丹屏、天主教堂等景点。', 1, 2028, '广西北海市海城区涠洲镇', 21.05000000, 109.10000000, 'https://dimg04.c-ctrip.com/images/1lo6u12000ropv4xzF3A8.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6u12000ropv4xzF3A8.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5h12000rv28kyb9B5F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2j12000rrc6ngu4BFB.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5j12000rrc6nup9872.jpg\", \"https://dimg04.c-ctrip.com/images/1lo3s12000rrc752a83B4.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5u12000icks926C903.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 98.00, NULL, '全天', '4-11月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4959, '黄姚古镇', '梦境家园', '黄姚古镇发祥于宋朝，保存有300多间明清古建筑，石板街、带龙桥、古戏台是核心景点。', 2, 2030, '广西贺州市昭平县黄姚镇', 24.25000000, 111.71666667, 'https://dimg04.c-ctrip.com/images/10051f000001gsqnvB09E.jpg', '[\"https://dimg04.c-ctrip.com/images/10051f000001gsqnvB09E.jpg\", \"https://dimg04.c-ctrip.com/images/10051f000001gsqnvB09E.jpg\", \"https://dimg04.c-ctrip.com/images/10051f000001gsqnvB09E.jpg\", \"https://dimg04.c-ctrip.com/images/10051f000001gsqnvB09E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 88.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4960, '程阳八寨', '中国最美侗寨', '程阳八寨是侗族聚居地，风雨桥、鼓楼、吊脚楼保存完好，程阳风雨桥是侗族建筑的代表作。', 2, 2031, '广西柳州市三江侗族自治县林溪镇', 25.78333333, 109.61666667, 'https://dimg04.c-ctrip.com/images/1lo1812000jcu8wp9FB7C.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1812000jcu8wp9FB7C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1812000jcu8wp9FB7C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1812000jcu8wp9FB7C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1812000jcu8wp9FB7C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4961, '亚龙湾', '天下第一湾', '亚龙湾拥有7公里长的银色沙滩，沙质细腻，海水清澈，是三亚最优质的海滨度假区。', 4, 2033, '海南省三亚市吉阳区亚龙湾路', 18.23333333, 109.63333333, '/images/attractions/yalongbay.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '10-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4962, '天涯海角', '爱情圣地', '天涯海角因两块刻有“天涯”“海角”的巨石而得名，是海南的标志性景区，寓意“天涯海角永相随”。', 2, 2033, '海南省三亚市天涯区天涯镇', 18.28333333, 109.33333333, 'https://dimg04.c-ctrip.com/images/1lo2w12000bkakwfv4046.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2w12000bkakwfv4046.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6412000bkal5gxBB41.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5212000bkal0b7C4D1.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5e12000bkal99aCC83.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0512000ickkiay7081.jpg\", \"https://dimg07.c-ctrip.com/images/0100u120008ws5twoF20B_R_1600_10000.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 81.00, NULL, '07:30-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4963, '蜈支洲岛', '中国马尔代夫', '蜈支洲岛海水能见度高达27米，是海南最清澈的海域，拥有丰富的水上娱乐项目，被誉为“中国的马尔代夫”。', 4, 2033, '海南省三亚市海棠区蜈支洲岛', 18.31666667, 109.75000000, 'https://dimg04.c-ctrip.com/images/1lo0212000r8tntmcA4D2.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0212000r8tntmcA4D2.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4712000r8tpusk368F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6u12000r8tpvvcFC0C.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1812000r8tqab50C07.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5x12000icklihj5D7A.jpg\", \"https://dimg03.c-ctrip.com/images/01006120008r0zknw4B04_R_1600_10000.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 144.00, NULL, '08:00-17:30', '10-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4964, '南山文化旅游区', '佛教文化圣地', '南山文化旅游区是一座展示中国佛教传统文化的大型园区，108米海上观音是世界最大的观音圣像。', 2, 2033, '海南省三亚市崖州区南山村', 18.31666667, 109.20000000, '/images/attractions/nanshan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 129.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4965, '分界洲岛', '心灵分界岛', '分界洲岛是热带与亚热带的分界线，海水清澈，珊瑚丰富，是潜水和海上娱乐的绝佳去处。', 4, 2036, '海南省陵水县光坡镇', 18.56666667, 110.18333333, 'https://dimg04.c-ctrip.com/images/1lo3b12000j74pdwbB1AF.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo3b12000j74pdwbB1AF.jpg\", \"https://dimg04.c-ctrip.com/images/0100v120008xuvwnnE010.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2u12000bd9sgn4DD0F.jpg\", \"https://dimg04.c-ctrip.com/images/3508180000014lglvB0D9.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2912000icktolnFC51.jpg\", \"https://dimg04.c-ctrip.com/images/350e180000014o0ly299B.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 132.00, NULL, '08:00-17:30', '10-4月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4966, '海花岛', '世界最大花形人工岛', '海花岛由三个花瓣形人工岛组成，集酒店、购物、娱乐、文化于一体，是海南的新地标。', 3, 2034, '海南省儋州市白马井镇', 19.73333333, 109.23333333, '/images/attractions/haihuadao.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4967, '骑楼老街', '南洋风情', '海口骑楼老街是南洋风格的建筑群，保存有中山路、博爱路等历史街区，是海口的历史文化名片。', 2, 2032, '海南省海口市龙华区得胜沙路至长堤路', 20.03333333, 110.33333333, 'https://dimg04.c-ctrip.com/images/01055120005yvw1fo61AD.jpg', '[\"https://dimg04.c-ctrip.com/images/01055120005yvw1fo61AD.jpg\", \"https://dimg04.c-ctrip.com/images/0100n120005yuuyex5D81.jpg\", \"https://dimg04.c-ctrip.com/images/100110000000pdbz57342.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ1d12000rqyofleD3A7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5a12000ickuu1b458F.jpg\", \"https://dimg04.c-ctrip.com/images/27c1212000na9ji4x8795_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4968, '洪崖洞', '现实版千与千寻', '洪崖洞是依山而建的吊脚楼建筑群，夜晚灯火辉煌，宛如《千与千寻》中的汤屋，是重庆最热门的网红打卡地。', 2, 2037, '重庆市渝中区嘉陵江滨江路88号', 29.56666667, 106.56666667, '/images/attractions/hongyadong.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4969, '大足石刻', '石窟艺术最后的丰碑', '大足石刻是唐、五代、宋时期凿造的石刻造像，以宝顶山、北山、南山、石门山、石篆山为代表，是中国晚期石窟艺术的巅峰。', 2, 2039, '重庆市大足区宝顶镇', 29.70000000, 105.71666667, 'https://dimg04.c-ctrip.com/images/0100y1200087e4jl1CF02.jpg', '[\"https://dimg04.c-ctrip.com/images/0100y1200087e4jl1CF02.jpg\", \"https://dimg04.c-ctrip.com/images/01030120008rxqtyiB006.jpg\", \"https://dimg04.c-ctrip.com/images/01072120008bw9zzm832D.jpg\", \"https://dimg04.c-ctrip.com/images/100v1c000001e2l316759.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0y12000icko36zEC44.jpg\", \"https://dimg04.c-ctrip.com/images/fd/headphoto/g4/M0B/62/D3/CggYHlYzICeANYHtAAAb-x-G1JY633_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 115.00, NULL, '08:30-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4970, '武隆天生三桥', '世界最大的天生桥群', '天生三桥由天龙桥、青龙桥、黑龙桥组成，是典型的喀斯特地貌，电影《满城尽带黄金甲》在此取景。', 1, 2038, '重庆市武隆区仙女山镇', 29.43333333, 107.75000000, 'https://dimg04.c-ctrip.com/images/0105q120004gsttsa454D.jpg', '[\"https://dimg04.c-ctrip.com/images/0105q120004gsttsa454D.jpg\", \"https://dimg04.c-ctrip.com/images/0100212000jtjhm24EE03.jpg\", \"https://dimg04.c-ctrip.com/images/0104c12000jtji60h107B.jpg\", \"https://dimg04.c-ctrip.com/images/0HJ1q12000rpnyru80FB5.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1d12000ickpgbvEAE3.jpg\", \"https://dimg04.c-ctrip.com/images/0Z83r12000cfsg5qm02BB_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 125.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4971, '解放碑', '重庆精神堡垒', '解放碑是抗战胜利和重庆解放的历史见证，是重庆最繁华的商业中心，周边是购物和美食的天堂。', 2, 2037, '重庆市渝中区民族路177号', 29.55000000, 106.56666667, '/images/attractions/jiefangbei.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4972, '长江索道', '万里长江第一条空中走廊', '长江索道是连接渝中区和南岸区的跨江索道，乘坐索道可俯瞰长江两岸风光，是山城重庆的独特体验。', 3, 2037, '重庆市渝中区新华路153号', 29.55000000, 106.58333333, 'https://dimg04.c-ctrip.com/images/1lo3k12000r2gduew8391.png', '[\"https://dimg04.c-ctrip.com/images/1lo3k12000r2gduew8391.png\", \"https://dimg04.c-ctrip.com/images/01A511200090idw6fDB4A.jpg\", \"https://dimg04.c-ctrip.com/images/0101m12000jcjdi4eECEA.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5e12000r2ge9sqE4F4.jpg\", \"https://dimg04.c-ctrip.com/images/0105b12000f6sfcg7BDA8.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6m12000ickofl609BA.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 30.00, NULL, '07:30-22:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4973, '酉阳桃花源', '世外桃源原型地', '酉阳桃花源是陶渊明《桃花源记》原型地之一，景区内有太古洞、桃花溪、秦晋风情等景点。', 2, 2041, '重庆市酉阳县桃花源镇', 28.83333333, 108.76666667, 'https://dimg04.c-ctrip.com/images/0104e120008lsgk3wC0AF.jpg', '[\"https://dimg04.c-ctrip.com/images/0104e120008lsgk3wC0AF.jpg\", \"https://dimg04.c-ctrip.com/images/01044120008lr0s0qAED2.jpg\", \"https://dimg04.c-ctrip.com/images/100g0q000000gc5t20195.jpg\", \"https://dimg04.c-ctrip.com/images/01067120008lr0w1mD057.png\", \"https://dimg04.c-ctrip.com/images/0zg5b12000icl1r7n488C.jpg\", \"https://dimg04.c-ctrip.com/images/27c2m12000na9j4bl5392_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4974, '巫山小三峡', '中华奇观', '小三峡是龙门峡、巴雾峡、滴翠峡的总称，以雄、奇、秀、美著称，可乘船游览，观赏两岸奇峰、悬棺、古栈道。', 1, 2040, '重庆市巫山县巫峡镇', 31.06666667, 109.86666667, 'https://dimg04.c-ctrip.com/images/0104y1200087cuizr215A.jpg', '[\"https://dimg04.c-ctrip.com/images/0104y1200087cuizr215A.jpg\", \"https://dimg04.c-ctrip.com/images/0100w12000aso20gz7C32.jpg\", \"https://dimg04.c-ctrip.com/images/0102f12000aso25j381C9.jpg\", \"https://dimg04.c-ctrip.com/images/0106i12000f6qjjyc3F2A.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2412000ickxcpfFEC6.jpg\", \"https://dimg04.c-ctrip.com/images/27c2u12000na9jl4c55A2_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4975, '黄果树瀑布', '亚洲第一大瀑布', '黄果树瀑布高77.8米，宽101米，是世界上唯一可以从上、下、前、后、左、右六个方位观赏的瀑布，水势磅礴。', 1, 2044, '贵州省安顺市黄果树旅游区', 25.98333333, 105.66666667, '/images/attractions/huangguoshu.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 210.00, NULL, '07:30-18:00', '6-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4976, '荔波小七孔', '地球腰带上的绿宝石', '小七孔景区以精巧、秀美著称，有七孔桥、拉雅瀑布、68级跌水瀑布、水上森林等景观，宛如仙境。', 1, 2046, '贵州省黔南州荔波县瑶山瑶族乡', 25.23333333, 107.88333333, 'https://dimg04.c-ctrip.com/images/0101312000izs6jhs5BAF.jpg', '[\"https://dimg04.c-ctrip.com/images/0101312000izs6jhs5BAF.jpg\", \"https://dimg04.c-ctrip.com/images/100w1a00000191vd7C9B2.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g5/M08/D1/8F/CggYr1cz9h2AXFpoACTVeU2Otek666.jpg\", \"https://dimg04.c-ctrip.com/images/0100712000izs3j82774D.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6x12000ickoa0wED7B.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85u12000j2c7yoqA7AE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 130.00, NULL, '08:00-16:30', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4977, '西江千户苗寨', '中国最大苗寨', '西江千户苗寨是世界上最大的苗族聚居村寨，依山而建的吊脚楼层层叠叠，夜晚灯火如星河璀璨。', 2, 2045, '贵州省黔东南州雷山县西江镇', 26.50000000, 108.16666667, 'https://dimg04.c-ctrip.com/images/0100312000jcj5ai8384D.jpg', '[\"https://dimg04.c-ctrip.com/images/0100312000jcj5ai8384D.jpg\", \"https://dimg04.c-ctrip.com/images/1007180000014f73wF525.jpg\", \"https://dimg04.c-ctrip.com/images/0103612000fajrtc025AD.jpg\", \"https://dimg04.c-ctrip.com/images/010661200087chtmy173B.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5s12000iclf2x265F8.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80612000hp47tznCDF4_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 90.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4978, '梵净山', '天空之城', '梵净山是武陵山脉主峰，海拔2572米，拥有云海、佛光、红云金顶等奇观，2018年被列入世界自然遗产。', 1, 2047, '贵州省铜仁市江口县太平镇', 27.91666667, 108.66666667, 'https://dimg04.c-ctrip.com/images/1lo0412000qdacnpgB9D7.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo0412000qdacnpgB9D7.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2x12000qdagfppF3DE.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2n12000qdacnncC441.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2812000qdacohcAD05.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5q12000ickruff4291.jpg\", \"https://dimg04.c-ctrip.com/images/0Z85a12000iufydl904A8_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-16:00', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4979, '遵义会议会址', '伟大转折之地', '遵义会议会址是1935年中共中央政治局扩大会议的召开地，这次会议是中国共产党历史上一个生死攸关的转折点。', 5, 2043, '贵州省遵义市红花岗区子尹路96号', 27.70000000, 106.91666667, 'https://dimg04.c-ctrip.com/images/10090z000000nmgbl110E.jpg', '[\"https://dimg04.c-ctrip.com/images/10090z000000nmgbl110E.jpg\", \"https://dimg04.c-ctrip.com/images/350w1d000001enq9tFDB6.jpg\", \"https://dimg04.c-ctrip.com/images/350l1d000001ehv2967D7.jpg\", \"https://dimg04.c-ctrip.com/images/350j1d000001eh7lnEC34.jpg\", \"https://dimg04.c-ctrip.com/images/0zg6q12000ickw06f6DCD.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0d12000c00ov7pAB80.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '08:30-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4980, '镇远古城', '东方威尼斯', '镇远古城㵲阳河穿城而过，两岸古建筑依山傍水，青龙洞、祝圣桥、古巷道是核心景点。', 2, 2045, '贵州省黔东南州镇远县', 27.05000000, 108.41666667, 'https://dimg04.c-ctrip.com/images/10011d000001ey7gn134F.jpg', '[\"https://dimg04.c-ctrip.com/images/10011d000001ey7gn134F.jpg\", \"https://dimg04.c-ctrip.com/images/0101212000j0jooneA014.jpg\", \"https://dimg04.c-ctrip.com/images/0104z12000ns1rwdyE420.jpg\", \"https://dimg04.c-ctrip.com/images/0100x1200083ee69zF7FE.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1r12000iclvc4h710B.jpg\", \"https://dimg04.c-ctrip.com/images/0Z81l12000cdiswuvE6DD_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4981, '龙宫', '中国最长最美的水溶洞', '龙宫拥有全国最长、最美的水溶洞，可乘船游览洞内奇观，还有龙门飞瀑、观音洞等景点。', 1, 2044, '贵州省安顺市西秀区龙宫镇', 26.16666667, 105.85000000, 'https://dimg04.c-ctrip.com/images/0100b12000j0dzah7EDDE.jpg', '[\"https://dimg04.c-ctrip.com/images/0100b12000j0dzah7EDDE.jpg\", \"https://dimg04.c-ctrip.com/images/0102y12000ns1qffx11C2.jpg\", \"https://dimg04.c-ctrip.com/images/0106r1200085cvjauB300.jpg\", \"https://dimg04.c-ctrip.com/images/0106z120008jkwa5r5F2C.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2s12000icm6bavC293.jpg\", \"https://dimg04.c-ctrip.com/images/1me4t12000oywu8i90103_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '08:00-17:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4982, '赤水丹霞', '千瀑之市', '赤水丹霞是世界自然遗产，有大瀑布、佛光岩、四洞沟等景区，以丹霞地貌、瀑布群、桫椤为特色。', 1, 2043, '贵州省遵义市赤水市', 28.38333333, 105.96666667, 'https://dimg04.c-ctrip.com/images/0100q12000f6pv6xf3D96.jpg', '[\"https://dimg04.c-ctrip.com/images/0100q12000f6pv6xf3D96.jpg\", \"https://dimg04.c-ctrip.com/images/0103o1200084v2vki6546.jpg\", \"https://dimg04.c-ctrip.com/images/01047120008alnmxuBC20.jpg\", \"https://dimg04.c-ctrip.com/images/100c1f000001gsvfs5684.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1712000icnp2m76F59.jpg\", \"https://dimg04.c-ctrip.com/images/0Z84n12000i265nz2FD77_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4983, '布达拉宫', '世界屋脊的明珠', '布达拉宫是世界上海拔最高、最雄伟的宫殿，是藏传佛教圣地和历代达赖喇嘛的冬宫，始建于7世纪。', 2, 2048, '西藏拉萨市城关区北京中路35号', 29.65000000, 91.11666667, 'https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g1/M06/FC/24/CghzflW7H_iATdynAAA-FlXAIeA738.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4k12000id2uyba73F1.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1l12000r80nvwwBC8B.jpg\", \"https://dimg04.c-ctrip.com/images/0102c12000jbqn6otD98E.jpg\", \"https://dimg04.c-ctrip.com/images/01056120008ts0c3eC9F5.jpg\", \"https://dimg04.c-ctrip.com/images/100t1h000001hngwf1417.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 200.00, NULL, '09:00-16:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4984, '大昭寺', '西藏的眼睛', '大昭寺是藏传佛教最神圣的寺庙，供奉着释迦牟尼12岁等身像，是信徒朝圣的终点，八廓街环绕其周围。', 2, 2048, '西藏拉萨市城关区八廓街', 29.65000000, 91.13333333, 'https://dimg04.c-ctrip.com/images/0102d12000rqt0tdv5C70.jpg', '[\"https://dimg04.c-ctrip.com/images/0102d12000rqt0tdv5C70.jpg\", \"https://dimg04.c-ctrip.com/images/0102d12000rqt0tdv5C70.jpg\", \"https://dimg04.c-ctrip.com/images/0102d12000rqt0tdv5C70.jpg\", \"https://dimg04.c-ctrip.com/images/0102d12000rqt0tdv5C70.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 85.00, NULL, '09:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4985, '纳木措', '天湖', '纳木措是世界海拔最高的大型湖泊，藏语意为“天湖”，是西藏三大圣湖之一，湖水湛蓝，与雪山相映。', 1, 2048, '西藏拉萨市当雄县', 30.70000000, 90.55000000, 'https://dimg04.c-ctrip.com/images/100g0h0000008r5qhBA0C.jpg', '[\"https://dimg04.c-ctrip.com/images/100g0h0000008r5qhBA0C.jpg\", \"https://dimg04.c-ctrip.com/images/100g0h0000008r5qhBA0C.jpg\", \"https://dimg04.c-ctrip.com/images/100g0h0000008r5qhBA0C.jpg\", \"https://dimg04.c-ctrip.com/images/100g0h0000008r5qhBA0C.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4986, '雅鲁藏布大峡谷', '世界第一大峡谷', '雅鲁藏布大峡谷全长504.6公里，最深6009米，是世界第一大峡谷，可近距离观赏南迦巴瓦峰。', 1, 2049, '西藏林芝市米林县派镇', 29.60000000, 94.90000000, '/images/attractions/yarlung-tsangpo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '08:00-20:30', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4987, '珠穆朗玛峰大本营', '世界之巅', '珠峰大本营是攀登珠峰的起点，海拔5200米，可远眺世界最高峰珠穆朗玛峰（8848.86米）。', 1, 2050, '西藏日喀则市定日县扎西宗乡', 28.20000000, 86.83333333, '/images/attractions/everest-basecamp.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 180.00, NULL, '全天', '4-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4988, '羊卓雍措', '天鹅之湖', '羊卓雍措是西藏三大圣湖之一，湖水碧蓝，蜿蜒曲折，像一条蓝色的丝带镶嵌在群山之中。', 1, 2051, '西藏山南市浪卡子县', 28.95000000, 90.66666667, '/images/attractions/yamdrok.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '全天', '6-9月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4989, '扎什伦布寺', '班禅驻锡地', '扎什伦布寺是藏传佛教格鲁派六大寺之一，历代班禅的驻锡地，寺内有强巴佛大殿、十世班禅灵塔等。', 2, 2050, '西藏日喀则市桑珠孜区几吉郎卡路1号', 29.26666667, 88.88333333, '/images/attractions/tashilhunpo.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 55.00, NULL, '09:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4990, '冈仁波齐', '神山之王', '冈仁波齐是藏传佛教、印度教、耆那教、苯教公认的神山，转山是信徒一生的愿望，被誉为“世界中心”。', 2, 2052, '西藏阿里地区普兰县巴嘎乡', 31.06666667, 81.30000000, '/images/attractions/kailash.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 150.00, NULL, '全天', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (4991, '沙湖生态旅游区', '沙漠中的湖泊', '沙湖融合江南水乡与大漠风光于一体，湖水、沙漠、芦苇、飞鸟构成独特景观，是宁夏的王牌景区。', 1, 2054, '宁夏石嘴山市平罗县前进农场', 38.80000000, 106.35000000, 'https://dimg04.c-ctrip.com/images/350p14000000x3wii81A6.jpg', '[\"https://dimg04.c-ctrip.com/images/350p14000000x3wii81A6.jpg\", \"https://dimg04.c-ctrip.com/images/350p14000000x3wii81A6.jpg\", \"https://dimg04.c-ctrip.com/images/350p14000000x3wii81A6.jpg\", \"https://dimg04.c-ctrip.com/images/350p14000000x3wii81A6.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 120.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4992, '沙坡头', '中国十大最好玩的地方', '沙坡头集大漠、黄河、高山、绿洲于一体，可体验滑沙、黄河飞索、羊皮筏子等项目，是户外爱好者的天堂。', 1, 2057, '宁夏中卫市沙坡头区迎水桥镇', 37.46666667, 105.00000000, 'https://dimg04.c-ctrip.com/images/100o0q000000ga82rCD2E.jpg', '[\"https://dimg04.c-ctrip.com/images/100o0q000000ga82rCD2E.jpg\", \"https://dimg04.c-ctrip.com/images/100o0q000000ga82rCD2E.jpg\", \"https://dimg04.c-ctrip.com/images/100o0q000000ga82rCD2E.jpg\", \"https://dimg04.c-ctrip.com/images/100o0q000000ga82rCD2E.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 80.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4993, '镇北堡西部影城', '中国电影从这里走向世界', '镇北堡西部影城是《红高粱》《大话西游》《新龙门客栈》等百余部电影的取景地，被誉为“东方好莱坞”。', 3, 2053, '宁夏银川市西夏区镇北堡镇', 38.56666667, 106.03333333, 'https://dimg04.c-ctrip.com/images/1A0t16000000z3x2yB8A4.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0t16000000z3x2yB8A4.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t16000000z3x2yB8A4.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t16000000z3x2yB8A4.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t16000000z3x2yB8A4.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4994, '西夏陵', '东方金字塔', '西夏陵是西夏历代帝王陵墓，现存9座帝陵、271座陪葬墓，规模宏大，被誉为“东方金字塔”。', 2, 2053, '宁夏银川市西夏区贺兰山东麓', 38.41666667, 105.96666667, 'https://dimg04.c-ctrip.com/images/1A08170000012fwpuEA68.jpg', '[\"https://dimg04.c-ctrip.com/images/1A08170000012fwpuEA68.jpg\", \"https://dimg04.c-ctrip.com/images/1A08170000012fwpuEA68.jpg\", \"https://dimg04.c-ctrip.com/images/1A08170000012fwpuEA68.jpg\", \"https://dimg04.c-ctrip.com/images/1A08170000012fwpuEA68.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 75.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4995, '贺兰山岩画', '石头上的史诗', '贺兰山岩画是古代游牧民族留下的艺术珍品，以人面像、狩猎、放牧等题材为主，记录了远古人类的生活。', 2, 2053, '宁夏银川市贺兰县贺兰山东麓', 38.61666667, 106.10000000, 'https://dimg04.c-ctrip.com/images/1lo1x12000cw86r860D42.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo1x12000cw86r860D42.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1x12000cw86r860D42.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1x12000cw86r860D42.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1x12000cw86r860D42.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 60.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4996, '须弥山石窟', '宁夏敦煌', '须弥山石窟始凿于北魏，现存洞窟162座，造像350余尊，是古代佛教艺术的瑰宝。', 2, 2056, '宁夏固原市原州区黄铎堡镇', 36.20000000, 106.15000000, 'https://dimg04.c-ctrip.com/images/0100w1200086mk9woB952.jpg', '[\"https://dimg04.c-ctrip.com/images/0100w1200086mk9woB952.jpg\", \"https://dimg04.c-ctrip.com/images/0100w1200086mk9woB952.jpg\", \"https://dimg04.c-ctrip.com/images/0100w1200086mk9woB952.jpg\", \"https://dimg04.c-ctrip.com/images/0100w1200086mk9woB952.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 50.00, NULL, '08:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4997, '六盘山国家森林公园', '黄土高原上的绿色明珠', '六盘山是红军长征翻越的最后一座大山，森林茂密，溪流潺潺，有小南川、凉殿峡、植物园等景点。', 1, 2056, '宁夏固原市泾源县泾河源镇', 35.38333333, 106.31666667, 'https://dimg04.c-ctrip.com/images/1A0t15000000xiagr15D2.jpg', '[\"https://dimg04.c-ctrip.com/images/1A0t15000000xiagr15D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t15000000xiagr15D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t15000000xiagr15D2.jpg\", \"https://dimg04.c-ctrip.com/images/1A0t15000000xiagr15D2.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 65.00, NULL, '08:00-18:00', '5-10月', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4998, '维多利亚港', '世界三大夜景之一', '维多利亚港是香港的地标，夜晚两岸灯光璀璨，可乘坐天星小轮夜游维港，欣赏幻彩咏香江灯光秀。', 1, 2058, '香港特别行政区油尖旺区至东区', 22.28333333, 114.16666667, 'https://dimg04.c-ctrip.com/images/10020y000000m5j4vCC02.jpg', '[\"https://dimg04.c-ctrip.com/images/10020y000000m5j4vCC02.jpg\", \"https://dimg04.c-ctrip.com/images/100d0z000000naxy05131.jpg\", \"https://dimg04.c-ctrip.com/images/100g0z000000mjpqy60D9.jpg\", \"https://dimg04.c-ctrip.com/images/10050y000000m3ci12FA0.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1n12000icld024A2D0.jpg\", \"https://dimg04.c-ctrip.com/images/100413000000txgc5A4D8.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (4999, '香港迪士尼乐园', '童话王国', '香港迪士尼乐园是全球第五座迪士尼乐园，拥有七大主题园区，是亲子游的首选目的地。', 3, 2058, '香港特别行政区离岛区大屿山', 22.31666667, 114.03333333, 'https://dimg04.c-ctrip.com/images/1lo2a12000rqqgloeA389.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2a12000rqqgloeA389.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1412000rqqgq9kE090.jpg\", \"https://dimg04.c-ctrip.com/images/1lo7312000rqqhdgs6F4F.jpg\", \"https://dimg04.c-ctrip.com/images/1lo5812000rqqgvofD003.jpg\", \"https://dimg04.c-ctrip.com/images/0zg2012000icksiej6AAF.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1u12000k60t9gy7523.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 639.00, NULL, '10:00-20:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5000, '太平山顶', '俯瞰香港全景', '太平山顶是香港岛的最高点，乘坐山顶缆车可俯瞰维多利亚港和九龙半岛的全景，夜景尤为迷人。', 1, 2058, '香港特别行政区中西区太平山', 22.26666667, 114.15000000, 'https://dimg04.c-ctrip.com/images/1lo2e12000rbaeehl8024.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo2e12000rbaeehl8024.jpg\", \"https://dimg04.c-ctrip.com/images/1lo1s12000rbaf04l2A2E.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2x12000b1d2b348CEA.jpg\", \"https://dimg04.c-ctrip.com/images/100f0z000000ncfisF674.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5c12000icljid51BDE.jpg\", \"https://dimg04.c-ctrip.com/images/1lo6c12000rbaeqgv1FDC.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 52.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5001, '香港海洋公园', '海洋主题乐园', '香港海洋公园集海洋动物展览、机动游戏、表演于一体，拥有熊猫馆、海洋剧场、过山车等项目。', 3, 2058, '香港特别行政区南区黄竹坑', 22.23333333, 114.16666667, 'https://dimg04.c-ctrip.com/images/1lo3b12000rnhx4196B38.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo3b12000rnhx4196B38.jpg\", \"https://dimg04.c-ctrip.com/images/1lo2y12000qowdkb31F14.jpg\", \"https://dimg04.c-ctrip.com/images/0105u120008h4x6scABC4.png\", \"https://dimg04.c-ctrip.com/images/1lo4g12000e11pr8tACB7.jpg\", \"https://dimg04.c-ctrip.com/images/0zg5u12000ickqah279E9.jpg\", \"https://dimg04.c-ctrip.com/images/0102w12000873g3z738FA.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 498.00, NULL, '10:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5002, '尖沙咀海滨花园', '维港观景台', '尖沙咀海滨花园是欣赏维港夜景的最佳地点，星光大道、钟楼、文化中心都在此。', 1, 2058, '香港特别行政区油尖旺区尖沙咀', 22.30000000, 114.16666667, 'https://dimg04.c-ctrip.com/images/0105x1200085qcb8kC266.jpg', '[\"https://dimg04.c-ctrip.com/images/0105x1200085qcb8kC266.jpg\", \"https://dimg04.c-ctrip.com/images/0104h120008286fzh1403.jpg\", \"https://dimg04.c-ctrip.com/images/0100r1200089l0mej27A5.jpg\", \"https://dimg04.c-ctrip.com/images/0100x120008286qug2E3E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4u12000icm2gvs0E3D.jpg\", \"https://dimg04.c-ctrip.com/images/0Z80d3215ac8sbadcDBB6_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5003, '大三巴牌坊', '澳门地标', '大三巴牌坊是圣保禄教堂的前壁遗址，融合欧洲文艺复兴时期与东方建筑风格，是澳门的象征。', 2, 2059, '澳门特别行政区花王堂区大三巴街', 22.20000000, 113.53333333, '/images/attractions/ruins-stpaul.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (5004, '澳门旅游塔', '全球十大观光塔之一', '澳门塔高338米，可俯瞰澳门全景，塔顶有蹦极、空中漫步等极限运动项目。', 3, 2059, '澳门特别行政区大堂区南湾新填海区', 22.18333333, 113.53333333, '/images/attractions/macau-tower.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 185.00, NULL, '10:00-21:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (5005, '威尼斯人度假村', '水城风情', '威尼斯人度假村以威尼斯水乡为主题，拥有运河、贡多拉船、购物中心、赌场等，是澳门最大的综合度假村。', 3, 2059, '澳门特别行政区路氹城望德圣母湾大马路', 22.15000000, 113.55000000, '/images/attractions/venetian.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (5006, '妈阁庙', '澳门名字的由来', '妈阁庙是澳门最古老的庙宇，供奉妈祖，葡萄牙人登陆时询问地名，居民答“妈阁”，澳门葡文名“Macau”由此而来。', 2, 2059, '澳门特别行政区风顺堂区妈阁庙前地', 22.18333333, 113.51666667, 'https://dimg04.c-ctrip.com/images/0107112000f6o3a6a1541.jpg', '[\"https://dimg04.c-ctrip.com/images/0107112000f6o3a6a1541.jpg\", \"https://dimg04.c-ctrip.com/images/0105a12000ro0u6yaB16A.jpg\", \"https://dimg04.c-ctrip.com/images/0103612000f6o3l7qC89F.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M03/88/C9/CghzgVWwv-KAStcoABEa-cXClp0489.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1312000icyee8oA627.jpg\", \"https://dimg04.c-ctrip.com/images/1h64q120008lvdiiw18BE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '07:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5007, '澳门博物馆', '澳门历史文化', '澳门博物馆位于大炮台上，展示澳门的历史、民俗和传统文化，登顶可俯瞰澳门全景。', 2, 2059, '澳门特别行政区花王堂区博物馆前地', 22.20000000, 113.53333333, '/images/attractions/macau-museum.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 15.00, NULL, '10:00-18:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (5008, '台北故宫博物院', '中华文化宝库', '台北故宫博物院收藏了65万件中华文化艺术瑰宝，包括翠玉白菜、肉形石、毛公鼎等镇馆之宝。', 2, 2060, '台湾省台北市士林区至善路二段221号', 25.10000000, 121.55000000, 'https://dimg04.c-ctrip.com/images/fd/tg/g4/M01/72/7D/CggYHFY7F7iAF6-bAAtq3wFHDJY069.jpg', '[\"https://dimg04.c-ctrip.com/images/fd/tg/g4/M01/72/7D/CggYHFY7F7iAF6-bAAtq3wFHDJY069.jpg\", \"https://dimg04.c-ctrip.com/images/1001180000015mwemA033.jpg\", \"https://dimg04.c-ctrip.com/images/100q13000000tzy3r5041.jpg\", \"https://dimg04.c-ctrip.com/images/0106l12000ac4z2eq562D.jpg\", \"https://dimg04.c-ctrip.com/images/0zg0q12000icklz145A79.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g4/M01/72/7D/CggYHFY7F7iAF6-bAAtq3wFHDJY069_Z_1000_0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 350.00, NULL, '08:30-18:30', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5009, '台北101大楼', '台北地标', '台北101曾是世界最高建筑，楼高508米，观景台可俯瞰台北全景，跨年烟花秀闻名全球。', 3, 2060, '台湾省台北市信义区信义路五段7号', 25.03333333, 121.56666667, 'https://dimg04.c-ctrip.com/images/1lo6512000nye4tcqACA1.jpg', '[\"https://dimg04.c-ctrip.com/images/1lo6512000nye4tcqACA1.jpg\", \"https://dimg04.c-ctrip.com/images/1lo4e12000p1j19lj12F9.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0r12000p1j1augCE1D.jpg\", \"https://dimg04.c-ctrip.com/images/1lo0112000ogxihzoC955.jpg\", \"https://dimg04.c-ctrip.com/images/0zg1b12000icl5h61C4BB.jpg\", \"https://dimg04.c-ctrip.com/images/0356u12000r8caysf661B_Z_1000_0.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 600.00, NULL, '09:00-22:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5010, '日月潭', '台湾最大天然湖泊', '日月潭是台湾最著名的风景区，湖中有拉鲁岛，北半湖形如圆日，南半湖形如弯月，湖光山色，景色宜人。', 1, 2061, '台湾省南投县鱼池乡', 23.86666667, 120.91666667, 'https://dimg04.c-ctrip.com/images/0101612000ac3yksi17D9.jpg', '[\"https://dimg04.c-ctrip.com/images/0101612000ac3yksi17D9.jpg\", \"https://dimg04.c-ctrip.com/images/100j0g00000088aec4E60.jpg\", \"https://dimg04.c-ctrip.com/images/100w0p000000fu1kd2CCE.jpg\", \"https://dimg04.c-ctrip.com/images/100o0p000000fmv3iAF2E.jpg\", \"https://dimg04.c-ctrip.com/images/0zg7312000icnrfk62B4B.jpg\", \"https://dimg04.c-ctrip.com/images/100a0p000000fpq1l0238.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 100.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5011, '阿里山', '五奇著称', '阿里山以森林、云海、日出、晚霞、小火车五奇著称，春季樱花盛开，是台湾最具代表性的自然景区。', 1, 2062, '台湾省嘉义县阿里山乡', 23.51666667, 120.80000000, '/images/attractions/alishan.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 300.00, NULL, '全天', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
INSERT INTO `attraction` VALUES (5012, '士林夜市', '台湾第一夜市', '士林夜市是台北最大的夜市，拥有数百家小吃摊位，蚵仔煎、大肠包小肠、豪大大鸡排等美食闻名。', 2, 2060, '台湾省台北市士林区基河路', 25.08333333, 121.51666667, 'https://dimg04.c-ctrip.com/images/100o1f000001gp48p077E.jpg', '[\"https://dimg04.c-ctrip.com/images/100o1f000001gp48p077E.jpg\", \"https://dimg04.c-ctrip.com/images/100e0d0000006uk2k0EA8.jpg\", \"https://dimg04.c-ctrip.com/images/100510000000p5ev945FE.jpg\", \"https://dimg04.c-ctrip.com/images/fd/tg/g2/M04/2D/FE/CghzgVW2KzOAWMROABSfDFsVClI338.jpg\", \"https://dimg04.c-ctrip.com/images/0zg4p12000icl3kff5022.jpg\", \"https://dimg04.c-ctrip.com/images/0Z83s224x8u5qu8l3C2DE_R_180_180.jpg\"]', 0.00, 0, 0, 0, 0, NULL, 0.00, NULL, '16:00-24:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-22 22:28:27');
INSERT INTO `attraction` VALUES (5013, '清境农场', '台湾小瑞士', '清境农场位于高山，草原广阔，欧式建筑林立，可观赏绵羊秀、远眺合欢山，有“台湾小瑞士”之称。', 1, 2061, '台湾省南投县仁爱乡', 24.05000000, 121.16666667, '/images/attractions/chingjing.jpg', NULL, 0.00, 0, 0, 0, 0, NULL, 200.00, NULL, '08:00-17:00', '全年', NULL, NULL, NULL, NULL, 1, 2, NULL, '2026-03-19 18:43:25', '2026-03-19 18:43:25');
