INSERT INTO `city` VALUES (1682, '乌鲁木齐', '中国', 'https://dimg04.c-ctrip.com/images/100f0m000000dxl7eABE2_C_1180_462.jpg', 7.4, 8, 95, '乌鲁木齐是新疆维吾尔自治区的首府，地处亚欧大陆中心，拥有丰富的历史文化和独特的自然风光，是中国西北地区的重要城市。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:32:09');
INSERT INTO `city` VALUES (1683, '喀什', '中国', 'https://dimg04.c-ctrip.com/images/0101i120008oxt2myD303_C_1180_462.jpg', 12.3, 10, 90, '喀什是中国新疆维吾尔自治区的一个重要城市，具有丰富的历史文化和独特的地理位置，是丝绸之路的重要节点。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:32:30');
INSERT INTO `city` VALUES (1684, '伊犁', '中国', 'https://dimg04.c-ctrip.com/images/0102j120004gmqoh9A62A_D_223_168.jpg', 8.5, 12, 88, '伊犁哈萨克自治州，别名伊犁，是新疆维吾尔自治区自治州，位于中国的西北边陲，新疆西北部，东北与俄罗斯、蒙古国接壤，西与哈萨克斯坦共和国交界', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:33:07');
INSERT INTO `city` VALUES (1685, '吐鲁番', '中国', 'https://dimg04.c-ctrip.com/images/0102a1200086v5avqA3B9_D_223_168.jpg', 14.5, 6, 85, '\r\n\r\n吐鲁番是新疆维吾尔自治区的地级市，以干热气候、葡萄和哈密瓜闻名，同时拥有丰富的历史文化遗产和旅游资源。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:33:09');
INSERT INTO `city` VALUES (1686, '阿勒泰', '中国', 'https://dimg04.c-ctrip.com/images/010741200099zjitrC667_C_1180_462.jpg', 4.0, 7, 82, '阿勒泰地区是中国西北唯一与俄罗斯接壤的地区', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:33:35');
INSERT INTO `city` VALUES (1687, '巴音郭楞', '中国', 'https://dimg04.c-ctrip.com/images/0103c120008aomd85C523_C_1180_462.jpg', 8.8, 7, 78, '巴音郭楞蒙古自治州，简称 巴州，“巴音郭楞”为蒙古语音译，意为“ 富饶的流域 ”， 隶属新疆维吾尔自治区，位于新疆维吾尔自治区东南部', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:33:38');
INSERT INTO `city` VALUES (1688, '阿克苏', '中国', 'https://dimg04.c-ctrip.com/images/01033120009bxtps2EECE_C_1180_462.jpg', 10.7, 3, 75, '阿克苏，别称白水城，隶属新疆维吾尔自治区阿克苏地区，地处南疆中部、塔克拉玛干大沙漠西北边缘、塔里木河上游，是干旱气候地区，水能资源丰富，地下水1.01亿立方米。矿产资源丰富，已发现矿种17 种，可利用资源储量的矿种7种。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:33:57');
INSERT INTO `city` VALUES (1689, '和田', '中国', 'https://dimg04.c-ctrip.com/images/010231200086k2rlbE407_C_1180_462.jpg', 12.2, 4, 70, '和田，位于新疆最南端，古称 于阗，藏话意思为“产玉石的地方”。 是 丝绸之路 南道上的重镇。 素有“玉石之都”的美名。 1959年，“和阗”又改“和田”，1983年设市，成为 和田地区 的中心。 和田地区总面积为24.8万平方公里，人口150万。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:34:08');
INSERT INTO `city` VALUES (1690, '克拉玛依', '中国', 'https://dimg04.c-ctrip.com/images/010241200085vfwkzAB33_C_1180_462.jpg', 8.6, 3, 68, '新疆维吾尔自治区下辖地级市，别称黑油山，位于新疆维吾尔自治区北部，准噶尔盆地西北边缘，加依尔山南麓之间。', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:34:38');
INSERT INTO `city` VALUES (1691, '塔城', '中国', 'https://n.sinaimg.cn/sinacn20110/298/w1618h1080/20190802/c239-iaqfzyw1284966.jpg', 6.0, 4, 65, '塔城是新疆维吾尔自治区塔城地区下辖县级市，是塔城地委、行署所在地。 位于中国西北边陲，地处塔额盆地北缘', 0, 1, '2026-03-19 17:16:15', '2026-03-23 18:34:58');
INSERT INTO `city` VALUES (1779, '西宁市', '中国', 'https://tr-osdcp.qunarzz.com/tr-osd-tr-manager/img/ab470dbd6eafee33a887caef16f20d07.jpg', 5.8, 6, 1000, '青海省省会，古称“青唐城”，是青藏高原的东方门户，素有“西海锁钥”之称。拥有塔尔寺、东关清真大寺等著名景点。[citation:2][citation:7]', 1, 1, '2026-03-19 17:39:21', '2026-03-23 18:35:52');
INSERT INTO `city` VALUES (1780, '湟中区', '中国', 'https://p1.ssl.qhimg.com/t0108cd15027ddd83af.png', 5.5, 1, 500, '西宁市下辖区，藏传佛教格鲁派六大寺院之一的塔尔寺所在地，被誉为“佛祖诞生地”。[citation:2]', 2, 1, '2026-03-19 17:39:21', '2026-03-23 18:35:57');
INSERT INTO `city` VALUES (1781, '湟源县', '中国', 'https://news.hangzhou.com.cn/gnxw/content/2022-08/29/e08acd39-e06b-42d6-920d-379dbd6ae945.jpg', 5.0, 1, 300, '西宁市下辖县，青藏高原重要的农业区和商贸集散地，拥有丹噶尔古城。[citation:2]', 3, 1, '2026-03-19 17:39:21', '2026-03-23 18:36:27');
INSERT INTO `city` VALUES (1782, '大通回族土族自治县', '中国', 'https://dimg04.c-ctrip.com/images/350q160000010obxrE32C_C_1180_462.jpg', 4.5, 0, 250, '西宁市下辖县，高原旅游胜地，拥有老爷山、鹞子沟等景区。[citation:2]', 4, 1, '2026-03-19 17:39:21', '2026-03-23 18:38:20');
INSERT INTO `city` VALUES (1783, '海东市', '中国', 'https://dimg04.c-ctrip.com/images/0103m1200090fokjd9579_C_1180_462.jpg', 7.0, 0, 600, '青海省地级市，位于青海湖以东，是连接兰州和西宁的重要节点城市。[citation:2]', 5, 1, '2026-03-19 17:39:21', '2026-03-23 18:38:39');
INSERT INTO `city` VALUES (1784, '乐都区', '中国', 'https://dimg04.c-ctrip.com/images/1A0t170000011pyp0B51C_C_1180_462.jpg', 6.8, 1, 300, '海东市核心区，河湟文化的重要发祥地，拥有瞿昙寺。[citation:2]', 6, 1, '2026-03-19 17:39:21', '2026-03-23 18:39:16');
INSERT INTO `city` VALUES (1785, '平安区', '中国', 'https://dimg04.c-ctrip.com/images/100w170000013bqi24278_C_1180_462.jpg', 6.5, 1, 250, '海东市辖区，古称“平安驿”，是青藏铁路的重要站点。[citation:2]', 7, 1, '2026-03-19 17:39:21', '2026-03-23 18:39:30');
INSERT INTO `city` VALUES (1786, '互助土族自治县', '中国', 'https://dimg04.c-ctrip.com/images/100i1a0000019oiyg4424_C_1180_462.jpg', 5.5, 1, 500, '全国唯一的土族自治县，拥有互助土族故土园5A级景区。[citation:1][citation:2]', 8, 1, '2026-03-19 17:39:21', '2026-03-23 18:39:51');
INSERT INTO `city` VALUES (1787, '民和回族土族自治县', '中国', 'https://dimg04.c-ctrip.com/images/0100h12000ax9vzmxD468_C_1180_462.jpg', 8.0, 0, 200, '青海省东大门，与甘肃省接壤。[citation:2]', 9, 1, '2026-03-19 17:39:21', '2026-03-23 18:40:06');
INSERT INTO `city` VALUES (1788, '化隆回族自治县', '中国', 'https://dimg04.c-ctrip.com/images/0105q12000f9nfadsBFE5_C_1180_462.jpg', 6.0, 0, 180, '以化隆拉面闻名全国。[citation:2]', 10, 1, '2026-03-19 17:39:21', '2026-03-23 18:40:17');
INSERT INTO `city` VALUES (1789, '循化撒拉族自治县', '中国', 'https://dimg04.c-ctrip.com/images/100f0z000000nj9vdAACC_C_1180_462.jpg', 8.5, 1, 350, '全国唯一的撒拉族自治县，拥有孟达天池、骆驼泉等景区。[citation:2]', 11, 1, '2026-03-19 17:39:21', '2026-03-23 18:40:29');
INSERT INTO `city` VALUES (1790, '海北藏族自治州', '中国', 'https://dimg04.c-ctrip.com/images/100w1f000001gwcvu3D07_C_1180_462.jpg', 0.5, 0, 700, '位于青海湖北岸，拥有金银滩草原、原子城等著名景区。[citation:2]', 12, 1, '2026-03-19 17:39:21', '2026-03-23 18:40:45');
INSERT INTO `city` VALUES (1791, '门源回族自治县', '中国', 'https://dimg04.c-ctrip.com/images/0101k120009eh8v9m05E7_C_1180_462.jpg', 0.0, 2, 600, '以百里油菜花海闻名全国，是夏季旅游热门目的地。[citation:1][citation:2]', 13, 1, '2026-03-19 17:39:21', '2026-03-23 18:40:57');
INSERT INTO `city` VALUES (1792, '祁连县', '中国', 'https://dimg04.c-ctrip.com/images/0100x1200090fopjz9D55_C_1180_462.jpg', -0.5, 2, 650, '“天境祁连”，拥有阿咪东索、卓尔山等著名景区。[citation:1][citation:2]', 14, 1, '2026-03-19 17:39:21', '2026-03-23 18:41:11');
INSERT INTO `city` VALUES (1793, '刚察县', '中国', 'https://dimg04.c-ctrip.com/images/1lo1l12000e4k8unqF06A_C_1180_462.jpg', -0.8, 0, 400, '青海湖北岸，拥有湟鱼洄游奇观。[citation:1][citation:2]', 15, 1, '2026-03-19 17:39:21', '2026-03-23 18:41:24');
INSERT INTO `city` VALUES (1794, '海晏县', '中国', 'https://dimg04.c-ctrip.com/images/0103712000rkb7ecy5AA8_C_1180_462.jpg', -0.3, 2, 450, '原子城所在地，中国第一颗原子弹和氢弹研制基地。[citation:1][citation:2]', 16, 1, '2026-03-19 17:39:21', '2026-03-23 18:41:38');
INSERT INTO `city` VALUES (1795, '海南藏族自治州', '中国', 'https://tr-osdcp.qunarzz.com/tr-osd-tr-manager/img/6a1ebd941f1c9abc372111718e97ea2a.jpg_r_480x360x95_73eb0e86.jpg', 2.0, 0, 600, '青海湖南岸，拥有青海湖主景区二郎剑、龙羊峡等。[citation:2]', 17, 1, '2026-03-19 17:39:21', '2026-03-23 18:42:48');
INSERT INTO `city` VALUES (1796, '共和县', '中国', 'https://bkimg.cdn.bcebos.com/pic/2cf5e0fe9925bc315c60587e4b849ab1cb134854da98?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', 2.5, 3, 550, '海南州府所在地，青海湖二郎剑景区所在地。[citation:1][citation:2]', 18, 1, '2026-03-19 17:39:21', '2026-03-23 18:44:08');
INSERT INTO `city` VALUES (1797, '贵德县', '中国', 'https://dimg04.c-ctrip.com/images/0100t120009ehb6876A95_C_1180_462.jpg', 7.5, 2, 500, '“天下黄河贵德清”，拥有清清黄河、贵德国家地质公园。[citation:6][citation:2]', 19, 1, '2026-03-19 17:39:21', '2026-03-23 18:44:26');
INSERT INTO `city` VALUES (1798, '兴海县', '中国', 'https://dimg04.c-ctrip.com/images/100n160000010omgrB847_C_1180_462.jpg', 1.5, 0, 150, '海南州下辖县。[citation:2]', 20, 1, '2026-03-19 17:39:21', '2026-03-23 18:44:39');
INSERT INTO `city` VALUES (1799, '同德县', '中国', 'https://bkimg.cdn.bcebos.com/pic/b8014a90f603738dc44ab371bc1bb051f819ec65?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', 1.0, 0, 120, '海南州下辖县。[citation:2]', 21, 1, '2026-03-19 17:39:21', '2026-03-23 18:45:07');
INSERT INTO `city` VALUES (1800, '贵南县', '中国', 'https://k.sinaimg.cn/n/spider20220802/450/w800h450/20220802/9f64-b91792aeea6f51a97fbaf6584eda4d68.jpg/w700h350z1l10t102cc.jpg', 2.0, 0, 130, '海南州下辖县。[citation:2]', 22, 1, '2026-03-19 17:39:21', '2026-03-23 18:45:21');
INSERT INTO `city` VALUES (1801, '海西蒙古族藏族自治州', '中国', 'https://dimg04.c-ctrip.com/images/0103m1200086jv56c6AE6_C_1180_462.jpg', 3.0, 0, 900, '“聚宝盆”柴达木盆地的主体，拥有茶卡盐湖、水上雅丹、翡翠湖等。[citation:2]', 23, 1, '2026-03-19 17:39:21', '2026-03-23 18:45:40');
INSERT INTO `city` VALUES (1802, '格尔木市', '中国', 'https://dimg04.c-ctrip.com/images/0104w1200090fmg2iF466_C_1180_462.jpg', 4.5, 2, 800, '青海省第二大城市，青藏铁路重要枢纽，察尔汗盐湖所在地。[citation:2][citation:4]', 24, 1, '2026-03-19 17:39:21', '2026-03-23 18:50:13');
INSERT INTO `city` VALUES (1803, '德令哈市', '中国', 'https://dimg04.c-ctrip.com/images/01034120009eh6ff39FEE_C_1180_462.jpg', 3.5, 1, 400, '海西州府，诗人海子笔下的“雨水中一座荒凉的城”。[citation:2]', 25, 1, '2026-03-19 17:39:21', '2026-03-23 18:50:25');
INSERT INTO `city` VALUES (1804, '茫崖市', '中国', 'https://dimg04.c-ctrip.com/images/0102w12000b9wpy773DD6_C_1180_462.jpg', 2.0, 3, 500, '青海省最年轻的城市，拥有翡翠湖、艾肯泉（恶魔之眼）。[citation:2][citation:6]', 26, 1, '2026-03-19 17:39:21', '2026-03-23 18:50:51');
INSERT INTO `city` VALUES (1805, '乌兰县', '中国', 'https://dimg04.c-ctrip.com/images/0101v120009eh9dfb4947_C_1180_462.jpg', 3.0, 1, 700, '茶卡盐湖所在地。[citation:2][citation:4]', 27, 1, '2026-03-19 17:39:21', '2026-03-23 18:51:01');
INSERT INTO `city` VALUES (1806, '都兰县', '中国', 'https://dimg04.c-ctrip.com/images/1lo1d12000px81fon7377_C_1180_462.jpg', 2.5, 0, 200, '海西州下辖县。[citation:2]', 28, 1, '2026-03-19 17:39:21', '2026-03-23 18:51:12');
INSERT INTO `city` VALUES (1807, '天峻县', '中国', 'https://dimg04.c-ctrip.com/images/0106l120008bwc8raED08_C_1180_462.jpg', -0.5, 0, 150, '海西州下辖县。[citation:2]', 29, 1, '2026-03-19 17:39:21', '2026-03-23 18:51:57');
INSERT INTO `city` VALUES (1808, '大柴旦', '中国', 'https://dimg04.c-ctrip.com/images/0101v120008abkn61ACE1_C_1180_462.jpg', 1.5, 1, 550, '海西州派出机构，大柴旦翡翠湖所在地。[citation:2][citation:6]', 30, 1, '2026-03-19 17:39:21', '2026-03-23 18:52:20');
INSERT INTO `city` VALUES (1809, '黄南藏族自治州', '中国', 'https://dimg04.c-ctrip.com/images/0104u120009eh91pdE784_C_1180_462.jpg', 5.0, 0, 450, '热贡艺术发源地，拥有隆务寺、坎布拉国家森林公园。[citation:2][citation:3]', 31, 1, '2026-03-19 17:39:21', '2026-03-23 18:53:01');
INSERT INTO `city` VALUES (1810, '同仁市', '中国', 'https://dimg04.c-ctrip.com/images/100n0z000000npv7sFBE8_C_1180_462.jpg', 5.5, 2, 500, '国家级历史文化名城，热贡艺术核心区，隆务寺所在地。[citation:2][citation:6]', 32, 1, '2026-03-19 17:39:21', '2026-03-23 18:53:14');
INSERT INTO `city` VALUES (1811, '尖扎县', '中国', 'https://dimg04.c-ctrip.com/images/350m14000000x63m7E721_C_1180_462.jpg', 6.0, 1, 450, '坎布拉国家森林公园所在地。[citation:2]', 33, 1, '2026-03-19 17:39:21', '2026-03-23 18:53:23');
INSERT INTO `city` VALUES (1812, '泽库县', '中国', 'https://news.hangzhou.com.cn/gnxw/content/2022-06/27/20ca3c28-bb91-4224-9343-631c772e188b.jpg', 0.5, 0, 100, '黄南州下辖县。[citation:2]', 34, 1, '2026-03-19 17:39:21', '2026-03-23 18:53:47');
INSERT INTO `city` VALUES (1813, '河南蒙古族自治县', '中国', 'https://bkimg.cdn.bcebos.com/pic/d043ad4bd11373f01b4d08bfa70f4bfbfbed049b?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', 0.8, 0, 90, '黄南州下辖县。[citation:2]', 35, 1, '2026-03-19 17:39:21', '2026-03-23 18:54:22');
INSERT INTO `city` VALUES (1814, '果洛藏族自治州', '中国', 'https://bkimg.cdn.bcebos.com/pic/b219ebc4b74543a9a3051f5213178a82b9011415?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', -0.5, 0, 400, '黄河源头所在地，拥有年保玉则、阿尼玛卿雪山。[citation:2]', 36, 1, '2026-03-19 17:39:21', '2026-03-23 18:55:03');
INSERT INTO `city` VALUES (1815, '玛沁县', '中国', 'https://dimg04.c-ctrip.com/images/0104j120008i89mipA36A_C_1180_462.jpg', -0.8, 1, 250, '果洛州府，阿尼玛卿雪山所在地。[citation:2]', 37, 1, '2026-03-19 17:39:21', '2026-03-23 18:55:23');
INSERT INTO `city` VALUES (1816, '班玛县', '中国', 'https://bkimg.cdn.bcebos.com/pic/fcfaaf51f3deb48fce6bda1df21f3a292cf578f6?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', 1.5, 0, 120, '果洛州下辖县。[citation:2]', 38, 1, '2026-03-19 17:39:21', '2026-03-23 18:55:53');
INSERT INTO `city` VALUES (1817, '甘德县', '中国', 'https://bkimg.cdn.bcebos.com/pic/cdbf6c81800a19d806fe41cb31fa828ba71e467b?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', -1.0, 0, 80, '果洛州下辖县。[citation:2]', 39, 1, '2026-03-19 17:39:21', '2026-03-23 18:56:17');
INSERT INTO `city` VALUES (1818, '达日县', '中国', 'https://bkimg.cdn.bcebos.com/pic/d009b3de9c82d15813cdabdc820a19d8bc3e4214?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', -0.5, 0, 90, '果洛州下辖县。[citation:2]', 40, 1, '2026-03-19 17:39:21', '2026-03-23 18:56:33');
INSERT INTO `city` VALUES (1819, '久治县', '中国', 'https://dimg04.c-ctrip.com/images/100a0z000000n593h362D_C_1180_462.jpg', 0.0, 1, 350, '年保玉则景区所在地（目前暂时关闭）。[citation:2]', 41, 1, '2026-03-19 17:39:21', '2026-03-23 18:56:55');
INSERT INTO `city` VALUES (1820, '玛多县', '中国', 'https://dimg04.c-ctrip.com/images/100q0v000000jy0c460FA_C_1180_462.jpg', -2.0, 1, 150, '黄河源头，扎陵湖、鄂陵湖所在地。[citation:2]', 42, 1, '2026-03-19 17:39:21', '2026-03-23 18:57:05');
INSERT INTO `city` VALUES (1821, '玉树藏族自治州', '中国', 'https://dimg04.c-ctrip.com/images/01038120008aof7gbAEBD_C_1180_462.jpg', 2.5, 0, 500, '三江源核心区，拥有新寨玛尼堆、勒巴沟、文成公主庙。[citation:2]', 43, 1, '2026-03-19 17:39:21', '2026-03-23 18:58:49');
INSERT INTO `city` VALUES (1822, '玉树市', '中国', 'https://dimg04.c-ctrip.com/images/0105h120009eh8xrb2F7B_C_1180_462.jpg', 3.0, 4, 400, '玉树州府，2010年地震后重建的高原新城。[citation:2]', 44, 1, '2026-03-19 17:39:21', '2026-03-23 18:59:03');
INSERT INTO `city` VALUES (1823, '称多县', '中国', 'https://dimg04.c-ctrip.com/images/10051f000001gsqg73495_C_1180_462.jpg', 1.5, 0, 80, '玉树州下辖县。[citation:2]', 45, 1, '2026-03-19 17:39:21', '2026-03-23 18:59:12');
INSERT INTO `city` VALUES (1824, '囊谦县', '中国', 'https://dimg04.c-ctrip.com/images/01003120008inntnb9881_C_1180_462.jpg', 4.0, 0, 90, '玉树州下辖县。[citation:2]', 46, 1, '2026-03-19 17:39:21', '2026-03-23 18:59:22');
INSERT INTO `city` VALUES (1825, '杂多县', '中国', 'https://dimg04.c-ctrip.com/images/01A071200002zr8fr9603_C_1180_462.jpg', 0.5, 0, 100, '玉树州下辖县，澜沧江源头。[citation:2]', 47, 1, '2026-03-19 17:39:21', '2026-03-23 18:59:30');
INSERT INTO `city` VALUES (1826, '治多县', '中国', 'https://dimg04.c-ctrip.com/images/0104p12000evbl2jwB662_C_1180_462.jpg', -0.5, 0, 110, '玉树州下辖县，长江源头。[citation:2]', 48, 1, '2026-03-19 17:39:21', '2026-03-23 18:59:41');
INSERT INTO `city` VALUES (1827, '曲麻莱县', '中国', 'https://dimg04.c-ctrip.com/images/0105w12000pjauksbA9A7_C_1180_462.jpg', -1.0, 0, 120, '玉树州下辖县，黄河源头。[citation:2]', 49, 1, '2026-03-19 17:39:21', '2026-03-23 19:00:46');
INSERT INTO `city` VALUES (1828, '嘉峪关市', '中国', 'https://dimg04.c-ctrip.com/images/100e10000000o64omC2A6_C_1180_462.jpg', 7.5, 4, 900, '万里长城西端起点，因“天下第一雄关”嘉峪关而得名，素有“边陲锁钥”之称。', 1, 1, '2026-03-19 17:50:39', '2026-03-23 19:00:58');
INSERT INTO `city` VALUES (1829, '酒泉市', '中国', 'https://dimg04.c-ctrip.com/images/0101k12000hnps3my27D8_C_1180_462.jpg', 8.0, 7, 1000, '敦煌艺术的故乡，中国航天事业的摇篮，拥有莫高窟、鸣沙山月牙泉等世界级景点。', 2, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:07');
INSERT INTO `city` VALUES (1830, '张掖市', '中国', 'https://dimg04.c-ctrip.com/images/0100j120004gghj2nF26A_C_1180_462.jpg', 7.0, 6, 950, '“塞上江南”，七彩丹霞所在地，自古就是丝绸之路重镇。', 3, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:16');
INSERT INTO `city` VALUES (1831, '金昌市', '中国', 'https://dimg04.c-ctrip.com/images/0101s120009ehdnowA2E2_C_1180_462.jpg', 9.0, 2, 300, '“镍都”，紫金花城，戈壁滩上的工业新城。', 4, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:25');
INSERT INTO `city` VALUES (1832, '武威市', '中国', 'https://dimg04.c-ctrip.com/images/0105f1200090fnf2iEB59_C_1180_462.jpg', 8.5, 4, 700, '“铜奔马”出土地，古称凉州，是丝绸之路自东向西进入河西走廊的第一重镇。', 5, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:34');
INSERT INTO `city` VALUES (1833, '兰州市', '中国', 'https://dimg04.c-ctrip.com/images/100g0x000000lgz6t7BB3_C_1180_462.jpg', 10.5, 6, 950, '甘肃省省会，黄河唯一穿城而过的省会城市，享有“黄河之都”美誉。', 6, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:44');
INSERT INTO `city` VALUES (1834, '兰州新区', '中国', 'https://dimg04.c-ctrip.com/images/100r0z000000n8ruu93F3_C_1180_462.jpg', 9.5, 0, 200, '国家级新区，西北地区重要的经济增长极。', 7, 1, '2026-03-19 17:50:39', '2026-03-23 19:01:55');
INSERT INTO `city` VALUES (1835, '白银市', '中国', 'https://dimg04.c-ctrip.com/images/0106e1200087dxd4aE99D_C_1180_462.jpg', 9.0, 2, 400, '“铜城”，黄河石林所在地，红色旅游胜地。', 8, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:04');
INSERT INTO `city` VALUES (1836, '定西市', '中国', 'https://dimg04.c-ctrip.com/images/100u0w000000k5tliC34A_C_1180_462.jpg', 7.5, 2, 350, '“中国薯都”，渭河源头，黄土高原特色旅游目的地。', 9, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:12');
INSERT INTO `city` VALUES (1837, '天水市', '中国', 'https://dimg04.c-ctrip.com/images/010181200087dasi97C8F_C_1180_462.jpg', 11.5, 5, 850, '“羲皇故里”，全球华人寻根祭祖圣地，麦积山石窟所在地。', 10, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:21');
INSERT INTO `city` VALUES (1838, '平凉市', '中国', 'https://dimg04.c-ctrip.com/images/0100m1200087d8b7g17E8_C_1180_462.jpg', 9.5, 3, 700, '“道源圣地”，崆峒山所在地，养生旅游胜地。', 11, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:30');
INSERT INTO `city` VALUES (1839, '庆阳市', '中国', 'https://dimg04.c-ctrip.com/images/0100x120009ehdhxoAC74_C_1180_462.jpg', 9.0, 2, 350, '“农耕文明发源地”，周祖陵、红色南梁所在地。', 12, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:39');
INSERT INTO `city` VALUES (1840, '陇南市', '中国', 'https://dimg04.c-ctrip.com/images/01038120009eheae8CB09_C_1180_462.jpg', 14.0, 5, 650, '“陇上江南”，甘肃唯一的长江流域地区，官鹅沟5A景区所在地。', 13, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:47');
INSERT INTO `city` VALUES (1841, '临夏回族自治州', '中国', 'https://dimg04.c-ctrip.com/images/0102s1200098wpqv3496F_C_1180_462.jpg', 9.0, 3, 500, '“中国小麦加”，穆斯林风情浓郁，炳灵寺世界文化遗产旅游区所在地。', 14, 1, '2026-03-19 17:50:39', '2026-03-23 19:02:55');
INSERT INTO `city` VALUES (1842, '甘南藏族自治州', '中国', 'https://dimg04.c-ctrip.com/images/0102r12000ey3tq3h3453_C_1180_462.jpg', 3.5, 6, 800, '“九色香巴拉”，青藏之窗，冶力关5A景区所在地，扎尕那为世界级网红打卡地。', 15, 1, '2026-03-19 17:50:39', '2026-03-23 19:03:12');
INSERT INTO `city` VALUES (1843, '西安市', '中国', 'https://dimg04.c-ctrip.com/images/0106m120004eks4oyF624_C_1180_462.jpg', 13.5, 9, 1000, '十三朝古都，世界历史名城，丝绸之路的起点，拥有秦始皇兵马俑、大雁塔、城墙等世界级文化遗产。', 1, 1, '2026-03-19 17:58:12', '2026-03-23 19:03:22');
INSERT INTO `city` VALUES (1844, '铜川市', '中国', 'https://dimg04.c-ctrip.com/images/01023120009eh5i8aFEDA_C_1180_462.jpg', 12.0, 4, 300, '“耀州瓷”故乡，药王孙思邈故里，拥有药王山、玉华宫、照金香山等景区。', 2, 1, '2026-03-19 17:58:12', '2026-03-23 19:03:34');
INSERT INTO `city` VALUES (1845, '宝鸡市', '中国', 'https://dimg04.c-ctrip.com/images/0101x120008k3ipk96887_C_1180_462.jpg', 12.5, 4, 700, '炎帝故里，青铜器之乡，法门寺、太白山所在地，周秦文化发祥地。', 3, 1, '2026-03-19 17:58:12', '2026-03-23 19:03:53');
INSERT INTO `city` VALUES (1846, '咸阳市', '中国', 'https://dimg04.c-ctrip.com/images/100o1f000001gp3s825D2_C_1180_462.jpg', 13.0, 4, 800, '中国第一帝都，秦汉文化重要发源地，拥有乾陵、茂陵、昭陵等唐代帝陵群。', 4, 1, '2026-03-19 17:58:12', '2026-03-23 19:04:02');
INSERT INTO `city` VALUES (1847, '渭南市', '中国', 'https://dimg04.c-ctrip.com/images/010141200092lyxvn1D6A_C_1180_462.jpg', 13.5, 4, 850, '“三圣故里”，西岳华山所在地，拥有少华山、洽川湿地等自然景观。', 5, 1, '2026-03-19 17:58:12', '2026-03-23 19:04:12');
INSERT INTO `city` VALUES (1848, '杨凌农业高新技术产业示范区', '中国', 'https://bkimg.cdn.bcebos.com/pic/86d6277f9e2f07082838db65d27faf99a9014c085418?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080', 12.5, 0, 200, '中国首个农业高新技术产业示范区，农耕文明发源地之一。', 6, 1, '2026-03-19 17:58:12', '2026-03-23 19:05:46');
INSERT INTO `city` VALUES (1849, '延安市', '中国', 'https://dimg04.c-ctrip.com/images/01059120008axeyndAFBA_C_1180_462.jpg', 9.5, 5, 750, '中国革命圣地，宝塔山、枣园、杨家岭等红色遗址所在地，黄帝陵也坐落于此。', 7, 1, '2026-03-19 17:58:12', '2026-03-23 19:05:59');
INSERT INTO `city` VALUES (1850, '榆林市', '中国', 'https://dimg04.c-ctrip.com/images/010501200089qc9x6C27F_C_1180_462.jpg', 8.5, 5, 600, '“塞上明珠”，拥有镇北台、红石峡、石峁遗址、波浪谷等独特景观。', 8, 1, '2026-03-19 17:58:12', '2026-03-23 19:06:08');
INSERT INTO `city` VALUES (1851, '汉中市', '中国', 'https://dimg04.c-ctrip.com/images/10010v000000jxuf848C5_C_1180_462.jpg', 14.5, 5, 650, '“西北小江南”，汉文化发祥地，拥有武侯墓、石门栈道、黎坪国家森林公园。', 9, 1, '2026-03-19 17:58:12', '2026-03-23 19:06:19');
INSERT INTO `city` VALUES (1852, '安康市', '中国', 'https://dimg04.c-ctrip.com/images/0HJ6n12000rrax4fg3B1E_C_1180_462.jpg', 15.0, 4, 450, '“秦巴明珠”，瀛湖、南宫山、中坝大峡谷等生态旅游胜地。', 10, 1, '2026-03-19 17:58:12', '2026-03-23 19:06:31');
INSERT INTO `city` VALUES (1853, '商洛市', '中国', 'https://dimg04.c-ctrip.com/images/0103m120009eh5zo00DD8_C_1180_462.jpg', 13.5, 4, 500, '“秦岭最美是商洛”，金丝峡5A景区、牛背梁国家森林公园所在地。', 11, 1, '2026-03-19 17:58:12', '2026-03-23 19:06:40');
INSERT INTO `city` VALUES (1854, '成都市', '中国', 'https://dimg04.c-ctrip.com/images/100r1f000001gon9mBC5D_C_1180_462.jpg', 16.0, 5, 1000, '天府之国，中国最佳旅游城市，拥有青城山-都江堰、大熊猫繁育基地、武侯祠、杜甫草堂等世界级旅游资源。', 1, 1, '2026-03-19 18:05:37', '2026-03-23 19:06:49');
INSERT INTO `city` VALUES (1855, '都江堰市', '中国', 'https://dimg04.c-ctrip.com/images/010481200087cold8BDA3_C_1180_462.jpg', 15.5, 1, 800, '因都江堰水利工程而得名，青城山道教发源地，世界文化遗产地。', 2, 1, '2026-03-19 18:05:37', '2026-03-23 19:07:05');
INSERT INTO `city` VALUES (1856, '邛崃市', '中国', 'https://dimg04.c-ctrip.com/images/0101b120008wyaamjF6C4_C_1180_462.jpg', 16.5, 1, 400, '巴蜀四大古城之一，拥有天台山5A景区、平乐古镇等。', 3, 1, '2026-03-19 18:05:37', '2026-03-23 19:10:39');
INSERT INTO `city` VALUES (1857, '崇州市', '中国', 'https://dimg04.c-ctrip.com/images/100k12000000rutyw010D_C_1180_462.jpg', 16.0, 0, 350, '街子古镇、元通古镇所在地。', 4, 1, '2026-03-19 18:05:37', '2026-03-23 19:10:50');
INSERT INTO `city` VALUES (1858, '大邑县', '中国', 'https://dimg04.c-ctrip.com/images/0106d120008s72bu2C3DB_C_1180_462.jpg', 15.0, 2, 600, '安仁古镇5A景区、西岭雪山所在地。', 5, 1, '2026-03-19 18:05:37', '2026-03-23 19:10:59');
INSERT INTO `city` VALUES (1859, '绵阳市', '中国', 'https://dimg04.c-ctrip.com/images/100v14000000xatikC4CC_C_1180_462.jpg', 16.0, 3, 700, '中国科技城，拥有北川羌城5A景区、九皇山、窦圌山等。', 6, 1, '2026-03-19 18:05:37', '2026-03-23 19:11:08');
INSERT INTO `city` VALUES (1860, '广元市', '中国', 'https://dimg04.c-ctrip.com/images/0102e120009ehcwmvC7D9_C_1180_462.jpg', 16.0, 3, 700, '女皇故里，拥有剑门蜀道剑门关5A景区、皇泽寺、千佛崖等。', 7, 1, '2026-03-19 18:05:37', '2026-03-23 19:11:20');
INSERT INTO `city` VALUES (1861, '巴中市', '中国', 'https://dimg04.c-ctrip.com/images/0101r120009389iltA480_C_1180_462.jpg', 17.0, 1, 650, '革命老区，拥有光雾山5A景区、诺水河国家级风景名胜区。', 8, 1, '2026-03-19 18:05:37', '2026-03-23 19:11:28');
INSERT INTO `city` VALUES (1862, '南充市', '中国', 'https://dimg04.c-ctrip.com/images/01032120009eh67oc22DC_C_1180_462.jpg', 17.5, 2, 800, '三国文化发源地，拥有阆中古城5A景区、朱德故里5A景区。', 9, 1, '2026-03-19 18:05:37', '2026-03-23 19:11:40');
INSERT INTO `city` VALUES (1863, '广安市', '中国', 'https://dimg04.c-ctrip.com/images/0105o1200090fn8th95E0_C_1180_462.jpg', 18.0, 1, 700, '邓小平故里，拥有邓小平故里5A景区、华蓥山旅游区。', 10, 1, '2026-03-19 18:05:37', '2026-03-23 19:11:50');
INSERT INTO `city` VALUES (1864, '达州市', '中国', 'https://dimg04.c-ctrip.com/images/100k0w000000kcel7577A_C_1180_462.jpg', 17.0, 0, 450, '巴人故里，拥有真佛山、巴山大峡谷等景区。', 11, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:00');
INSERT INTO `city` VALUES (1865, '乐山市', '中国', 'https://dimg04.c-ctrip.com/images/0104r1200087cs4s52948_C_1180_462.jpg', 17.5, 3, 900, '拥有峨眉山-乐山大佛双5A景区，世界自然与文化双遗产地。', 12, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:11');
INSERT INTO `city` VALUES (1866, '宜宾市', '中国', 'https://dimg04.c-ctrip.com/images/100d1d000001el1hx1D08_C_1180_462.png', 18.0, 2, 750, '万里长江第一城，拥有蜀南竹海、兴文石海等4A景区，五粮液故乡。', 13, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:20');
INSERT INTO `city` VALUES (1867, '泸州市', '中国', 'https://dimg04.c-ctrip.com/images/0101l120008auqdok7CFB_C_1180_462.jpg', 18.0, 0, 500, '酒城，拥有泸州老窖旅游区、太平古镇等。', 14, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:29');
INSERT INTO `city` VALUES (1868, '自贡市', '中国', 'https://dimg04.c-ctrip.com/images/01001120008362zwn32B7_C_1180_462.jpg', 18.0, 2, 550, '千年盐都、恐龙之乡、中国灯城，拥有恐龙博物馆、燊海井、中华彩灯大世界等。', 15, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:39');
INSERT INTO `city` VALUES (1869, '内江市', '中国', 'https://dimg04.c-ctrip.com/images/0100a120009ehdft65F1D_C_1180_462.jpg', 17.5, 0, 300, '张大千故里。', 16, 1, '2026-03-19 18:05:37', '2026-03-23 19:12:50');
INSERT INTO `city` VALUES (1870, '眉山市', '中国', 'https://dimg04.c-ctrip.com/images/0102b120008k4nheqE2FF_C_1180_462.jpg', 17.0, 2, 500, '三苏故里，拥有三苏祠、瓦屋山、黑龙滩等景区。', 17, 1, '2026-03-19 18:05:37', '2026-03-23 19:13:00');
INSERT INTO `city` VALUES (1871, '雅安市', '中国', 'https://dimg04.c-ctrip.com/images/0101x1200090fmogj53F4_C_1180_462.jpg', 16.0, 2, 600, '雨城，拥有碧峰峡5A景区、蒙顶山、喇叭河等。', 18, 1, '2026-03-19 18:05:37', '2026-03-23 19:13:10');
